const book: BibleBook = {
  id: 'acts',
  name: 'Atos',
  englishName: 'Acts',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'The first book I wrote, Theophilus, concerned all that Jesus began both to do and to teach,', pt: 'Fiz o primeiro tratado, ó Teófilo, acerca de tudo quanto Jesus começou a fazer e ensinar,' },
      { v: 2, en: 'until the day in which he was received up, after he had given commandment through the Holy Spirit to the apostles whom he had chosen.', pt: 'até o dia em que foi levado para cima, depois de haver dado mandamento, pelo Espírito Santo, aos apóstolos que escolhera;' },
      { v: 3, en: 'To these he also showed himself alive after he suffered, by many proofs, appearing to them over a period of forty days, and speaking about God’s Kingdom.', pt: 'aos quais também, depois de haver padecido, se apresentou vivo, com muitas provas infalíveis, aparecendo-lhes por espaço de quarenta dias, e lhes falando das coisas concernentes ao reino de Deus.' },
      { v: 4, en: 'Being assembled together with them, he commanded them, “Don’t depart from Jerusalem, but wait for the promise of the Father, which you heard from me.', pt: 'Estando com eles, ordenou-lhes que não se ausentassem de Jerusalém, mas que esperassem a promessa do Pai, a qual (disse ele) de mim ouvistes.' },
      { v: 5, en: 'For John indeed baptized in water, but you will be baptized in the Holy Spirit not many days from now.”', pt: 'Porque, na verdade, João batizou em água, mas vós sereis batizados no Espírito Santo, dentro de poucos dias.' },
      { v: 6, en: 'Therefore when they had come together, they asked him, “Lord, are you now restoring the kingdom to Israel?”', pt: 'Aqueles, pois, que se haviam reunido perguntavam-lhe, dizendo: Senhor, é nesse tempo que restauras o reino a Israel?' },
      { v: 7, en: 'He said to them, “It isn’t for you to know times or seasons which the Father has set within his own authority.', pt: 'Respondeu-lhes: A vós não vos compete saber os tempos ou as épocas, que o Pai reservou à sua própria autoridade.' },
      { v: 8, en: 'But you will receive power when the Holy Spirit has come upon you. You will be witnesses to me in Jerusalem, in all Judea and Samaria, and to the uttermost parts of the earth.”', pt: 'Mas recebereis poder, ao descer sobre vós o Espírito Santo, e ser-me-eis testemunhas, tanto em Jerusalém, como em toda a Judéia e Samária, e até os confins da terra.' },
      { v: 9, en: 'When he had said these things, as they were looking, he was taken up, and a cloud received him out of their sight.', pt: 'Tendo ele dito estas coisas, foi levado para cima, enquanto eles olhavam, e uma nuvem o recebeu, ocultando-o a seus olhos.' },
      { v: 10, en: 'While they were looking steadfastly into the sky as he went, behold, two men stood by them in white clothing,', pt: 'Estando eles com os olhos fitos no céu, enquanto ele subia, eis que junto deles apareceram dois varões vestidos de branco,' },
      { v: 11, en: 'who also said, “You men of Galilee, why do you stand looking into the sky? This Jesus, who was received up from you into the sky, will come back in the same way as you saw him going into the sky.”', pt: 'os quais lhes disseram: Varões galileus, por que ficais aí olhando para o céu? Esse Jesus, que dentre vós foi elevado para o céu, há de vir assim como para o céu o vistes ir.' },
      { v: 12, en: 'Then they returned to Jerusalem from the mountain called Olivet, which is near Jerusalem, a Sabbath day’s journey away.', pt: 'Então voltaram para Jerusalém, do monte chamado das Oliveiras, que está perto de Jerusalém, à distância da jornada de um sábado.' },
      { v: 13, en: 'When they had come in, they went up into the upper room, where they were staying; that is Peter, John, James, Andrew, Philip, Thomas, Bartholomew, Matthew, James the son of Alphaeus, Simon the Zealot, and Judas the son of James.', pt: 'E, entrando, subiram ao cenáculo, onde permaneciam Pedro e João, Tiago e André, Felipe e Tomé, Bartolomeu e Mateus; Tiago, filho de Alfeu, Simão o Zelote, e Judas, filho de Tiago.' },
      { v: 14, en: 'All these with one accord continued steadfastly in prayer and supplication, along with the women, and Mary the mother of Jesus, and with his brothers.', pt: 'Todos estes perseveravam unanimemente em oração, com as mulheres, e Maria, mãe de Jesus, e com os irmãos dele.' },
      { v: 15, en: 'In these days, Peter stood up in the middle of the disciples (and the number of names was about one hundred twenty), and said,', pt: 'Naqueles dias levantou-se Pedro no meio dos irmãos, sendo o número de pessoas ali reunidas cerca de cento e vinte, e disse:' },
      { v: 16, en: '“Brothers, it was necessary that this Scripture should be fulfilled, which the Holy Spirit spoke before by the mouth of David concerning Judas, who was guide to those who took Jesus.', pt: 'Irmãos, convinha que se cumprisse a escritura que o Espírito Santo predisse pela boca de Davi, acerca de Judas, que foi o guia daqueles que prenderam a Jesus;' },
      { v: 17, en: 'For he was counted with us, and received his portion in this ministry.', pt: 'pois ele era contado entre nós e teve parte neste ministério.' },
      { v: 18, en: 'Now this man obtained a field with the reward for his wickedness, and falling headlong, his body burst open, and all his intestines gushed out.', pt: '(Ora, ele adquiriu um campo com o salário da sua iniquidade; e precipitando-se, caiu prostrado e arrebentou pelo meio, e todas as suas entranhas se derramaram.' },
      { v: 19, en: 'It became known to everyone who lived in Jerusalem that in their language that field was called ‘Akeldama,’ that is, ‘The field of blood.’', pt: 'E tornou-se isto conhecido de todos os habitantes de Jerusalém; de maneira que na própria língua deles esse campo se chama Acéldama, isto é, Campo de Sangue.)' },
      { v: 20, en: 'For it is written in the book of Psalms, ‘Let his habitation be made desolate. Let no one dwell therein;’ and, ‘Let another take his office.’', pt: 'Porquanto no livro dos Salmos está escrito: Fique deserta a sua habitação, e não haja quem nela habite; e: Tome outro o seu ministério.' },
      { v: 21, en: '“Of the men therefore who have accompanied us all the time that the Lord Jesus went in and out among us,', pt: 'É necessário, pois, que dos varões que conviveram conosco todo o tempo em que o Senhor Jesus andou entre nós,' },
      { v: 22, en: 'beginning from the baptism of John, to the day that he was received up from us, of these one must become a witness with us of his resurrection.”', pt: 'começando desde o batismo de João até o dia em que dentre nós foi levado para cima, um deles se torne testemunha conosco da sua ressurreição.' },
      { v: 23, en: 'They put forward two, Joseph called Barsabbas, who was also called Justus, and Matthias.', pt: 'E apresentaram dois: José, chamado Barsabás, que tinha por sobrenome o Justo, e Matias.' },
      { v: 24, en: 'They prayed, and said, “You, Lord, who know the hearts of all men, show which one of these two you have chosen', pt: 'E orando, disseram: Tu, Senhor, que conheces os corações de todos, mostra qual destes dois tens escolhido' },
      { v: 25, en: 'to take part in this ministry and apostleship from which Judas fell away, that he might go to his own place.”', pt: 'para tomar o lugar neste ministério e apostolado, do qual Judas se desviou para ir ao seu próprio lugar.' },
      { v: 26, en: 'They drew lots for them, and the lot fell on Matthias, and he was counted with the eleven apostles.', pt: 'Então deitaram sortes a respeito deles e caiu a sorte sobre Matias, e por voto comum foi ele contado com os onze apóstolos.' },
    ],
    2: [
      { v: 1, en: 'Now when the day of Pentecost had come, they were all with one accord in one place.', pt: 'Ao cumprir-se o dia de Pentecostes, estavam todos reunidos no mesmo lugar.' },
      { v: 2, en: 'Suddenly there came from the sky a sound like the rushing of a mighty wind, and it filled all the house where they were sitting.', pt: 'De repente veio do céu um ruído, como que de um vento impetuoso, e encheu toda a casa onde estavam sentados.' },
      { v: 3, en: 'Tongues like fire appeared and were distributed to them, and one sat on each of them.', pt: 'E lhes apareceram umas línguas como que de fogo, que se distribuíam, e sobre cada um deles pousou uma.' },
      { v: 4, en: 'They were all filled with the Holy Spirit, and began to speak with other languages, as the Spirit gave them the ability to speak.', pt: 'E todos ficaram cheios do Espírito Santo, e começaram a falar noutras línguas, conforme o Espírito lhes concedia que falassem.' },
      { v: 5, en: 'Now there were dwelling in Jerusalem Jews, devout men, from every nation under the sky.', pt: 'Habitavam então em Jerusalém judeus, homens piedosos, de todas as nações que há debaixo do céu.' },
      { v: 6, en: 'When this sound was heard, the multitude came together, and were bewildered, because everyone heard them speaking in his own language.', pt: 'Ouvindo-se, pois, aquele ruído, ajuntou-se a multidão; e estava confusa, porque cada um os ouvia falar na sua própria língua.' },
      { v: 7, en: 'They were all amazed and marveled, saying to one another, “Behold, aren’t all these who speak Galileans?', pt: 'E todos pasmavam e se admiravam, dizendo uns aos outros: Pois quê! não são galileus todos esses que estão falando?' },
      { v: 8, en: 'How do we hear, everyone in our own native language?', pt: 'Como é, pois, que os ouvimos falar cada um na própria língua em que nascemos?' },
      { v: 9, en: 'Parthians, Medes, Elamites, and people from Mesopotamia, Judea, Cappadocia, Pontus, Asia,', pt: 'Nós, partos, medos, e elamitas; e os que habitamos a Mesopotâmia, a Judéia e a Capadócia, o Ponto e a Ásia,' },
      { v: 10, en: 'Phrygia, Pamphylia, Egypt, the parts of Libya around Cyrene, visitors from Rome, both Jews and proselytes,', pt: 'a Frígia e a Panfília, o Egito e as partes da Líbia próximas a Cirene, e forasteiros romanos, tanto judeus como prosélitos,' },
      { v: 11, en: 'Cretans and Arabians: we hear them speaking in our languages the mighty works of God!”', pt: 'cretenses e árabes - ouvímo-los em nossas línguas, falar das grandezas de Deus.' },
      { v: 12, en: 'They were all amazed, and were perplexed, saying to one another, “What does this mean?”', pt: 'E todos pasmavam e estavam perplexos, dizendo uns aos outros: Que quer dizer isto?' },
      { v: 13, en: 'Others, mocking, said, “They are filled with new wine.”', pt: 'E outros, zombando, diziam: Estão cheios de mosto.' },
      { v: 14, en: 'But Peter, standing up with the eleven, lifted up his voice, and spoke out to them, “You men of Judea, and all you who dwell at Jerusalem, let this be known to you, and listen to my words.', pt: 'Então Pedro, pondo-se em pé com os onze, levantou a voz e disse-lhes: Varões judeus e todos os que habitais em Jerusalém, seja- vos isto notório, e escutai as minhas palavras.' },
      { v: 15, en: 'For these aren’t drunken, as you suppose, seeing it is only the third hour of the day.', pt: 'Pois estes homens não estão embriagados, como vós pensais, visto que é apenas a terceira hora do dia.' },
      { v: 16, en: 'But this is what has been spoken through the prophet Joel:', pt: 'Mas isto é o que foi dito pelo profeta Joel:' },
      { v: 17, en: '‘It will be in the last days, says God, that I will pour out my Spirit on all flesh. Your sons and your daughters will prophesy. Your young men will see visions. Your old men will dream dreams.', pt: 'E acontecerá nos últimos dias, diz o Senhor, que derramarei do meu Espírito sobre toda a carne; e os vossos filhos e as vossas filhas profetizarão, os vossos mancebos terão visões, os vossos anciãos terão sonhos;' },
      { v: 18, en: 'Yes, and on my servants and on my handmaidens in those days, I will pour out my Spirit, and they will prophesy.', pt: 'e sobre os meus servos e sobre as minhas servas derramarei do meu Espírito naqueles dias, e eles profetizarão.' },
      { v: 19, en: 'I will show wonders in the sky above, and signs on the earth beneath; blood, and fire, and billows of smoke.', pt: 'E mostrarei prodígios em cima no céu; e sinais embaixo na terra, sangue, fogo e vapor de fumaça.' },
      { v: 20, en: 'The sun will be turned into darkness, and the moon into blood, before the great and glorious day of the Lord comes.', pt: 'O sol se converterá em trevas, e a lua em sangue, antes que venha o grande e glorioso dia do Senhor.' },
      { v: 21, en: 'It will be that whoever will call on the name of the Lord will be saved.’', pt: 'e acontecerá que todo aquele que invocar o nome do Senhor será salvo.' },
      { v: 22, en: '“Men of Israel, hear these words! Jesus of Nazareth, a man approved by God to you by mighty works and wonders and signs which God did by him among you, even as you yourselves know,', pt: 'Varões israelitas, escutai estas palavras: A Jesus, o nazareno, varão aprovado por Deus entre vós com milagres, prodígios e sinais, que Deus por ele fez no meio de vós, como vós mesmos bem sabeis;' },
      { v: 23, en: 'him, being delivered up by the determined counsel and foreknowledge of God, you have taken by the hand of lawless men, crucified and killed;', pt: 'a este, que foi entregue pelo determinado conselho e presciência de Deus, vós matastes, crucificando-o pelas mãos de iníquos;' },
      { v: 24, en: 'whom God raised up, having freed him from the agony of death, because it was not possible that he should be held by it.', pt: 'ao qual Deus ressuscitou, rompendo os grilhões da morte, pois não era possível que fosse retido por ela.' },
      { v: 25, en: 'For David says concerning him, ‘I saw the Lord always before my face, For he is on my right hand, that I should not be moved.', pt: 'Porque dele fala Davi: Sempre via diante de mim o Senhor, porque está à minha direita, para que eu não seja abalado;' },
      { v: 26, en: 'Therefore my heart was glad, and my tongue rejoiced. Moreover my flesh also will dwell in hope;', pt: 'por isso se alegrou o meu coração, e a minha língua exultou; e além disso a minha carne há de repousar em esperança;' },
      { v: 27, en: 'because you will not leave my soul in Hades, neither will you allow your Holy One to see decay.', pt: 'pois não deixarás a minha alma no hades, nem permitirás que o teu Santo veja a corrupção;' },
      { v: 28, en: 'You made known to me the ways of life. You will make me full of gladness with your presence.’', pt: 'fizeste-me conhecer os caminhos da vida; encher-me-ás de alegria na tua presença.' },
      { v: 29, en: '“Brothers, I may tell you freely of the patriarch David, that he both died and was buried, and his tomb is with us to this day.', pt: 'Irmãos, seja-me permitido dizer-vos livremente acerca do patriarca Davi, que ele morreu e foi sepultado, e entre nós está até hoje a sua sepultura.' },
      { v: 30, en: 'Therefore, being a prophet, and knowing that God had sworn with an oath to him that of the fruit of his body, according to the flesh, he would raise up the Christ to sit on his throne,', pt: 'Sendo, pois, ele profeta, e sabendo que Deus lhe havia prometido com juramento que faria sentar sobre o seu trono um dos seus descendentes -' },
      { v: 31, en: 'he foreseeing this spoke about the resurrection of the Christ, that his soul wasn’t left in Hades, and his flesh didn’t see decay.', pt: 'prevendo isto, Davi falou da ressurreição de Cristo, que a sua alma não foi deixada no hades, nem a sua carne viu a corrupção.' },
      { v: 32, en: 'This Jesus God raised up, to which we all are witnesses.', pt: 'Ora, a este Jesus, Deus ressuscitou, do que todos nós somos testemunhas.' },
      { v: 33, en: 'Being therefore exalted by the right hand of God, and having received from the Father the promise of the Holy Spirit, he has poured out this, which you now see and hear.', pt: 'De sorte que, exaltado pela dextra de Deus, e tendo recebido do Pai a promessa do Espírito Santo, derramou isto que vós agora vedes e ouvis.' },
      { v: 34, en: 'For David didn’t ascend into the heavens, but he says himself, ‘The Lord said to my Lord, “Sit by my right hand,', pt: 'Porque Davi não subiu aos céus, mas ele próprio declara: Disse o Senhor ao meu Senhor: Assenta-te à minha direita,' },
      { v: 35, en: 'until I make your enemies a footstool for your feet.”’', pt: 'até que eu ponha os teus inimigos por escabelo de teus pés.' },
      { v: 36, en: '“Let all the house of Israel therefore know certainly that God has made him both Lord and Christ, this Jesus whom you crucified.”', pt: 'Saiba pois com certeza toda a casa de Israel que a esse mesmo Jesus, a quem vós crucificastes, Deus o fez Senhor e Cristo.' },
      { v: 37, en: 'Now when they heard this, they were cut to the heart, and said to Peter and the rest of the apostles, “Brothers, what shall we do?”', pt: 'E, ouvindo eles isto, compungiram-se em seu coração, e perguntaram a Pedro e aos demais apóstolos: Que faremos, irmãos?' },
      { v: 38, en: 'Peter said to them, “Repent, and be baptized, every one of you, in the name of Jesus Christ for the forgiveness of sins, and you will receive the gift of the Holy Spirit.', pt: 'Pedro então lhes respondeu: Arrependei-vos, e cada um de vós seja batizado em nome de Jesus Cristo, para remissão de vossos pecados; e recebereis o dom do Espírito Santo.' },
      { v: 39, en: 'For the promise is to you, and to your children, and to all who are far off, even as many as the Lord our God will call to himself.”', pt: 'Porque a promessa vos pertence a vós, a vossos filhos, e a todos os que estão longe: a quantos o Senhor nosso Deus chamar.' },
      { v: 40, en: 'With many other words he testified, and exhorted them, saying, “Save yourselves from this crooked generation!”', pt: 'E com muitas outras palavras dava testemunho, e os exortava, dizendo: salvai-vos desta geração perversa.' },
      { v: 41, en: 'Then those who gladly received his word were baptized. There were added that day about three thousand souls.', pt: 'De sorte que foram batizados os que receberam a sua palavra; e naquele dia agregaram-se quase três mil almas;' },
      { v: 42, en: 'They continued steadfastly in the apostles’ teaching and fellowship, in the breaking of bread, and prayer.', pt: 'e perseveravam na doutrina dos apóstolos e na comunhão, no partir do pão e nas orações.' },
      { v: 43, en: 'Fear came on every soul, and many wonders and signs were done through the apostles.', pt: 'Em cada alma havia temor, e muitos prodígios e sinais eram feitos pelos apóstolos.' },
      { v: 44, en: 'All who believed were together, and had all things in common.', pt: 'Todos os que criam estavam unidos e tinham tudo em comum.' },
      { v: 45, en: 'They sold their possessions and goods, and distributed them to all, according as anyone had need.', pt: 'E vendiam suas propriedades e bens e os repartiam por todos, segundo a necessidade de cada um.' },
      { v: 46, en: 'Day by day, continuing steadfastly with one accord in the temple, and breaking bread at home, they took their food with gladness and singleness of heart,', pt: 'E, perseverando unânimes todos os dias no templo, e partindo o pão em casa, comiam com alegria e singeleza de coração,' },
      { v: 47, en: 'praising God, and having favor with all the people. The Lord added to the assembly day by day those who were being saved.', pt: 'louvando a Deus, e caindo na graça de todo o povo. E cada dia acrescentava-lhes o Senhor os que iam sendo salvos.' },
    ],
    3: [
      { v: 1, en: 'Peter and John were going up into the temple at the hour of prayer, the ninth hour.', pt: 'Pedro e João subiam ao templo à hora da oração, a nona.' },
      { v: 2, en: 'A certain man who was lame from his mother’s womb was being carried, whom they laid daily at the door of the temple which is called Beautiful, to ask gifts for the needy of those who entered into the temple.', pt: 'E, era carregado um homem, coxo de nascença, o qual todos os dias punham à porta do templo, chamada Formosa, para pedir esmolas aos que entravam.' },
      { v: 3, en: 'Seeing Peter and John about to go into the temple, he asked to receive gifts for the needy.', pt: 'Ora, vendo ele a Pedro e João, que iam entrando no templo, pediu que lhe dessem uma esmola.' },
      { v: 4, en: 'Peter, fastening his eyes on him, with John, said, “Look at us.”', pt: 'E Pedro, com João, fitando os olhos nele, disse: Olha para nós.' },
      { v: 5, en: 'He listened to them, expecting to receive something from them.', pt: 'E ele os olhava atentamente, esperando receber deles alguma coisa.' },
      { v: 6, en: 'But Peter said, “I have no silver or gold, but what I have, that I give you. In the name of Jesus Christ of Nazareth, get up and walk!”', pt: 'Disse-lhe Pedro: Não tenho prata nem ouro; mas o que tenho, isso te dou; em nome de Jesus Cristo, o nazareno, anda.' },
      { v: 7, en: 'He took him by the right hand, and raised him up. Immediately his feet and his ankle bones received strength.', pt: 'Nisso, tomando-o pela mão direita, o levantou; imediatamente os seus pés e artelhos se firmaram' },
      { v: 8, en: 'Leaping up, he stood, and began to walk. He entered with them into the temple, walking, leaping, and praising God.', pt: 'e, dando ele um salto, pôs-se em pé. Começou a andar e entrou com eles no templo, andando, saltando e louvando a Deus.' },
      { v: 9, en: 'All the people saw him walking and praising God.', pt: 'Todo o povo, ao vê-lo andar e louvar a Deus,' },
      { v: 10, en: 'They recognized him, that it was he who used to sit begging for gifts for the needy at the Beautiful Gate of the temple. They were filled with wonder and amazement at what had happened to him.', pt: 'reconhecia-o como o mesmo que estivera sentado a pedir esmola à Porta Formosa do templo; e todos ficaram cheios de pasmo e assombro, pelo que lhe acontecera.' },
      { v: 11, en: 'As the lame man who was healed held on to Peter and John, all the people ran together to them in the porch that is called Solomon’s, greatly wondering.', pt: 'Apegando-se o homem a Pedro e João, todo o povo correu atônito para junto deles, ao pórtico chamado de Salomão.' },
      { v: 12, en: 'When Peter saw it, he responded to the people, “You men of Israel, why do you marvel at this man? Why do you fasten your eyes on us, as though by our own power or godliness we had made him walk?', pt: 'Pedro, vendo isto, disse ao povo: Varões israelitas, por que vos admirais deste homem? Ou, por que fitais os olhos em nós, como se por nosso próprio poder ou piedade o tivéssemos feito andar?' },
      { v: 13, en: 'The God of Abraham, Isaac, and Jacob, the God of our fathers, has glorified his Servant Jesus, whom you delivered up, and denied in the presence of Pilate, when he had determined to release him.', pt: 'O Deus de Abraão, de Isaque e de Jacó, o Deus de nossos pais, glorificou a seu Servo Jesus, a quem vós entregastes e perante a face de Pilatos negastes, quando este havia resolvido soltá-lo.' },
      { v: 14, en: 'But you denied the Holy and Righteous One, and asked for a murderer to be granted to you,', pt: 'Mas vós negastes o Santo e Justo, e pedistes que se vos desse um homicida;' },
      { v: 15, en: 'and killed the Prince of life, whom God raised from the dead, to which we are witnesses.', pt: 'e matastes o Autor da vida, a quem Deus ressuscitou dentre os mortos, do que nós somos testemunhas.' },
      { v: 16, en: 'By faith in his name, his name has made this man strong, whom you see and know. Yes, the faith which is through him has given him this perfect soundness in the presence of you all.', pt: 'E pela fé em seu nome fez o seu nome fortalecer a este homem que vedes e conheceis; sim, a fé, que vem por ele, deu a este, na presença de todos vós, esta perfeita saúde.' },
      { v: 17, en: '“Now, brothers, I know that you did this in ignorance, as did also your rulers.', pt: 'Agora, irmãos, eu sei que o fizestes por ignorância, como também as vossas autoridades.' },
      { v: 18, en: 'But the things which God announced by the mouth of all his prophets, that Christ should suffer, he thus fulfilled.', pt: 'Mas Deus assim cumpriu o que já dantes pela boca de todos os seus profetas havia anunciado que o seu Cristo havia de padecer.' },
      { v: 19, en: '“Repent therefore, and turn again, that your sins may be blotted out, so that there may come times of refreshing from the presence of the Lord,', pt: 'Arrependei-vos, pois, e convertei-vos, para que sejam apagados os vossos pecados, de sorte que venham os tempos de refrigério, da presença do Senhor,' },
      { v: 20, en: 'and that he may send Christ Jesus, who was ordained for you before,', pt: 'e envie ele o Cristo, que já dantes vos foi indicado, Jesus,' },
      { v: 21, en: 'whom heaven must receive until the times of restoration of all things, which God spoke long ago by the mouth of his holy prophets.', pt: 'ao qual convém que o céu receba até os tempos da restauração de todas as coisas, das quais Deus falou pela boca dos seus santos profetas, desde o princípio.' },
      { v: 22, en: 'For Moses indeed said to the fathers, ‘The Lord God will raise up a prophet for you from among your brothers, like me. You shall listen to him in all things whatever he says to you.', pt: 'Pois Moisés disse: Suscitar-vos-á o Senhor vosso Deus, dentre vossos irmãos, um profeta semelhante a mim; a ele ouvireis em tudo quanto vos disser.' },
      { v: 23, en: 'It will be that every soul that will not listen to that prophet will be utterly destroyed from among the people.’', pt: 'E acontecerá que toda alma que não ouvir a esse profeta, será exterminada dentre o povo.' },
      { v: 24, en: 'Yes, and all the prophets from Samuel and those who followed after, as many as have spoken, they also told of these days.', pt: 'E todos os profetas, desde Samuel e os que sucederam, quantos falaram, também anunciaram estes dias.' },
      { v: 25, en: 'You are the children of the prophets, and of the covenant which God made with our fathers, saying to Abraham, ‘In your offspring will all the families of the earth be blessed.’', pt: 'Vós sois os filhos dos profetas e do pacto que Deus fez com vossos pais, dizendo a Abraão: Na tua descendência serão abençoadas todas as famílias da terra.' },
      { v: 26, en: 'God, having raised up his servant Jesus, sent him to you first to bless you, in turning away every one of you from your wickedness.”', pt: 'Deus suscitou a seu Servo, e a vós primeiramente vo-lo enviou para que vos abençoasse, desviando-vos, a cada um, das vossas maldades.' },
    ],
    4: [
      { v: 1, en: 'As they spoke to the people, the priests and the captain of the temple and the Sadducees came to them,', pt: 'Enquanto eles estavam falando ao povo, sobrevieram-lhes os sacerdotes, o capitão do templo e os saduceus,' },
      { v: 2, en: 'being upset because they taught the people and proclaimed in Jesus the resurrection from the dead.', pt: 'doendo-se muito de que eles ensinassem o povo, e anunciassem em Jesus a ressurreição dentre os mortos,' },
      { v: 3, en: 'They laid hands on them, and put them in custody until the next day, for it was now evening.', pt: 'deitaram mão neles, e os encerraram na prisão até o dia seguinte; pois era já tarde.' },
      { v: 4, en: 'But many of those who heard the word believed, and the number of the men came to be about five thousand.', pt: 'Muitos, porém, dos que ouviram a palavra, creram, e se elevou o número dos homens a quase cinco mil.' },
      { v: 5, en: 'In the morning, their rulers, elders, and scribes were gathered together in Jerusalem.', pt: 'No dia seguinte, reuniram-se em Jerusalém as autoridades, os anciãos, os escribas,' },
      { v: 6, en: 'Annas the high priest was there, with Caiaphas, John, Alexander, and as many as were relatives of the high priest.', pt: 'e Anás, o sumo sacerdote, e Caifás, João, Alexandre, e todos quantos eram da linhagem do sumo sacerdote.' },
      { v: 7, en: 'When they had stood Peter and John in the middle of them, they inquired, “By what power, or in what name, have you done this?”', pt: 'E, pondo-os no meio deles, perguntaram: Com que poder ou em nome de quem fizestes vós isto?' },
      { v: 8, en: 'Then Peter, filled with the Holy Spirit, said to them, “You rulers of the people, and elders of Israel,', pt: 'Então Pedro, cheio do Espírito Santo, lhes disse: Autoridades do povo e vós, anciãos,' },
      { v: 9, en: 'if we are examined today concerning a good deed done to a crippled man, by what means this man has been healed,', pt: 'se nós hoje somos inquiridos acerca do benefício feito a um enfermo, e do modo como foi curado,' },
      { v: 10, en: 'be it known to you all, and to all the people of Israel, that in the name of Jesus Christ of Nazareth, whom you crucified, whom God raised from the dead, in him does this man stand here before you whole.', pt: 'seja conhecido de vós todos, e de todo o povo de Israel, que em nome de Jesus Cristo, o nazareno, aquele a quem vós crucificastes e a quem Deus ressuscitou dentre os mortos, nesse nome está este aqui, são diante de vós.' },
      { v: 11, en: 'He is ‘the stone which was regarded as worthless by you, the builders, which has become the head of the corner.’', pt: 'Ele é a pedra que foi rejeitada por vós, os edificadores, a qual foi posta como pedra angular.' },
      { v: 12, en: 'There is salvation in none other, for neither is there any other name under heaven, that is given among men, by which we must be saved!”', pt: 'E em nenhum outro há salvação; porque debaixo do céu nenhum outro nome há, dado entre os homens, em que devamos ser salvos.' },
      { v: 13, en: 'Now when they saw the boldness of Peter and John, and had perceived that they were unlearned and ignorant men, they marveled. They recognized that they had been with Jesus.', pt: 'Então eles, vendo a intrepidez de Pedro e João, e tendo percebido que eram homens iletrados e indoutos, se admiravam; e reconheciam que haviam estado com Jesus.' },
      { v: 14, en: 'Seeing the man who was healed standing with them, they could say nothing against it.', pt: 'E vendo em pé com eles o homem que fora curado, nada tinham que dizer em contrário.' },
      { v: 15, en: 'But when they had commanded them to go aside out of the council, they conferred among themselves,', pt: 'Todavia, mandando-os sair do sinédrio, conferenciaram entre si,' },
      { v: 16, en: 'saying, “What shall we do to these men? Because indeed a notable miracle has been done through them, as can be plainly seen by all who dwell in Jerusalem, and we can’t deny it.', pt: 'dizendo: Que havemos de fazer a estes homens? porque a todos os que habitam em Jerusalém é manifesto que por eles foi feito um sinal notório, e não o podemos negar.' },
      { v: 17, en: 'But so that this spreads no further among the people, let’s threaten them, that from now on they don’t speak to anyone in this name.”', pt: 'Mas, para que não se divulgue mais entre o povo, ameacemo- los para que de ora em diante não falem neste nome a homem algum.' },
      { v: 18, en: 'They called them, and commanded them not to speak at all nor teach in the name of Jesus.', pt: 'E, chamando-os, ordenaram-lhes que absolutamente não falassem nem ensinassem em nome de Jesus.' },
      { v: 19, en: 'But Peter and John answered them, “Whether it is right in the sight of God to listen to you rather than to God, judge for yourselves,', pt: 'Mas Pedro e João, respondendo, lhes disseram: Julgai vós se é justo diante de Deus ouvir-nos antes a vós do que a Deus;' },
      { v: 20, en: 'for we can’t help telling the things which we saw and heard.”', pt: 'pois nós não podemos deixar de falar das coisas que temos visto e ouvido.' },
      { v: 21, en: 'When they had further threatened them, they let them go, finding no way to punish them, because of the people; for everyone glorified God for that which was done.', pt: 'Mas eles ainda os ameaçaram mais, e, não achando motivo para os castigar, soltaram-nos, por causa do povo; porque todos glorificavam a Deus pelo que acontecera;' },
      { v: 22, en: 'For the man on whom this miracle of healing was performed was more than forty years old.', pt: 'pois tinha mais de quarenta anos o homem em quem se operara esta cura milagrosa.' },
      { v: 23, en: 'Being let go, they came to their own company, and reported all that the chief priests and the elders had said to them.', pt: 'E soltos eles, foram para os seus, e contaram tudo o que lhes haviam dito os principais sacerdotes e os anciãos.' },
      { v: 24, en: 'When they heard it, they lifted up their voice to God with one accord, and said, “O Lord, you are God, who made the heaven, the earth, the sea, and all that is in them;', pt: 'Ao ouvirem isto, levantaram unanimemente a voz a Deus e disseram: Senhor, tu que fizeste o céu, a terra, o mar, e tudo o que neles há;' },
      { v: 25, en: 'who by the mouth of your servant, David, said, ‘Why do the nations rage, and the peoples plot a vain thing?', pt: 'que pelo Espírito Santo, por boca de nosso pai Davi, teu servo, disseste: Por que se enfureceram os gentios, e os povos imaginaram coisas vãs?' },
      { v: 26, en: 'The kings of the earth take a stand, and the rulers take council together, against the Lord, and against his Christ.’', pt: 'Levantaram-se os reis da terra, e as autoridades ajuntaram- se à uma, contra o Senhor e contra o seu Ungido.' },
      { v: 27, en: '“For truly, in this city against your holy servant, Jesus, whom you anointed, both Herod and Pontius Pilate, with the Gentiles and the people of Israel, were gathered together', pt: 'Porque verdadeiramente se ajuntaram, nesta cidade, contra o teu santo Servo Jesus, ao qual ungiste, não só Herodes, mas também Pôncio Pilatos com os gentios e os povos de Israel;' },
      { v: 28, en: 'to do whatever your hand and your council foreordained to happen.', pt: 'para fazerem tudo o que a tua mão e o teu conselho predeterminaram que se fizesse.' },
      { v: 29, en: 'Now, Lord, look at their threats, and grant to your servants to speak your word with all boldness,', pt: 'Agora pois, ó Senhor, olha para as suas ameaças, e concede aos teus servos que falam com toda a intrepidez a tua palavra,' },
      { v: 30, en: 'while you stretch out your hand to heal; and that signs and wonders may be done through the name of your holy Servant Jesus.”', pt: 'enquanto estendes a mão para curar e para que se façam sinais e prodígios pelo nome de teu santo Servo Jesus.' },
      { v: 31, en: 'When they had prayed, the place was shaken where they were gathered together. They were all filled with the Holy Spirit, and they spoke the word of God with boldness.', pt: 'E, tendo eles orado, tremeu o lugar em que estavam reunidos; e todos foram cheios do Espírito Santo, e anunciavam com intrepidez a palavra de Deus.' },
      { v: 32, en: 'The multitude of those who believed were of one heart and soul. Not one of them claimed that anything of the things which he possessed was his own, but they had all things in common.', pt: 'Da multidão dos que criam, era um só o coração e uma só a alma, e ninguém dizia que coisa alguma das que possuía era sua própria, mas todas as coisas lhes eram comuns.' },
      { v: 33, en: 'With great power, the apostles gave their testimony of the resurrection of the Lord Jesus. Great grace was on them all.', pt: 'Com grande poder os apóstolos davam testemunho da ressurreição do Senhor Jesus, e em todos eles havia abundante graça.' },
      { v: 34, en: 'For neither was there among them any who lacked, for as many as were owners of lands or houses sold them, and brought the proceeds of the things that were sold,', pt: 'Pois não havia entre eles necessitado algum; porque todos os que possuíam terras ou casas, vendendo-as, traziam o preço do que vendiam e o depositavam aos pés dos apóstolos.' },
      { v: 35, en: 'and laid them at the apostles’ feet, and distribution was made to each, according as anyone had need.', pt: 'E se repartia a qualquer um que tivesse necessidade.' },
      { v: 36, en: 'Joses, who by the apostles was also called Barnabas (which is, being interpreted, Son of Encouragement), a Levite, a man of Cyprus by race,', pt: 'então José, cognominado pelos apóstolos Barnabé (que quer dizer, filho de consolação), levita, natural de Chipre,' },
      { v: 37, en: 'having a field, sold it, and brought the money and laid it at the apostles’ feet.', pt: 'possuindo um campo, vendeu-o, trouxe o preço e o depositou aos pés dos apóstolos.' },
    ],
    5: [
      { v: 1, en: 'But a certain man named Ananias, with Sapphira, his wife, sold a possession,', pt: 'Mas um certo homem chamado Ananias, com Safira, sua mulher, vendeu uma propriedade,' },
      { v: 2, en: 'and kept back part of the price, his wife also being aware of it, and brought a certain part, and laid it at the apostles’ feet.', pt: 'e reteve parte do preço, sabendo-o também sua mulher; e levando a outra parte, a depositou aos pés dos apóstolos.' },
      { v: 3, en: 'But Peter said, “Ananias, why has Satan filled your heart to lie to the Holy Spirit, and to keep back part of the price of the land?', pt: 'Disse então Pedro: Ananias, por que encheu Satanás o teu coração, para que mentisses ao Espírito Santo e retivesses parte do preço do terreno?' },
      { v: 4, en: 'While you kept it, didn’t it remain your own? After it was sold, wasn’t it in your power? How is it that you have conceived this thing in your heart? You haven’t lied to men, but to God.”', pt: 'Enquanto o possuías, não era teu? e vendido, não estava o preço em teu poder? Como, pois, formaste este desígnio em teu coração? Não mentiste aos homens, mas a Deus.' },
      { v: 5, en: 'Ananias, hearing these words, fell down and died. Great fear came on all who heard these things.', pt: 'E Ananias, ouvindo estas palavras, caiu e expirou. E grande temor veio sobre todos os que souberam disto.' },
      { v: 6, en: 'The young men arose and wrapped him up, and they carried him out and buried him.', pt: 'Levantando-se os moços, cobriram-no e, transportando-o para fora, o sepultaram.' },
      { v: 7, en: 'About three hours later, his wife, not knowing what had happened, came in.', pt: 'Depois de um intervalo de cerca de três horas, entrou também sua mulher, sabendo o que havia acontecido.' },
      { v: 8, en: 'Peter answered her, “Tell me whether you sold the land for so much.” She said, “Yes, for so much.”', pt: 'E perguntou-lhe Pedro: Dize-me vendestes por tanto aquele terreno? E ela respondeu: Sim, por tanto.' },
      { v: 9, en: 'But Peter asked her, “How is it that you have agreed together to tempt the Spirit of the Lord? Behold, the feet of those who have buried your husband are at the door, and they will carry you out.”', pt: 'Então Pedro lhe disse: Por que é que combinastes entre vós provar o Espírito do Senhor? Eis aí à porta os pés dos que sepultaram o teu marido, e te levarão também a ti.' },
      { v: 10, en: 'She fell down immediately at his feet, and died. The young men came in and found her dead, and they carried her out and buried her by her husband.', pt: 'Imediatamente ela caiu aos pés dele e expirou. E entrando os moços, acharam-na morta e, levando-a para fora, sepultaram-na ao lado do marido.' },
      { v: 11, en: 'Great fear came on the whole assembly, and on all who heard these things.', pt: 'Sobreveio grande temor a toda a igreja e a todos os que ouviram estas coisas.' },
      { v: 12, en: 'By the hands of the apostles many signs and wonders were done among the people. They were all with one accord in Solomon’s porch.', pt: 'E muitos sinais e prodígios eram feitos entre o povo pelas mãos dos apóstolos. E estavam todos de comum acordo no pórtico de Salomão.' },
      { v: 13, en: 'None of the rest dared to join them, however the people honored them.', pt: 'Dos outros, porém, nenhum ousava ajuntar-se a eles; mas o povo os tinha em grande estima;' },
      { v: 14, en: 'More believers were added to the Lord, multitudes of both men and women.', pt: 'e cada vez mais se agregavam crentes ao Senhor em grande número tanto de homens como de mulheres;' },
      { v: 15, en: 'They even carried out the sick into the streets, and laid them on cots and mattresses, so that as Peter came by, at the least his shadow might overshadow some of them.', pt: 'a ponto de transportarem os enfermos para as ruas, e os porem em leitos e macas, para que ao passar Pedro, ao menos sua sombra cobrisse alguns deles.' },
      { v: 16, en: 'The multitude also came together from the cities around Jerusalem, bringing sick people, and those who were tormented by unclean spirits: and they were all healed.', pt: 'Também das cidades circunvizinhas afluía muita gente a Jerusalém, conduzindo enfermos e atormentados de espíritos imundos, os quais eram todos curados.' },
      { v: 17, en: 'But the high priest rose up, and all those who were with him (which is the sect of the Sadducees), and they were filled with jealousy,', pt: 'Levantando-se o sumo sacerdote e todos os que estavam com ele (isto é, a seita dos saduceus), encheram-se de inveja,' },
      { v: 18, en: 'and laid hands on the apostles, and put them in public custody.', pt: 'deitaram mão nos apóstolos, e os puseram na prisão pública.' },
      { v: 19, en: 'But an angel of the Lord opened the prison doors by night, and brought them out, and said,', pt: 'Mas de noite um anjo do Senhor abriu as portas do cárcere e, tirando-os para fora, disse:' },
      { v: 20, en: '“Go stand and speak in the temple to the people all the words of this life.”', pt: 'Ide, apresentai-vos no templo, e falai ao povo todas as palavras desta vida.' },
      { v: 21, en: 'When they heard this, they entered into the temple about daybreak, and taught. But the high priest came, and those who were with him, and called the council together, and all the senate of the children of Israel, and sent to the prison to have them brought.', pt: 'Ora, tendo eles ouvido isto, entraram de manhã cedo no templo e ensinavam. Chegando, porém o sumo sacerdote e os que estavam com ele, convocaram o sinédrio, com todos os anciãos dos filhos de Israel, e enviaram guardas ao cárcere para trazê-los.' },
      { v: 22, en: 'But the officers who came didn’t find them in the prison. They returned and reported,', pt: 'Mas os guardas, tendo lá ido, não os acharam na prisão; e voltando, lho anunciaram,' },
      { v: 23, en: '“We found the prison shut and locked, and the guards standing before the doors, but when we opened them, we found no one inside!”', pt: 'dizendo: Achamos realmente o cárcere fechado com toda a segurança, e as sentinelas em pé às portas; mas, abrindo-as, a ninguém achamos dentro.' },
      { v: 24, en: 'Now when the high priest, the captain of the temple, and the chief priests heard these words, they were very perplexed about them and what might become of this.', pt: 'E quando o capitão do templo e os principais sacerdotes ouviram estas palavras ficaram perplexos acerca deles e do que viria a ser isso.' },
      { v: 25, en: 'One came and told them, “Behold, the men whom you put in prison are in the temple, standing and teaching the people.”', pt: 'Então chegou alguém e lhes anunciou: Eis que os homens que encerrastes na prisão estão no templo, em pé, a ensinar o povo.' },
      { v: 26, en: 'Then the captain went with the officers, and brought them without violence, for they were afraid that the people might stone them.', pt: 'Nisso foi o capitão com os guardas e os trouxe, não com violência, porque temiam ser apedrejados pelo povo.' },
      { v: 27, en: 'When they had brought them, they set them before the council. The high priest questioned them,', pt: 'E tendo-os trazido, os apresentaram ao sinédrio. E o sumo sacerdote os interrogou, dizendo:' },
      { v: 28, en: 'saying, “Didn’t we strictly command you not to teach in this name? Behold, you have filled Jerusalem with your teaching, and intend to bring this man’s blood on us.”', pt: 'Não vos admoestamos expressamente que não ensinásseis nesse nome? e eis que enchestes Jerusalém dessa vossa doutrina e quereis lançar sobre nós o sangue desse homem.' },
      { v: 29, en: 'But Peter and the apostles answered, “We must obey God rather than men.', pt: 'Respondendo Pedro e os apóstolos, disseram: Importa antes obedecer a Deus que aos homens.' },
      { v: 30, en: 'The God of our fathers raised up Jesus, whom you killed, hanging him on a tree.', pt: 'O Deus de nossos pais ressuscitou a Jesus, ao qual vós matastes, suspendendo-o no madeiro;' },
      { v: 31, en: 'God exalted him with his right hand to be a Prince and a Savior, to give repentance to Israel, and remission of sins.', pt: 'sim, Deus, com a sua destra, o elevou a Príncipe e Salvador, para dar a Israel o arrependimento e remissão de pecados.' },
      { v: 32, en: 'We are His witnesses of these things; and so also is the Holy Spirit, whom God has given to those who obey him.”', pt: 'E nós somos testemunhas destas coisas, e bem assim o Espírito Santo, que Deus deu àqueles que lhe obedecem.' },
      { v: 33, en: 'But they, when they heard this, were cut to the heart, and were determined to kill them.', pt: 'Ora, ouvindo eles isto, se enfureceram e queriam matá-los.' },
      { v: 34, en: 'But one stood up in the council, a Pharisee named Gamaliel, a teacher of the law, honored by all the people, and commanded to put the apostles out for a little while.', pt: 'Mas, levantando-se no sinédrio certo fariseu chamado Gamaliel, doutor da lei, acatado por todo o povo, mandou que por um pouco saíssem aqueles homens;' },
      { v: 35, en: 'He said to them, “You men of Israel, be careful concerning these men, what you are about to do.', pt: 'e prosseguiu: Varões israelitas, acautelai-vos a respeito do que estai para fazer a estes homens.' },
      { v: 36, en: 'For before these days Theudas rose up, making himself out to be somebody; to whom a number of men, about four hundred, joined themselves: who was slain; and all, as many as obeyed him, were dispersed, and came to nothing.', pt: 'Porque, há algum tempo, levantou-se Teudas, dizendo ser alguém; ao qual se ajuntaram uns quatrocentos homens; mas ele foi morto, e todos quantos lhe obedeciam foram dispersos e reduzidos a nada.' },
      { v: 37, en: 'After this man, Judas of Galilee rose up in the days of the enrollment, and drew away some people after him. He also perished, and all, as many as obeyed him, were scattered abroad.', pt: 'Depois dele levantou-se Judas, o galileu, nos dias do recenseamento, e levou muitos após si; mas também este pereceu, e todos quantos lhe obedeciam foram dispersos.' },
      { v: 38, en: 'Now I tell you, withdraw from these men, and leave them alone. For if this counsel or this work is of men, it will be overthrown.', pt: 'Agora vos digo: Dai de mão a estes homens, e deixai-os, porque este conselho ou esta obra, caso seja dos homens, se desfará;' },
      { v: 39, en: 'But if it is of God, you will not be able to overthrow it, and you would be found even to be fighting against God!”', pt: 'mas, se é de Deus, não podereis derrotá-los; para que não sejais, porventura, achados até combatendo contra Deus.' },
      { v: 40, en: 'They agreed with him. Summoning the apostles, they beat them and commanded them not to speak in the name of Jesus, and let them go.', pt: 'Concordaram, pois, com ele, e tendo chamado os apóstolos, açoitaram-nos e mandaram que não falassem em nome de Jesus, e os soltaram.' },
      { v: 41, en: 'They therefore departed from the presence of the council, rejoicing that they were counted worthy to suffer dishonor for Jesus’ name.', pt: 'Retiraram-se pois da presença do sinédrio, regozijando-se de terem sido julgados dignos de sofrer afronta pelo nome de Jesus.' },
      { v: 42, en: 'Every day, in the temple and at home, they never stopped teaching and preaching Jesus, the Christ.', pt: 'E todos os dias, no templo e de casa em casa, não cessavam de ensinar, e de anunciar a Jesus, o Cristo.' },
    ],
    6: [
      { v: 1, en: 'Now in those days, when the number of the disciples was multiplying, a complaint arose from the Hellenists against the Hebrews, because their widows were neglected in the daily service.', pt: 'Ora, naqueles dias, crescendo o número dos discípulos, houve uma murmuração dos helenistas contra os hebreus, porque as viúvas daqueles estavam sendo esquecidas na distribuição diária.' },
      { v: 2, en: 'The twelve summoned the multitude of the disciples and said, “It is not appropriate for us to forsake the word of God and serve tables.', pt: 'E os doze, convocando a multidão dos discípulos, disseram: Não é razoável que nós deixemos a palavra de Deus e sirvamos às mesas.' },
      { v: 3, en: 'Therefore select from among you, brothers, seven men of good report, full of the Holy Spirit and of wisdom, whom we may appoint over this business.', pt: 'Escolhei, pois, irmãos, dentre vós, sete homens de boa reputação, cheios do Espírito Santo e de sabedoria, aos quais encarreguemos deste serviço.' },
      { v: 4, en: 'But we will continue steadfastly in prayer and in the ministry of the word.”', pt: 'Mas nós perseveraremos na oração e no ministério da palavra.' },
      { v: 5, en: 'These words pleased the whole multitude. They chose Stephen, a man full of faith and of the Holy Spirit, Philip, Prochorus, Nicanor, Timon, Parmenas, and Nicolaus, a proselyte of Antioch;', pt: 'O parecer agradou a todos, e elegeram a Estevão, homem cheio de fé e do Espírito Santo, Filipe, Prócoro, Nicanor, Timão, Pármenas, e Nicolau, prosélito de Antioquia,' },
      { v: 6, en: 'whom they set before the apostles. When they had prayed, they laid their hands on them.', pt: 'e os apresentaram perante os apóstolos; estes, tendo orado, lhes impuseram as mãos.' },
      { v: 7, en: 'The word of God increased and the number of the disciples multiplied in Jerusalem exceedingly. A great company of the priests were obedient to the faith.', pt: 'E divulgava-se a palavra de Deus, de sorte que se multiplicava muito o número dos discípulos em Jerusalém e muitos sacerdotes obedeciam à fé.' },
      { v: 8, en: 'Stephen, full of faith and power, performed great wonders and signs among the people.', pt: 'Ora, Estêvão, cheio de graça e poder, fazia prodígios e grandes sinais entre o povo.' },
      { v: 9, en: 'But some of those who were of the synagogue called “The Libertines”, and of the Cyrenians, of the Alexandrians, and of those of Cilicia and Asia arose, disputing with Stephen.', pt: 'Levantaram-se, porém, alguns que eram da sinagoga chamada dos libertos, dos cireneus, dos alexandrinos, dos da Cilícia e da Ásia, e disputavam com Estêvão;' },
      { v: 10, en: 'They weren’t able to withstand the wisdom and the Spirit by which he spoke.', pt: 'e não podiam resistir à sabedoria e ao Espírito com que falava.' },
      { v: 11, en: 'Then they secretly induced men to say, “We have heard him speak blasphemous words against Moses and God.”', pt: 'Então subornaram uns homens para que dissessem: Temo-lo ouvido proferir palavras blasfemas contra Moisés e contra Deus.' },
      { v: 12, en: 'They stirred up the people, the elders, and the scribes, and came against him and seized him, and brought him in to the council,', pt: 'Assim excitaram o povo, os anciãos, e os escribas; e investindo contra ele, o arrebataram e o levaram ao sinédrio;' },
      { v: 13, en: 'and set up false witnesses who said, “This man never stops speaking blasphemous words against this holy place and the law.', pt: 'e apresentaram falsas testemunhas que diziam: Este homem não cessa de proferir palavras contra este santo lugar e contra a lei;' },
      { v: 14, en: 'For we have heard him say that this Jesus of Nazareth will destroy this place, and will change the customs which Moses delivered to us.”', pt: 'porque nós o temos ouvido dizer que esse Jesus, o nazareno, há de destruir este lugar e mudar os costumes que Moisés nos transmitiu.' },
      { v: 15, en: 'All who sat in the council, fastening their eyes on him, saw his face like it was the face of an angel.', pt: 'Então todos os que estavam assentados no sinédrio, fitando os olhos nele, viram o seu rosto como de um anjo.' },
    ],
    7: [
      { v: 1, en: 'The high priest said, “Are these things so?”', pt: 'E disse o sumo sacerdote: Porventura são assim estas coisas?' },
      { v: 2, en: 'He said, “Brothers and fathers, listen. The God of glory appeared to our father Abraham, when he was in Mesopotamia, before he lived in Haran,', pt: 'Estêvão respondeu: Irmãos e pais, ouvi. O Deus da glória apareceu a nosso pai Abraão, estando ele na Mesopotâmia, antes de habitar em Harã,' },
      { v: 3, en: 'and said to him, ‘Get out of your land, and from your relatives, and come into a land which I will show you.’', pt: 'e disse-lhe: Sai da tua terra e dentre a tua parentela, e dirige-te à terra que eu te mostrar.' },
      { v: 4, en: 'Then he came out of the land of the Chaldaeans, and lived in Haran. From there, when his father was dead, God moved him into this land, where you are now living.', pt: 'Então saiu da terra dos caldeus e habitou em Harã. Dali, depois que seu pai faleceu, Deus o trouxe para esta terra em que vós agora habitais.' },
      { v: 5, en: 'He gave him no inheritance in it, no, not so much as to set his foot on. He promised that he would give it to him for a possession, and to his offspring after him, when he still had no child.', pt: 'E não lhe deu nela herança, nem sequer o espaço de um pé; mas prometeu que lha daria em possessão, e depois dele à sua descendência, não tendo ele ainda filho.' },
      { v: 6, en: 'God spoke in this way: that his offspring would live as aliens in a strange land, and that they would be enslaved and mistreated for four hundred years.', pt: 'Pois Deus disse que a sua descendência seria peregrina em terra estranha e que a escravizariam e maltratariam por quatrocentos anos.' },
      { v: 7, en: '‘I will judge the nation to which they will be in bondage,’ said God, ‘and after that will they come out, and serve me in this place.’', pt: 'Mas eu julgarei a nação que os tiver escravizado, disse Deus; e depois disto sairão, e me servirão neste lugar.' },
      { v: 8, en: 'He gave him the covenant of circumcision. So Abraham became the father of Isaac, and circumcised him the eighth day. Isaac became the father of Jacob, and Jacob became the father of the twelve patriarchs.', pt: 'E deu-lhe o pacto da circuncisão; assim então gerou Abraão a Isaque, e o circuncidou ao oitavo dia; e Isaque gerou a Jacó, e Jacó aos doze patriarcas.' },
      { v: 9, en: '“The patriarchs, moved with jealousy against Joseph, sold him into Egypt. God was with him,', pt: 'Os patriarcas, movidos de inveja, venderam José para o Egito; mas Deus era com ele,' },
      { v: 10, en: 'and delivered him out of all his afflictions, and gave him favor and wisdom before Pharaoh, king of Egypt. He made him governor over Egypt and all his house.', pt: 'e o livrou de todas as suas tribulações, e lhe deu graça e sabedoria perante Faraó, rei do Egito, que o constituiu governador sobre o Egito e toda a sua casa.' },
      { v: 11, en: 'Now a famine came over all the land of Egypt and Canaan, and great affliction. Our fathers found no food.', pt: 'Sobreveio então uma fome a todo o Egito e Canaã, e grande tribulação; e nossos pais não achavam alimentos.' },
      { v: 12, en: 'But when Jacob heard that there was grain in Egypt, he sent out our fathers the first time.', pt: 'Mas tendo ouvido Jacó que no Egito havia trigo, enviou ali nossos pais pela primeira vez.' },
      { v: 13, en: 'On the second time Joseph was made known to his brothers, and Joseph’s race was revealed to Pharaoh.', pt: 'E na segunda vez deu-se José a conhecer a seus irmãos, e a sua linhagem tornou-se manifesta a Faraó.' },
      { v: 14, en: 'Joseph sent, and summoned Jacob, his father, and all his relatives, seventy-five souls.', pt: 'Então José mandou chamar a seu pai Jacó, e a toda a sua parentela - setenta e cinco almas.' },
      { v: 15, en: 'Jacob went down into Egypt, and he died, himself and our fathers,', pt: 'Jacó, pois, desceu ao Egito, onde morreu, ele e nossos pais;' },
      { v: 16, en: 'and they were brought back to Shechem, and laid in the tomb that Abraham bought for a price in silver from the children of Hamor of Shechem.', pt: 'e foram transportados para Siquém e depositados na sepultura que Abraão comprara por certo preço em prata aos filhos de Emor, em Siquém.' },
      { v: 17, en: '“But as the time of the promise came close which God had sworn to Abraham, the people grew and multiplied in Egypt,', pt: 'Enquanto se aproximava o tempo da promessa que Deus tinha feito a Abraão, o povo crescia e se multiplicava no Egito;' },
      { v: 18, en: 'until there arose a different king, who didn’t know Joseph.', pt: 'até que se levantou ali outro rei, que não tinha conhecido José.' },
      { v: 19, en: 'The same took advantage of our race, and mistreated our fathers, and forced them to throw out their babies, so that they wouldn’t stay alive.', pt: 'Usando esse de astúcia contra a nossa raça, maltratou a nossos pais, ao ponto de fazê-los enjeitar seus filhos, para que não vivessem.' },
      { v: 20, en: 'At that time Moses was born, and was exceedingly handsome. He was nourished three months in his father’s house.', pt: 'Nesse tempo nasceu Moisés, e era mui formoso, e foi criado três meses em casa de seu pai.' },
      { v: 21, en: 'When he was thrown out, Pharaoh’s daughter took him up, and reared him as her own son.', pt: 'Sendo ele enjeitado, a filha de Faraó o recolheu e o criou como seu próprio filho.' },
      { v: 22, en: 'Moses was instructed in all the wisdom of the Egyptians. He was mighty in his words and works.', pt: 'Assim Moisés foi instruído em toda a sabedoria dos egípcios, e era poderoso em palavras e obras.' },
      { v: 23, en: 'But when he was forty years old, it came into his heart to visit his brothers, the children of Israel.', pt: 'Ora, quando ele completou quarenta anos, veio-lhe ao coração visitar seus irmãos, os filhos de Israel.' },
      { v: 24, en: 'Seeing one of them suffer wrong, he defended him, and avenged him who was oppressed, striking the Egyptian.', pt: 'E vendo um deles sofrer injustamente, defendeu-o, e vingou o oprimido, matando o egípcio.' },
      { v: 25, en: 'He supposed that his brothers understood that God, by his hand, was giving them deliverance; but they didn’t understand.', pt: 'Cuidava que seus irmãos entenderiam que por mão dele Deus lhes havia de dar a liberdade; mas eles não entenderam.' },
      { v: 26, en: '“The day following, he appeared to them as they fought, and urged them to be at peace again, saying, ‘Sirs, you are brothers. Why do you wrong one another?’', pt: 'No dia seguinte apareceu-lhes quando brigavam, e quis levá- los à paz, dizendo: Homens, sois irmãos; por que vos maltratais um ao outro?' },
      { v: 27, en: 'But he who did his neighbor wrong pushed him away, saying, ‘Who made you a ruler and a judge over us?', pt: 'Mas o que fazia injustiça ao seu próximo o repeliu, dizendo: Quem te constituiu senhor e juiz sobre nós?' },
      { v: 28, en: 'Do you want to kill me, as you killed the Egyptian yesterday?’', pt: 'Acaso queres tu matar-me como ontem mataste o egípcio?' },
      { v: 29, en: 'Moses fled at this saying, and became a stranger in the land of Midian, where he became the father of two sons.', pt: 'A esta palavra fugiu Moisés, e tornou-se peregrino na terra de Madiã, onde gerou dois filhos.' },
      { v: 30, en: '“When forty years were fulfilled, an angel of the Lord appeared to him in the wilderness of Mount Sinai, in a flame of fire in a bush.', pt: 'E passados mais quarenta anos, apareceu-lhe um anjo no deserto do monte Sinai, numa chama de fogo no meio de uma sarça.' },
      { v: 31, en: 'When Moses saw it, he wondered at the sight. As he came close to see, a voice of the Lord came to him,', pt: 'Moisés, vendo isto, admirou-se da visão; e, aproximando-se ele para observar, soou a voz do Senhor;' },
      { v: 32, en: '‘I am the God of your fathers, the God of Abraham, the God of Isaac, and the God of Jacob.’ Moses trembled, and dared not look.', pt: 'Eu sou o deus de teus pais, o Deus de Abraão, de Isaque e de Jacó. E Moisés ficou trêmulo e não ousava olhar.' },
      { v: 33, en: 'The Lord said to him, ‘Take off your sandals, for the place where you stand is holy ground.', pt: 'Disse-lhe então o Senhor: Tira as alparcas dos teus pés, porque o lugar em que estás é terra santa.' },
      { v: 34, en: 'I have surely seen the affliction of my people that is in Egypt, and have heard their groaning. I have come down to deliver them. Now come, I will send you into Egypt.’', pt: 'Vi, com efeito, a aflição do meu povo no Egito, ouvi os seus gemidos, e desci para livrá-lo. Agora pois vem, e enviar-te-ei ao Egito.' },
      { v: 35, en: '“This Moses, whom they refused, saying, ‘Who made you a ruler and a judge?’—God has sent him as both a ruler and a deliverer by the hand of the angel who appeared to him in the bush.', pt: 'A este Moisés que eles haviam repelido, dizendo: Quem te constituiu senhor e juiz? a este enviou Deus como senhor e libertador, pela mão do anjo que lhe aparecera na sarça.' },
      { v: 36, en: 'This man led them out, having worked wonders and signs in Egypt, in the Red Sea, and in the wilderness for forty years.', pt: 'Foi este que os conduziu para fora, fazendo prodígios e sinais na terra do Egito, e no Mar Vermelho, e no deserto por quarenta anos.' },
      { v: 37, en: 'This is that Moses, who said to the children of Israel, ‘The Lord our God will raise up a prophet for you from among your brothers, like me.’', pt: 'Este é o Moisés que disse aos filhos de Israel: Deus vos suscitará dentre vossos irmãos um profeta como eu.' },
      { v: 38, en: 'This is he who was in the assembly in the wilderness with the angel that spoke to him on Mount Sinai, and with our fathers, who received living revelations to give to us,', pt: 'Este é o que esteve na congregação no deserto, com o anjo que lhe falava no monte Sinai, e com nossos pais, o qual recebeu palavras de vida para vo-las dar;' },
      { v: 39, en: 'to whom our fathers wouldn’t be obedient, but rejected him, and turned back in their hearts to Egypt,', pt: 'ao qual os nossos pais não quiseram obedecer, antes o rejeitaram, e em seus corações voltaram ao Egito,' },
      { v: 40, en: 'saying to Aaron, ‘Make us gods that will go before us, for as for this Moses, who led us out of the land of Egypt, we don’t know what has become of him.’', pt: 'dizendo a arão: Faze-nos deuses que vão adiante de nós; porque a esse Moisés que nos tirou da terra do Egito, não sabemos o que lhe aconteceu.' },
      { v: 41, en: 'They made a calf in those days, and brought a sacrifice to the idol, and rejoiced in the works of their hands.', pt: 'Fizeram, pois, naqueles dias o bezerro, e ofereceram sacrifício ao ídolo, e se alegravam nas obras das suas mãos.' },
      { v: 42, en: 'But God turned, and gave them up to serve the army of the sky, as it is written in the book of the prophets, ‘Did you offer to me slain animals and sacrifices forty years in the wilderness, O house of Israel?', pt: 'Mas Deus se afastou, e os abandonou ao culto das hostes do céu, como está escrito no livro dos profetas: Porventura me oferecestes vítimas e sacrifícios por quarenta anos no deserto, ó casa de Israel?' },
      { v: 43, en: 'You took up the tabernacle of Moloch, the star of your god Rephan, the figures which you made to worship. I will carry you away beyond Babylon.’', pt: 'Antes carregastes o tabernáculo de Moloque e a estrela do deus Renfã, figuras que vós fizestes para adorá-las. Desterrar-vos-ei pois, para além da Babilônia.' },
      { v: 44, en: '“Our fathers had the tabernacle of the testimony in the wilderness, even as he who spoke to Moses commanded him to make it according to the pattern that he had seen;', pt: 'Entre os nossos pais no deserto estava o tabernáculo do testemunho, como ordenara aquele que disse a Moisés que o fizesse segundo o modelo que tinha visto;' },
      { v: 45, en: 'which also our fathers, in their turn, brought in with Joshua when they entered into the possession of the nations, whom God drove out before the face of our fathers, to the days of David,', pt: 'o qual nossos pais, tendo-o por sua vez recebido, o levaram sob a direção de Josué, quando entraram na posse da terra das nações que Deus expulsou da presença dos nossos pais, até os dias de Davi,' },
      { v: 46, en: 'who found favor in the sight of God, and asked to find a habitation for the God of Jacob.', pt: 'que achou graça diante de Deus, e pediu que lhe fosse dado achar habitação para o Deus de Jacó.' },
      { v: 47, en: 'But Solomon built him a house.', pt: 'Entretanto foi Salomão quem lhe edificou uma casa;' },
      { v: 48, en: 'However, the Most High doesn’t dwell in temples made with hands, as the prophet says,', pt: 'mas o Altíssimo não habita em templos feitos por mãos de homens, como diz o profeta:' },
      { v: 49, en: '‘heaven is my throne, and the earth a footstool for my feet. What kind of house will you build me?’ says the Lord. ‘Or what is the place of my rest?', pt: 'O céu é meu trono, e a terra o escabelo dos meus pés. Que casa me edificareis, diz o Senhor, ou qual o lugar do meu repouso?' },
      { v: 50, en: 'Didn’t my hand make all these things?’', pt: 'Não fez, porventura, a minha mão todas estas coisas?' },
      { v: 51, en: '“You stiff-necked and uncircumcised in heart and ears, you always resist the Holy Spirit! As your fathers did, so you do.', pt: 'Homens de dura cerviz, e incircuncisos de coração e ouvido, vós sempre resistis ao Espírito Santo; como o fizeram os vossos pais, assim também vós.' },
      { v: 52, en: 'Which of the prophets didn’t your fathers persecute? They killed those who foretold the coming of the Righteous One, of whom you have now become betrayers and murderers.', pt: 'A qual dos profetas não perseguiram vossos pais? Até mataram os que dantes anunciaram a vinda do Justo, do qual vós agora vos tornastes traidores e homicidas,' },
      { v: 53, en: 'You received the law as it was ordained by angels, and didn’t keep it!”', pt: 'vós, que recebestes a lei por ordenação dos anjos, e não a guardastes.' },
      { v: 54, en: 'Now when they heard these things, they were cut to the heart, and they gnashed at him with their teeth.', pt: 'Ouvindo eles isto, enfureciam-se em seus corações, e rangiam os dentes contra Estêvão.' },
      { v: 55, en: 'But he, being full of the Holy Spirit, looked up steadfastly into heaven, and saw the glory of God, and Jesus standing on the right hand of God,', pt: 'Mas ele, cheio do Espírito Santo, fitando os olhos no céu, viu a glória de Deus, e Jesus em pé à direita de Deus,' },
      { v: 56, en: 'and said, “Behold, I see the heavens opened, and the Son of Man standing at the right hand of God!”', pt: 'e disse: Eis que vejo os céus abertos, e o Filho do homem em pé à direita de Deus.' },
      { v: 57, en: 'But they cried out with a loud voice, and stopped their ears, and rushed at him with one accord.', pt: 'Então eles gritaram com grande voz, taparam os ouvidos, e arremeteram unânimes contra ele' },
      { v: 58, en: 'They threw him out of the city, and stoned him. The witnesses placed their garments at the feet of a young man named Saul.', pt: 'e, lançando-o fora da cidade o apedrejavam. E as testemunhas depuseram as suas vestes aos pés de um mancebo chamado Saulo.' },
      { v: 59, en: 'They stoned Stephen as he called out, saying, “Lord Jesus, receive my spirit!”', pt: 'Apedrejavam, pois, a Estêvão que orando, dizia: Senhor Jesus, recebe o meu espírito.' },
      { v: 60, en: 'He kneeled down, and cried with a loud voice, “Lord, don’t hold this sin against them!” When he had said this, he fell asleep.', pt: 'E pondo-se de joelhos, clamou com grande voz: Senhor, não lhes imputes este pecado. Tendo dito isto, adormeceu. E Saulo consentia na sua morte.' },
    ],
    8: [
      { v: 1, en: 'Saul was consenting to his death. A great persecution arose against the assembly which was in Jerusalem in that day. They were all scattered abroad throughout the regions of Judea and Samaria, except for the apostles.', pt: 'Naquele dia levantou-se grande perseguição contra a igreja que estava em Jerusalém; e todos exceto os apóstolos, foram dispersos pelas regiões da Judéia e da Samária.' },
      { v: 2, en: 'Devout men buried Stephen, and lamented greatly over him.', pt: 'E uns homens piedosos sepultaram a Estêvão, e fizeram grande pranto sobre ele.' },
      { v: 3, en: 'But Saul ravaged the assembly, entering into every house, and dragged both men and women off to prison.', pt: 'Saulo porém, assolava a igreja, entrando pelas casas e, arrastando homens e mulheres, os entregava à prisão.' },
      { v: 4, en: 'Therefore those who were scattered abroad went around preaching the word.', pt: 'No entanto os que foram dispersos iam por toda parte, anunciando a palavra.' },
      { v: 5, en: 'Philip went down to the city of Samaria, and proclaimed to them the Christ.', pt: 'E descendo Filipe à cidade de Samária, pregava-lhes a Cristo.' },
      { v: 6, en: 'The multitudes listened with one accord to the things that were spoken by Philip, when they heard and saw the signs which he did.', pt: 'As multidões escutavam, unânimes, as coisas que Filipe dizia, ouvindo-o e vendo os sinais que operava;' },
      { v: 7, en: 'For unclean spirits came out of many of those who had them. They came out, crying with a loud voice. Many who had been paralyzed and lame were healed.', pt: 'pois saíam de muitos possessos os espíritos imundos, clamando em alta voz; e muitos paralíticos e coxos foram curados;' },
      { v: 8, en: 'There was great joy in that city.', pt: 'pelo que houve grande alegria naquela cidade.' },
      { v: 9, en: 'But there was a certain man, Simon by name, who used to practice sorcery in the city, and amazed the people of Samaria, making himself out to be some great one,', pt: 'Ora, estava ali certo homem chamado Simão, que vinha exercendo naquela cidade a arte mágica, fazendo pasmar o povo da Samária, e dizendo ser ele uma grande personagem;' },
      { v: 10, en: 'to whom they all listened, from the least to the greatest, saying, “This man is that great power of God.”', pt: 'ao qual todos atendiam, desde o menor até o maior, dizendo: Este é o Poder de Deus que se chama Grande.' },
      { v: 11, en: 'They listened to him, because for a long time he had amazed them with his sorceries.', pt: 'Eles o atendiam porque já desde muito tempo os vinha fazendo pasmar com suas artes mágicas.' },
      { v: 12, en: 'But when they believed Philip preaching good news concerning God’s Kingdom and the name of Jesus Christ, they were baptized, both men and women.', pt: 'Mas, quando creram em Filipe, que lhes pregava acerca do reino de Deus e do nome de Jesus, batizavam-se homens e mulheres.' },
      { v: 13, en: 'Simon himself also believed. Being baptized, he continued with Philip. Seeing signs and great miracles occurring, he was amazed.', pt: 'E creu até o próprio Simão e, sendo batizado, ficou de contínuo com Filipe; e admirava-se, vendo os sinais e os grandes milagres que se faziam.' },
      { v: 14, en: 'Now when the apostles who were at Jerusalem heard that Samaria had received the word of God, they sent Peter and John to them,', pt: 'Os apóstolos, pois, que estavam em Jerusalém, tendo ouvido que os da Samária haviam recebido a palavra de Deus, enviaram-lhes Pedro e João;' },
      { v: 15, en: 'who, when they had come down, prayed for them, that they might receive the Holy Spirit;', pt: 'os quais, tendo descido, oraram por eles, para que recebessem o Espírito Santo.' },
      { v: 16, en: 'for as yet he had fallen on none of them. They had only been baptized in the name of Christ Jesus.', pt: 'Porque sobre nenhum deles havia ele descido ainda; mas somente tinham sido batizados em nome do Senhor Jesus.' },
      { v: 17, en: 'Then they laid their hands on them, and they received the Holy Spirit.', pt: 'Então lhes impuseram as mãos, e eles receberam o Espírito Santo.' },
      { v: 18, en: 'Now when Simon saw that the Holy Spirit was given through the laying on of the apostles’ hands, he offered them money,', pt: 'Quando Simão viu que pela imposição das mãos dos apóstolos se dava o Espírito Santo, ofereceu-lhes dinheiro,' },
      { v: 19, en: 'saying, “Give me also this power, that whomever I lay my hands on may receive the Holy Spirit.”', pt: 'dizendo: Dai-me também a mim esse poder, para que aquele sobre quem eu impuser as mãos, receba o Espírito Santo.' },
      { v: 20, en: 'But Peter said to him, “May your silver perish with you, because you thought you could obtain the gift of God with money!', pt: 'Mas disse-lhe Pedro: Vá tua prata contigo à perdição, pois cuidaste adquirir com dinheiro o dom de Deus.' },
      { v: 21, en: 'You have neither part nor lot in this matter, for your heart isn’t right before God.', pt: 'Tu não tens parte nem sorte neste ministério, porque o teu coração não é reto diante de Deus.' },
      { v: 22, en: 'Repent therefore of this, your wickedness, and ask God if perhaps the thought of your heart may be forgiven you.', pt: 'Arrepende-te, pois, dessa tua maldade, e roga ao Senhor para que porventura te seja perdoado o pensamento do teu coração;' },
      { v: 23, en: 'For I see that you are in the poison of bitterness and in the bondage of iniquity.”', pt: 'pois vejo que estás em fel de amargura, e em laços de iniquidade.' },
      { v: 24, en: 'Simon answered, “Pray for me to the Lord, that none of the things which you have spoken happen to me.”', pt: 'Respondendo, porém, Simão, disse: Rogai vós por mim ao Senhor, para que nada do que haveis dito venha sobre mim.' },
      { v: 25, en: 'They therefore, when they had testified and spoken the word of the Lord, returned to Jerusalem, and preached the Good News to many villages of the Samaritans.', pt: 'Eles, pois, havendo testificado e falado a palavra do Senhor, voltando para Jerusalém, evangelizavam muitas aldeias dos samaritanos.' },
      { v: 26, en: 'But an angel of the Lord spoke to Philip, saying, “Arise, and go toward the south to the way that goes down from Jerusalem to Gaza. This is a desert.”', pt: 'Mas um anjo do Senhor falou a Filipe, dizendo: Levanta-te, e vai em direção do sul pelo caminho que desce de Jerusalém a Gaza, o qual está deserto.' },
      { v: 27, en: 'He arose and went; and behold, there was a man of Ethiopia, a eunuch of great authority under Candace, queen of the Ethiopians, who was over all her treasure, who had come to Jerusalem to worship.', pt: 'E levantou-se e foi; e eis que um etíope, eunuco, mordomo- mor de Candace, rainha dos etíopes, o qual era superintendente de todos os seus tesouros e tinha ido a Jerusalém para adorar,' },
      { v: 28, en: 'He was returning and sitting in his chariot, and was reading the prophet Isaiah.', pt: 'regressava e, sentado no seu carro, lia o profeta Isaías.' },
      { v: 29, en: 'The Spirit said to Philip, “Go near, and join yourself to this chariot.”', pt: 'Disse o Espírito a Filipe: Chega-te e ajunta-te a esse carro.' },
      { v: 30, en: 'Philip ran to him, and heard him reading Isaiah the prophet, and said, “Do you understand what you are reading?”', pt: 'E correndo Filipe, ouviu que lia o profeta Isaías, e disse: Entendes, porventura, o que estás lendo?' },
      { v: 31, en: 'He said, “How can I, unless someone explains it to me?” He begged Philip to come up and sit with him.', pt: 'Ele respondeu: Pois como poderei entender, se alguém não me ensinar? e rogou a Filipe que subisse e com ele se sentasse.' },
      { v: 32, en: 'Now the passage of the Scripture which he was reading was this, “He was led as a sheep to the slaughter. As a lamb before his shearer is silent, so he doesn’t open his mouth.', pt: 'Ora, a passagem da Escritura que estava lendo era esta: Foi levado como a ovelha ao matadouro, e, como está mudo o cordeiro diante do que o tosquia, assim ele não abre a sua boca.' },
      { v: 33, en: 'In his humiliation, his judgment was taken away. Who will declare His generation? For his life is taken from the earth.”', pt: 'Na sua humilhação foi tirado o seu julgamento; quem contará a sua geração? porque a sua vida é tirada da terra.' },
      { v: 34, en: 'The eunuch answered Philip, “Who is the prophet talking about? About himself, or about someone else?”', pt: 'Respondendo o eunuco a Filipe, disse: Rogo-te, de quem diz isto o profeta? de si mesmo, ou de algum outro?' },
      { v: 35, en: 'Philip opened his mouth, and beginning from this Scripture, preached to him about Jesus.', pt: 'Então Filipe tomou a palavra e, começando por esta escritura, anunciou-lhe a Jesus.' },
      { v: 36, en: 'As they went on the way, they came to some water, and the eunuch said, “Behold, here is water. What is keeping me from being baptized?”', pt: 'E indo eles caminhando, chegaram a um lugar onde havia água, e disse o eunuco: Eis aqui água; que impede que eu seja batizado?' },
      { v: 37, en: '[E disse Felipe: é lícito, se crês de todo o coração. E, respondendo ele, disse: Creio que Jesus Cristo é o Filho de Deus.]', pt: '[E disse Felipe: é lícito, se crês de todo o coração. E, respondendo ele, disse: Creio que Jesus Cristo é o Filho de Deus.]' },
      { v: 38, en: 'He commanded the chariot to stand still, and they both went down into the water, both Philip and the eunuch, and he baptized him.', pt: 'mandou parar o carro, e desceram ambos à água, tanto Filipe como o eunuco, e Filipe o batizou.' },
      { v: 39, en: 'When they came up out of the water, the Spirit of the Lord caught Philip away, and the eunuch didn’t see him any more, for he went on his way rejoicing.', pt: 'Quando saíram da água, o Espírito do Senhor arrebatou a Filipe, e não o viu mais o eunuco, que jubiloso seguia o seu caminho.' },
      { v: 40, en: 'But Philip was found at Azotus. Passing through, he preached the Good News to all the cities, until he came to Caesarea.', pt: 'Mas Filipe achou-se em Azoto e, indo passando, evangelizava todas as cidades, até que chegou a Cesaréia.' },
    ],
    9: [
      { v: 1, en: 'But Saul, still breathing threats and slaughter against the disciples of the Lord, went to the high priest,', pt: 'Saulo, porém, respirando ainda ameaças e mortes contra os discípulos do Senhor, dirigiu-se ao sumo sacerdote,' },
      { v: 2, en: 'and asked for letters from him to the synagogues of Damascus, that if he found any who were of the Way, whether men or women, he might bring them bound to Jerusalem.', pt: 'e pediu-lhe cartas para Damasco, para as sinagogas, a fim de que, caso encontrasse alguns do Caminho, quer homens quer mulheres, os conduzisse presos a Jerusalém.' },
      { v: 3, en: 'As he traveled, he got close to Damascus, and suddenly a light from the sky shone around him.', pt: 'Mas, seguindo ele viagem e aproximando-se de Damasco, subitamente o cercou um resplendor de luz do céu;' },
      { v: 4, en: 'He fell on the earth, and heard a voice saying to him, “Saul, Saul, why do you persecute me?”', pt: 'e, caindo por terra, ouviu uma voz que lhe dizia: Saulo, Saulo, por que me persegues?' },
      { v: 5, en: 'He said, “Who are you, Lord?” The Lord said, “I am Jesus, whom you are persecuting.', pt: 'Ele perguntou: Quem és tu, Senhor? Respondeu o Senhor: Eu sou Jesus, a quem tu persegues;' },
      { v: 6, en: 'But rise up, and enter into the city, and you will be told what you must do.”', pt: 'mas levanta-te e entra na cidade, e lá te será dito o que te cumpre fazer.' },
      { v: 7, en: 'The men who traveled with him stood speechless, hearing the sound, but seeing no one.', pt: 'Os homens que viajavam com ele quedaram-se emudecidos, ouvindo, na verdade, a voz, mas não vendo ninguém.' },
      { v: 8, en: 'Saul arose from the ground, and when his eyes were opened, he saw no one. They led him by the hand, and brought him into Damascus.', pt: 'Saulo levantou-se da terra e, abrindo os olhos, não via coisa alguma; e, guiando-o pela mão, conduziram-no a Damasco.' },
      { v: 9, en: 'He was without sight for three days, and neither ate nor drank.', pt: 'E esteve três dias sem ver, e não comeu nem bebeu.' },
      { v: 10, en: 'Now there was a certain disciple at Damascus named Ananias. The Lord said to him in a vision, “Ananias!” He said, “Behold, it’s me, Lord.”', pt: 'Ora, havia em Damasco certo discípulo chamado Ananias; e disse-lhe o Senhor em visão: Ananias! Respondeu ele: Eis-me aqui, Senhor.' },
      { v: 11, en: 'The Lord said to him, “Arise, and go to the street which is called Straight, and inquire in the house of Judah for one named Saul, a man of Tarsus. For behold, he is praying,', pt: 'Ordenou-lhe o Senhor: Levanta-te, vai à rua chamada Direita e procura em casa de Judas um homem de Tarso chamado Saulo; pois eis que ele está orando;' },
      { v: 12, en: 'and in a vision he has seen a man named Ananias coming in, and laying his hands on him, that he might receive his sight.”', pt: 'e viu um homem chamado Ananias entrar e impor-lhe as mãos, para que recuperasse a vista.' },
      { v: 13, en: 'But Ananias answered, “Lord, I have heard from many about this man, how much evil he did to your saints at Jerusalem.', pt: 'Respondeu Ananias: Senhor, a muitos ouvi acerca desse homem, quantos males tem feito aos teus santos em Jerusalém;' },
      { v: 14, en: 'Here he has authority from the chief priests to bind all who call on your name.”', pt: 'e aqui tem poder dos principais sacerdotes para prender a todos os que invocam o teu nome.' },
      { v: 15, en: 'But the Lord said to him, “Go your way, for he is my chosen vessel to bear my name before the nations and kings, and the children of Israel.', pt: 'Disse-lhe, porém, o Senhor: Vai, porque este é para mim um vaso escolhido, para levar o meu nome perante os gentios, e os reis, e os filhos de Israel;' },
      { v: 16, en: 'For I will show him how many things he must suffer for my name’s sake.”', pt: 'pois eu lhe mostrarei quanto lhe cumpre padecer pelo meu nome.' },
      { v: 17, en: 'Ananias departed, and entered into the house. Laying his hands on him, he said, “Brother Saul, the Lord, who appeared to you on the road by which you came, has sent me, that you may receive your sight, and be filled with the Holy Spirit.”', pt: 'Partiu Ananias e entrou na casa e, impondo-lhe as mãos, disse: Irmão Saulo, o Senhor Jesus, que te apareceu no caminho por onde vinhas, enviou-me para que tornes a ver e sejas cheio do Espírito Santo.' },
      { v: 18, en: 'Immediately something like scales fell from his eyes, and he received his sight. He arose and was baptized.', pt: 'Logo lhe caíram dos olhos como que umas escamas, e recuperou a vista: então, levantando-se, foi batizado.' },
      { v: 19, en: 'He took food and was strengthened. Saul stayed several days with the disciples who were at Damascus.', pt: 'E, tendo tomado alimento, ficou fortalecido. Depois demorou- se alguns dias com os disc!pulos que estavam em Damasco;' },
      { v: 20, en: 'Immediately in the synagogues he proclaimed the Christ, that he is the Son of God.', pt: 'e logo nas sinagogas pregava a Jesus, que este era o filho de Deus.' },
      { v: 21, en: 'All who heard him were amazed, and said, “Isn’t this he who in Jerusalem made havoc of those who called on this name? And he had come here intending to bring them bound before the chief priests!”', pt: 'Todos os seus ouvintes pasmavam e diziam: Não é este o que em Jerusalém perseguia os que invocavam esse nome, e para isso veio aqui, para os levar presos aos principais sacerdotes?' },
      { v: 22, en: 'But Saul increased more in strength, and confounded the Jews who lived at Damascus, proving that this is the Christ.', pt: 'Saulo, porém, se fortalecia cada vez mais e confundia os judeus que habitavam em Damasco, provando que Jesus era o Cristo.' },
      { v: 23, en: 'When many days were fulfilled, the Jews conspired together to kill him,', pt: 'Decorridos muitos dias, os judeus deliberaram entre si matá- lo.' },
      { v: 24, en: 'but their plot became known to Saul. They watched the gates both day and night that they might kill him,', pt: 'Mas as suas ciladas vieram ao conhecimento de Saulo. E como eles guardavam as portas de dia e de noite para tirar-lhe a vida,' },
      { v: 25, en: 'but his disciples took him by night, and let him down through the wall, lowering him in a basket.', pt: 'os discípulos, tomando-o de noite, desceram-no pelo muro, dentro de um cesto.' },
      { v: 26, en: 'When Saul had come to Jerusalem, he tried to join himself to the disciples; but they were all afraid of him, not believing that he was a disciple.', pt: 'Tendo Saulo chegado a Jerusalém, procurava juntar-se aos discípulos; mas todos o temiam, não crendo que fosse discípulo.' },
      { v: 27, en: 'But Barnabas took him, and brought him to the apostles, and declared to them how he had seen the Lord on the way, and that he had spoken to him, and how at Damascus he had preached boldly in the name of Jesus.', pt: 'Então Barnabé, tomando-o consigo, o levou aos apóstolos, e lhes contou como no caminho ele vira o Senhor e que este lhe falara, e como em Damasco pregara ousadamente em nome de Jesus.' },
      { v: 28, en: 'He was with them entering into Jerusalem,', pt: 'Assim andava com eles em Jerusalém, entrando e saindo,' },
      { v: 29, en: 'preaching boldly in the name of the Lord Jesus. He spoke and disputed against the Hellenists, but they were seeking to kill him.', pt: 'e pregando ousadamente em nome do Senhor. Falava e disputava também com os helenistas; mas procuravam matá-lo.' },
      { v: 30, en: 'When the brothers knew it, they brought him down to Caesarea, and sent him off to Tarsus.', pt: 'Os irmãos, porém, quando o souberam, acompanharam-no até Cesaréia e o enviaram a Tarso.' },
      { v: 31, en: 'So the assemblies throughout all Judea and Galilee and Samaria had peace, and were built up. They were multiplied, walking in the fear of the Lord and in the comfort of the Holy Spirit.', pt: 'Assim, pois, a igreja em toda a Judéia, Galiléia e Samária, tinha paz, sendo edificada, e andando no temor do Senhor; e, pelo auxílio do Espírito Santo, se multiplicava.' },
      { v: 32, en: 'As Peter went throughout all those parts, he came down also to the saints who lived at Lydda.', pt: 'E aconteceu que, passando Pedro por toda parte, veio também aos santos que habitavam em Lida.' },
      { v: 33, en: 'There he found a certain man named Aeneas, who had been bedridden for eight years, because he was paralyzed.', pt: 'Achou ali certo homem, chamado Enéias, que havia oito anos jazia numa cama, porque era paralítico.' },
      { v: 34, en: 'Peter said to him, “Aeneas, Jesus Christ heals you. Get up and make your bed!” Immediately he arose.', pt: 'Disse-lhe Pedro: Enéias, Jesus Cristo te cura; levanta e faze a tua cama. E logo se levantou.' },
      { v: 35, en: 'All who lived at Lydda and in Sharon saw him, and they turned to the Lord.', pt: 'E viram-no todos os que habitavam em Lida e Sarona, os quais se converteram ao Senhor.' },
      { v: 36, en: 'Now there was at Joppa a certain disciple named Tabitha, which when translated, means Dorcas. This woman was full of good works and acts of mercy which she did.', pt: 'Havia em Jope uma discípula por nome Tabita, que traduzido quer dizer Dorcas, a qual estava cheia de boas obras e esmolas que fazia.' },
      { v: 37, en: 'In those days, she became sick, and died. When they had washed her, they laid her in an upper room.', pt: 'Ora, aconteceu naqueles dias que ela, adoecendo, morreu; e, tendo-a lavado, a colocaram no cenáculo.' },
      { v: 38, en: 'As Lydda was near Joppa, the disciples, hearing that Peter was there, sent two men to him, imploring him not to delay in coming to them.', pt: 'Como Lida era perto de Jope, ouvindo os discípulos que Pedro estava ali, enviaram-lhe dois homens, rogando-lhe: Não te demores em vir ter conosco.' },
      { v: 39, en: 'Peter got up and went with them. When he had come, they brought him into the upper room. All the widows stood by him weeping, and showing the coats and garments which Dorcas had made while she was with them.', pt: 'Pedro levantou-se e foi com eles; quando chegou, levaram-no ao cenáulo; e todas as viúvas o cercaram, chorando e mostrando-lhe as túnicas e vestidos que Dorcas fizera enquanto estava com elas.' },
      { v: 40, en: 'Peter sent them all out, and knelt down and prayed. Turning to the body, he said, “Tabitha, get up!” She opened her eyes, and when she saw Peter, she sat up.', pt: 'Mas Pedro, tendo feito sair a todos, pôs-se de joelhos e orou; e voltando-se para o corpo, disse: Tabita, levanta-te. Ela abriu os olhos e, vendo a Pedro, sentou-se.' },
      { v: 41, en: 'He gave her his hand, and raised her up. Calling the saints and widows, he presented her alive.', pt: 'Ele, dando-lhe a mão, levantou-a e, chamando os santos e as viúvas, apresentou-lha viva.' },
      { v: 42, en: 'And it became known throughout all Joppa, and many believed in the Lord.', pt: 'Tornou-se isto notório por toda a Jope, e muitos creram no Senhor.' },
      { v: 43, en: 'He stayed many days in Joppa with a tanner named Simon.', pt: 'Pedro ficou muitos dias em Jope, em casa de um curtidor chamado Simão.' },
    ],
    10: [
      { v: 1, en: 'Now there was a certain man in Caesarea, Cornelius by name, a centurion of what was called the Italian Regiment,', pt: 'Um homem em Cesaréia, por nome Cornélio, centurião da coorte chamada italiana,' },
      { v: 2, en: 'a devout man, and one who feared God with all his house, who gave gifts for the needy generously to the people, and always prayed to God.', pt: 'piedoso e temente a Deus com toda a sua casa, e que fazia muitas esmolas ao povo e de contínuo orava a Deus,' },
      { v: 3, en: 'At about the ninth hour of the day, he clearly saw in a vision an angel of God coming to him, and saying to him, “Cornelius!”', pt: 'cerca da hora nona do dia, viu claramente em visão um anjo de Deus, que se dirigia para ele e lhe dizia: Cornélio!' },
      { v: 4, en: 'He, fastening his eyes on him, and being frightened, said, “What is it, Lord?” He said to him, “Your prayers and your gifts to the needy have gone up for a memorial before God.', pt: 'Este, fitando nele os olhos e atemorizado, perguntou: Que é, Senhor? O anjo respondeu-lhe: As tuas orações e as tuas esmolas têm subido para memória diante de Deus;' },
      { v: 5, en: 'Now send men to Joppa, and get Simon, who is also called Peter.', pt: 'agora, pois, envia homens a Jope e manda chamar a Simão, que tem por sobrenome Pedro;' },
      { v: 6, en: 'He lodges with a tanner named Simon, whose house is by the seaside.', pt: 'este se acha hospedado com um certo Simão, curtidor, cuja casa fica à beira-mar. [Ele te dirá o que deves fazer.]' },
      { v: 7, en: 'When the angel who spoke to him had departed, Cornelius called two of his household servants and a devout soldier of those who waited on him continually.', pt: 'Logo que se retirou o anjo que lhe falava, Cornélio chamou dois dos seus domésticos e um piedoso soldado dos que estavam a seu serviço;' },
      { v: 8, en: 'Having explained everything to them, he sent them to Joppa.', pt: 'e, havendo contado tudo, os enviou a Jope.' },
      { v: 9, en: 'Now on the next day as they were on their journey, and got close to the city, Peter went up on the housetop to pray at about noon.', pt: 'No dia seguinte, indo eles seu caminho e estando já perto da cidade, subiu Pedro ao eirado para orar, cerca de hora sexta.' },
      { v: 10, en: 'He became hungry and desired to eat, but while they were preparing, he fell into a trance.', pt: 'E tendo fome, quis comer; mas enquanto lhe preparavam a comida, sobreveio-lhe um êxtase,' },
      { v: 11, en: 'He saw heaven opened and a certain container descending to him, like a great sheet let down by four corners on the earth,', pt: 'e via o céu aberto e um objeto descendo, como se fosse um grande lençol, sendo baixado pelas quatro pontas sobre a terra,' },
      { v: 12, en: 'in which were all kinds of four-footed animals of the earth, wild animals, reptiles, and birds of the sky.', pt: 'no qual havia de todos os quadrúpedes e répteis da terra e aves do céu.' },
      { v: 13, en: 'A voice came to him, “Rise, Peter, kill and eat!”', pt: 'E uma voz lhe disse: Levanta-te, Pedro, mata e come.' },
      { v: 14, en: 'But Peter said, “Not so, Lord; for I have never eaten anything that is common or unclean.”', pt: 'Mas Pedro respondeu: De modo nenhum, Senhor, porque nunca comi coisa alguma comum e imunda.' },
      { v: 15, en: 'A voice came to him again the second time, “What God has cleansed, you must not call unclean.”', pt: 'Pela segunda vez lhe falou a voz: Não chames tu comum ao que Deus purificou.' },
      { v: 16, en: 'This was done three times, and immediately the vessel was received up into heaven.', pt: 'Sucedeu isto por três vezes; e logo foi o objeto recolhido ao céu.' },
      { v: 17, en: 'Now while Peter was very perplexed in himself what the vision which he had seen might mean, behold, the men who were sent by Cornelius, having made inquiry for Simon’s house, stood before the gate,', pt: 'Enquanto Pedro refletia, perplexo, sobre o que seria a visão que tivera, eis que os homens enviados por Cornélio, tendo perguntado pela casa de Simão, pararam à porta.' },
      { v: 18, en: 'and called and asked whether Simon, who was also called Peter, was lodging there.', pt: 'E, chamando, indagavam se ali estava hospedado Simão, que tinha por sobrenome Pedro.' },
      { v: 19, en: 'While Peter was pondering the vision, the Spirit said to him, “Behold, three men seek you.', pt: 'Estando Pedro ainda a meditar sobre a visão, o Espírito lhe disse: Eis que dois homens te procuram.' },
      { v: 20, en: 'But arise, get down, and go with them, doubting nothing; for I have sent them.”', pt: 'Levanta-te, pois, desce e vai com eles, nada duvidando; porque eu tos enviei.' },
      { v: 21, en: 'Peter went down to the men, and said, “Behold, I am he whom you seek. Why have you come?”', pt: 'E descendo Pedro ao encontro desses homens, disse: Sou eu a quem procurais; qual é a causa por que viestes?' },
      { v: 22, en: 'They said, “Cornelius, a centurion, a righteous man and one who fears God, and well spoken of by all the nation of the Jews, was directed by a holy angel to invite you to his house, and to listen to what you say.”', pt: 'Eles responderam: O centurião Cornélio, homem justo e temente a Deus e que tem bom testemunho de toda a nação judaica, foi avisado por um santo anjo para te chamar à sua casa e ouvir as tuas palavras.' },
      { v: 23, en: 'So he called them in and provided a place to stay. On the next day Peter arose and went out with them, and some of the brothers from Joppa accompanied him.', pt: 'Pedro, pois, convidando-os a entrar, os hospedou. No dia seguinte levantou-se e partiu com eles, e alguns irmãos, dentre os de Jope, o acompanharam.' },
      { v: 24, en: 'On the next day they entered into Caesarea. Cornelius was waiting for them, having called together his relatives and his near friends.', pt: 'No outro dia entrou em Cesaréia. E Cornélio os esperava, tendo reunido os seus parentes e amigos mais íntimos.' },
      { v: 25, en: 'When Peter entered, Cornelius met him, fell down at his feet, and worshiped him.', pt: 'Quando Pedro ia entrar, veio-lhe Cornélio ao encontro e, prostrando-se a seus pés, o adorou.' },
      { v: 26, en: 'But Peter raised him up, saying, “Stand up! I myself am also a man.”', pt: 'Mas Pedro o ergueu, dizendo: Levanta-te, que eu também sou homem.' },
      { v: 27, en: 'As he talked with him, he went in and found many gathered together.', pt: 'E conversando com ele, entrou e achou muitos reunidos,' },
      { v: 28, en: 'He said to them, “You yourselves know how it is an unlawful thing for a man who is a Jew to join himself or come to one of another nation, but God has shown me that I shouldn’t call any man unholy or unclean.', pt: 'e disse-lhes: Vós bem sabeis que não é lícito a um judeu ajuntar-se ou chegar-se a estrangeiros; mas Deus mostrou-me que a nenhum homem devo chamar comum ou imundo;' },
      { v: 29, en: 'Therefore also I came without complaint when I was sent for. I ask therefore, why did you send for me?”', pt: 'pelo que, sendo chamado, vim sem objeção. Pergunto pois: Por que razão mandastes chamar-me?' },
      { v: 30, en: 'Cornelius said, “Four days ago, I was fasting until this hour, and at the ninth hour, I prayed in my house, and behold, a man stood before me in bright clothing,', pt: 'Então disse Cornélio: Faz agora quatro dias que eu estava orando em minha casa à hora nona, e eis que diante de mim se apresentou um homem com vestiduras resplandescentes,' },
      { v: 31, en: 'and said, ‘Cornelius, your prayer is heard, and your gifts to the needy are remembered in the sight of God.', pt: 'e disse: Cornélio, a tua oração foi ouvida, e as tuas esmolas estão em memória diante de Deus.' },
      { v: 32, en: 'Send therefore to Joppa, and summon Simon, who is also called Peter. He lodges in the house of a tanner named Simon, by the seaside. When he comes, he will speak to you.’', pt: 'Envia, pois, a Jope e manda chamar a Simão, que tem por sobrenome Pedro; ele está hospedado em casa de Simão, curtidor, à beira-mar.' },
      { v: 33, en: 'Therefore I sent to you at once, and it was good of you to come. Now therefore we are all here present in the sight of God to hear all things that have been commanded you by God.”', pt: 'Portanto mandei logo chamar-te, e bem fizeste em vir. Agora pois estamos todos aqui presentes diante de Deus, para ouvir tudo quanto te foi ordenado pelo Senhor.' },
      { v: 34, en: 'Peter opened his mouth and said, “Truly I perceive that God doesn’t show favoritism;', pt: 'Então Pedro, tomando a palavra, disse: Na verdade reconheço que Deus não faz acepção de pessoas;' },
      { v: 35, en: 'but in every nation he who fears him and works righteousness is acceptable to him.', pt: 'mas que lhe é aceitável aquele que, em qualquer nação, o teme e pratica o que é justo.' },
      { v: 36, en: 'The word which he sent to the children of Israel, preaching good news of peace by Jesus Christ—he is Lord of all—', pt: 'A palavra que ele enviou aos filhos de Israel, anunciando a paz por Jesus Cristo (este é o Senhor de todos) -' },
      { v: 37, en: 'you yourselves know what happened, which was proclaimed throughout all Judea, beginning from Galilee, after the baptism which John preached;', pt: 'esta palavra, vós bem sabeis, foi proclamada por toda a Judéia, começando pela Galiléia, depois do batismo que João pregou,' },
      { v: 38, en: 'even Jesus of Nazareth, how God anointed him with the Holy Spirit and with power, who went about doing good and healing all who were oppressed by the devil, for God was with him.', pt: 'concernente a Jesus de Nazaré, como Deus o ungiu com o Espírito Santo e com poder; o qual andou por toda parte, fazendo o bem e curando a todos os oprimidos do Diabo, porque Deus era com ele.' },
      { v: 39, en: 'We are witnesses of everything he did both in the country of the Jews, and in Jerusalem; whom they also killed, hanging him on a tree.', pt: 'Nós somos testemunhas de tudo quanto fez, tanto na terra dos judeus como em Jerusalém; ao qual mataram, pendurando-o num madeiro.' },
      { v: 40, en: 'God raised him up the third day, and gave him to be revealed,', pt: 'A este ressuscitou Deus ao terceiro dia e lhe concedeu que se manifestasse,' },
      { v: 41, en: 'not to all the people, but to witnesses who were chosen before by God, to us, who ate and drank with him after he rose from the dead.', pt: 'não a todo povo, mas às testemunhas predeterminadas por Deus, a nós, que comemos e bebemos juntamente com ele depois que ressurgiu dentre os mortos;' },
      { v: 42, en: 'He commanded us to preach to the people and to testify that this is he who is appointed by God as the Judge of the living and the dead.', pt: 'este nos mandou pregar ao povo, e testificar que ele é o que por Deus foi constituído juiz dos vivos e dos mortos.' },
      { v: 43, en: 'All the prophets testify about him, that through his name everyone who believes in him will receive remission of sins.”', pt: 'A ele todos os profetas dão testemunho de que todo o que nele crê receberá a remissão dos pecados pelo seu nome.' },
      { v: 44, en: 'While Peter was still speaking these words, the Holy Spirit fell on all those who heard the word.', pt: 'Enquanto Pedro ainda dizia estas coisas, desceu o Espírito Santo sobre todos os que ouviam a palavra.' },
      { v: 45, en: 'They of the circumcision who believed were amazed, as many as came with Peter, because the gift of the Holy Spirit was also poured out on the Gentiles.', pt: 'Os crentes que eram de circuncisão, todos quantos tinham vindo com Pedro, maravilharam-se de que também sobre os gentios se derramasse o dom do Espírito Santo;' },
      { v: 46, en: 'For they heard them speaking in other languages and magnifying God. Then Peter answered,', pt: 'porque os ouviam falar línguas e magnificar a Deus.' },
      { v: 47, en: '“Can anyone forbid these people from being baptized with water? They have received the Holy Spirit just like us.”', pt: 'Respondeu então Pedro: Pode alguém porventura recusar a água para que não sejam batizados estes que também, como nós, receberam o Espírito Santo?' },
      { v: 48, en: 'He commanded them to be baptized in the name of Jesus Christ. Then they asked him to stay some days.', pt: 'Mandou, pois, que fossem batizados em nome de Jesus Cristo. Então lhe rogaram que ficasse com eles por alguns dias.' },
    ],
    11: [
      { v: 1, en: 'Now the apostles and the brothers who were in Judea heard that the Gentiles had also received the word of God.', pt: 'Ora, ouviram os apóstolos e os irmãos que estavam na Judéia que também os gentios haviam recebido a palavra de Deus.' },
      { v: 2, en: 'When Peter had come up to Jerusalem, those who were of the circumcision contended with him,', pt: 'E quando Pedro subiu a Jerusalém, disputavam com ele os que eram da circuncisão,' },
      { v: 3, en: 'saying, “You went in to uncircumcised men, and ate with them!”', pt: 'dizendo: Entraste em casa de homens incircuncisos e comeste com eles.' },
      { v: 4, en: 'But Peter began, and explained to them in order, saying,', pt: 'Pedro, porém, começou a fazer-lhes uma exposição por ordem, dizendo:' },
      { v: 5, en: '“I was in the city of Joppa praying, and in a trance I saw a vision: a certain container descending, like it was a great sheet let down from heaven by four corners. It came as far as me.', pt: 'Estava eu orando na cidade de Jope, e em êxtase tive uma visão; descia um objeto, como se fosse um grande lençol, sendo baixado do céu pelas quatro pontas, e chegou perto de mim.' },
      { v: 6, en: 'When I had looked intently at it, I considered, and saw the four-footed animals of the earth, wild animals, creeping things, and birds of the sky.', pt: 'E, fitando nele os olhos, o contemplava, e vi quadrúpedes da terra, feras, répteis e aves do céu.' },
      { v: 7, en: 'I also heard a voice saying to me, ‘Rise, Peter, kill and eat!’', pt: 'Ouvi também uma voz que me dizia: Levanta-te, Pedro, mata e come.' },
      { v: 8, en: 'But I said, ‘Not so, Lord, for nothing unholy or unclean has ever entered into my mouth.’', pt: 'Mas eu respondi: De modo nenhum, Senhor, pois nunca em minha boca entrou coisa alguma comum e imunda.' },
      { v: 9, en: 'But a voice answered me the second time out of heaven, ‘What God has cleansed, don’t you call unclean.’', pt: 'Mas a voz respondeu-me do céu segunda vez: Não chames tu comum ao que Deus purificou.' },
      { v: 10, en: 'This was done three times, and all were drawn up again into heaven.', pt: 'Sucedeu isto por três vezes; e tudo tornou a recolher-se ao céu.' },
      { v: 11, en: 'Behold, immediately three men stood before the house where I was, having been sent from Caesarea to me.', pt: 'E eis que, nesse momento, pararam em frente à casa onde estávamos três homens que me foram enviados de Cesaréia.' },
      { v: 12, en: 'The Spirit told me to go with them, without discriminating. These six brothers also accompanied me, and we entered into the man’s house.', pt: 'Disse-me o Espírito que eu fosse com eles, sem hesitar; e também estes seis irmãos foram comigo e entramos na casa daquele homem.' },
      { v: 13, en: 'He told us how he had seen the angel standing in his house, and saying to him, ‘Send to Joppa, and get Simon, who is called Peter,', pt: 'E ele nos contou como vira em pé em sua casa o anjo, que lhe dissera: Envia a Jope e manda chamar a Simão, que tem por sobrenome Pedro,' },
      { v: 14, en: 'who will speak to you words by which you will be saved, you and all your house.’', pt: 'o qual te dirá palavras pelas quais serás salvo, tu e toda a tua casa.' },
      { v: 15, en: 'As I began to speak, the Holy Spirit fell on them, even as on us at the beginning.', pt: 'Logo que eu comecei a falar, desceu sobre eles o Espírito Santo, como também sobre nós no princípio.' },
      { v: 16, en: 'I remembered the word of the Lord, how he said, ‘John indeed baptized in water, but you will be baptized in the Holy Spirit.’', pt: 'Lembrei-me então da palavra do Senhor, como disse: João, na verdade, batizou com água; mas vós sereis batizados no Espírito Santo.' },
      { v: 17, en: 'If then God gave to them the same gift as us, when we believed in the Lord Jesus Christ, who was I, that I could withstand God?”', pt: 'Portanto, se Deus lhes deu o mesmo dom que dera também a nós, ao crermos no Senhor Jesus Cristo, quem era eu, para que pudesse resistir a Deus?' },
      { v: 18, en: 'When they heard these things, they held their peace, and glorified God, saying, “Then God has also granted to the Gentiles repentance to life!”', pt: 'Ouvindo eles estas coisas, apaziguaram-se e glorificaram a Deus, dizendo: Assim, pois, Deus concedeu também aos gentios o arrependimento para a vida.' },
      { v: 19, en: 'They therefore who were scattered abroad by the oppression that arose about Stephen traveled as far as Phoenicia, Cyprus, and Antioch, speaking the word to no one except to Jews only.', pt: 'Aqueles, pois, que foram dispersos pela tribulação suscitada por causa de Estêvão, passaram até a Fenícia, Chipre e Antioquia, não anunciando a ninguém a palavra, senão somente aos judeus.' },
      { v: 20, en: 'But there were some of them, men of Cyprus and Cyrene, who, when they had come to Antioch, spoke to the Hellenists, preaching the Lord Jesus.', pt: 'Havia, porém, entre eles alguns cíprios e cirenenses, os quais, entrando em Antioquia, falaram também aos gregos, anunciando o Senhor Jesus.' },
      { v: 21, en: 'The hand of the Lord was with them, and a great number believed and turned to the Lord.', pt: 'E a mão do Senhor era com eles, e grande número creu e se converteu ao Senhor.' },
      { v: 22, en: 'The report concerning them came to the ears of the assembly which was in Jerusalem. They sent out Barnabas to go as far as Antioch,', pt: 'Chegou a notícia destas coisas aos ouvidos da igreja em Jerusalém; e enviaram Barnabé a Antioquia;' },
      { v: 23, en: 'who, when he had come, and had seen the grace of God, was glad. He exhorted them all, that with purpose of heart they should remain near to the Lord.', pt: 'o qual, quando chegou e viu a graça de Deus, se alegrou, e exortava a todos a perseverarem no Senhor com firmeza de coração;' },
      { v: 24, en: 'For he was a good man, and full of the Holy Spirit and of faith, and many people were added to the Lord.', pt: 'porque era homem de bem, e cheio do Espírito Santo e de fé. E muita gente se uniu ao Senhor.' },
      { v: 25, en: 'Barnabas went out to Tarsus to look for Saul.', pt: 'Partiu, pois, Barnabé para Tarso, em busca de Saulo;' },
      { v: 26, en: 'When he had found him, he brought him to Antioch. For a whole year they were gathered together with the assembly, and taught many people. The disciples were first called Christians in Antioch.', pt: 'e tendo-o achado, o levou para Antioquia. E durante um ano inteiro reuniram-se naquela igreja e instruíram muita gente; e em Antioquia os discípulos pela primeira vez foram chamados cristãos.' },
      { v: 27, en: 'Now in these days, prophets came down from Jerusalem to Antioch.', pt: 'Naqueles dias desceram profetas de Jerusalém para Antioquia;' },
      { v: 28, en: 'One of them named Agabus stood up, and indicated by the Spirit that there should be a great famine all over the world, which also happened in the days of Claudius.', pt: 'e levantando-se um deles, de nome Ágabo, dava a entender pelo Espírito, que haveria uma grande fome por todo o mundo, a qual ocorreu no tempo de Cláudio.' },
      { v: 29, en: 'As any of the disciples had plenty, each determined to send relief to the brothers who lived in Judea;', pt: 'E os discípulos resolveram mandar, cada um conforme suas posses, socorro aos irmãos que habitavam na Judéia;' },
      { v: 30, en: 'which they also did, sending it to the elders by the hands of Barnabas and Saul.', pt: 'o que eles com efeito fizeram, enviando-o aos anciãos por mão de Barnabé e Saulo.' },
    ],
    12: [
      { v: 1, en: 'Now about that time, King Herod stretched out his hands to oppress some of the assembly.', pt: 'Por aquele mesmo tempo o rei Herodes estendeu as mãos sobre alguns da igreja, para os maltratar;' },
      { v: 2, en: 'He killed James, the brother of John, with the sword.', pt: 'e matou à espada Tiago, irmão de João.' },
      { v: 3, en: 'When he saw that it pleased the Jews, he proceeded to seize Peter also. This was during the days of unleavened bread.', pt: 'Vendo que isso agradava aos judeus, continuou, mandando prender também a Pedro. (Eram então os dias dos pães ázimos.)' },
      { v: 4, en: 'When he had arrested him, he put him in prison, and delivered him to four squads of four soldiers each to guard him, intending to bring him out to the people after the Passover.', pt: 'E, havendo-o prendido, lançou-o na prisão, entregando-o a quatro grupos de quatro soldados cada um para o guardarem, tencionando apresentá-lo ao povo depois da páscoa.' },
      { v: 5, en: 'Peter therefore was kept in the prison, but constant prayer was made by the assembly to God for him.', pt: 'Pedro, pois, estava guardado na prisão; mas a igreja orava com insistência a Deus por ele.' },
      { v: 6, en: 'The same night when Herod was about to bring him out, Peter was sleeping between two soldiers, bound with two chains. Guards in front of the door kept the prison.', pt: 'Ora quando Herodes estava para apresentá-lo, nessa mesma noite estava Pedro dormindo entre dois soldados, acorrentado com duas cadeias e as sentinelas diante da porta guardavam a prisão.' },
      { v: 7, en: 'And behold, an angel of the Lord stood by him, and a light shone in the cell. He struck Peter on the side, and woke him up, saying, “Stand up quickly!” His chains fell off from his hands.', pt: 'E eis que sobreveio um anjo do Senhor, e uma luz resplandeceu na prisão; e ele, tocando no lado de Pedro, o despertou, dizendo: Levanta-te depressa. E caíram-lhe das mãos as cadeias.' },
      { v: 8, en: 'The angel said to him, “Get dressed and put on your sandals.” He did so. He said to him, “Put on your cloak, and follow me.”', pt: 'Disse-lhe ainda o anjo: Cinge-te e calça as tuas sandálias. E ele o fez. Disse-lhe mais; Cobre-te com a tua capa e segue-me.' },
      { v: 9, en: 'And he went out and followed him. He didn’t know that what was being done by the angel was real, but thought he saw a vision.', pt: 'Pedro, saindo, o seguia, mesmo sem compreender que era real o que se fazia por intermédio de um anjo, julgando que era uma visão.' },
      { v: 10, en: 'When they were past the first and the second guard, they came to the iron gate that leads into the city, which opened to them by itself. They went out, and went down one street, and immediately the angel departed from him.', pt: 'Depois de terem passado a primeira e a segunda sentinela, chegaram à porta de ferro, que dá para a cidade, a qual se lhes abriu por si mesma; e tendo saído, passaram uma rua, e logo o anjo se apartou dele.' },
      { v: 11, en: 'When Peter had come to himself, he said, “Now I truly know that the Lord has sent out his angel and delivered me out of the hand of Herod, and from everything the Jewish people were expecting.”', pt: 'Pedro então, tornando a si, disse: Agora sei verdadeiramente que o Senhor enviou o seu anjo, e me livrou da mão de Herodes e de toda a expectativa do povo dos judeus.' },
      { v: 12, en: 'Thinking about that, he came to the house of Mary, the mother of John who was called Mark, where many were gathered together and were praying.', pt: 'Depois de assim refletir foi à casa de Maria, mãe de João, que tem por sobrenome Marcos, onde muitas pessoas estavam reunidas e oravam.' },
      { v: 13, en: 'When Peter knocked at the door of the gate, a maid named Rhoda came to answer.', pt: 'Quando ele bateu ao portão do pátio, uma criada chamada Rode saiu a escutar;' },
      { v: 14, en: 'When she recognized Peter’s voice, she didn’t open the gate for joy, but ran in, and reported that Peter was standing in front of the gate.', pt: 'e, reconhecendo a voz de Pedro, de gozo não abriu o portão, mas, correndo para dentro, anunciou que Pedro estava lá fora.' },
      { v: 15, en: 'They said to her, “You are crazy!” But she insisted that it was so. They said, “It is his angel.”', pt: 'Eles lhe disseram: Estás louca. Ela, porém, assegurava que assim era. Eles então diziam: É o seu anjo.' },
      { v: 16, en: 'But Peter continued knocking. When they had opened, they saw him, and were amazed.', pt: 'Mas Pedro continuava a bater, e, quando abriram, viram-no e pasmaram.' },
      { v: 17, en: 'But he, beckoning to them with his hand to be silent, declared to them how the Lord had brought him out of the prison. He said, “Tell these things to James, and to the brothers.” Then he departed, and went to another place.', pt: 'Mas ele, acenando-lhes com a mão para que se calassem, contou-lhes como o Senhor o tirara da prisão, e disse: Anunciai isto a Tiago e aos irmãos. E, saindo, partiu para outro lugar.' },
      { v: 18, en: 'Now as soon as it was day, there was no small stir among the soldiers about what had become of Peter.', pt: 'Logo que amanheceu, houve grande alvoroço entre os soldados sobre o que teria sido feito de Pedro.' },
      { v: 19, en: 'When Herod had sought for him, and didn’t find him, he examined the guards, and commanded that they should be put to death. He went down from Judea to Caesarea, and stayed there.', pt: 'E Herodes, tendo-o procurado e não o achando, inquiriu as sentinelas e mandou que fossem justiçadas; e descendo da Judéia para Cesaréia, demorou-se ali.' },
      { v: 20, en: 'Now Herod was very angry with the people of Tyre and Sidon. They came with one accord to him, and, having made Blastus, the king’s personal aide, their friend, they asked for peace, because their country depended on the king’s country for food.', pt: 'Ora, Herodes estava muito irritado contra os de Tiro e de Sidom; mas estes, vindo de comum acordo ter com ele e obtendo a amizade de Blasto, camareiro do rei, pediam paz, porquanto o seu país se abastecia do país do rei.' },
      { v: 21, en: 'On an appointed day, Herod dressed himself in royal clothing, sat on the throne, and gave a speech to them.', pt: 'num dia designado, Herodes, vestido de trajes reais, sentou- se no trono e dirigia-lhes a palavra.' },
      { v: 22, en: 'The people shouted, “The voice of a god, and not of a man!”', pt: 'E o povo exclamava: É a voz de um deus, e não de um homem.' },
      { v: 23, en: 'Immediately an angel of the Lord struck him, because he didn’t give God the glory, and he was eaten by worms and died.', pt: 'No mesmo instante o anjo do Senhor o feriu, porque não deu glória a Deus; e, comido de vermes, expirou.' },
      { v: 24, en: 'But the word of God grew and multiplied.', pt: 'E a palavra de Deus crescia e se multiplicava.' },
      { v: 25, en: 'Barnabas and Saul returned to Jerusalem, when they had fulfilled their service, also taking with them John who was called Mark.', pt: 'Barnabé e Saulo, havendo terminando aquele serviço, voltaram de Jerusalém, levando consigo a João, que tem por sobrenome Marcos.' },
    ],
    13: [
      { v: 1, en: 'Now in the assembly that was at Antioch there were some prophets and teachers: Barnabas, Simeon who was called Niger, Lucius of Cyrene, Manaen the foster brother of Herod the tetrarch, and Saul.', pt: 'Ora, na igreja em Antioquia havia profetas e mestres, a saber: Barnabé, Simeão, chamado Níger, Lúcio de Cirene, Manaém, colaço de Herodes o tetrarca, e Saulo.' },
      { v: 2, en: 'As they served the Lord and fasted, the Holy Spirit said, “Separate Barnabas and Saul for me, for the work to which I have called them.”', pt: 'Enquanto eles ministravam perante o Senhor e jejuavam, disse o Espírito Santo: Separai-me a Barnabé e a Saulo para a obra a que os tenho chamado.' },
      { v: 3, en: 'Then, when they had fasted and prayed and laid their hands on them, they sent them away.', pt: 'Então, depois que jejuaram, oraram e lhes impuseram as mãos, os despediram.' },
      { v: 4, en: 'So, being sent out by the Holy Spirit, they went down to Seleucia. From there they sailed to Cyprus.', pt: 'Estes, pois, enviados pelo Espírito Santo, desceram a Selêucia e dali navegaram para Chipre.' },
      { v: 5, en: 'When they were at Salamis, they proclaimed God’s word in the Jewish synagogues. They had also John as their attendant.', pt: 'Chegados a Salamina, anunciavam a palavra de Deus nas sinagogas dos judeus, e tinham a João como auxiliar.' },
      { v: 6, en: 'When they had gone through the island to Paphos, they found a certain sorcerer, a false prophet, a Jew, whose name was Bar Jesus,', pt: 'Havendo atravessado a ilha toda até Pafos, acharam um certo mago, falso profeta, judeu, chamado Bar-Jesus,' },
      { v: 7, en: 'who was with the proconsul, Sergius Paulus, a man of understanding. This man summoned Barnabas and Saul, and sought to hear the word of God.', pt: 'que estava com o procônsul Sérgio Paulo, homem sensato. Este chamou a Barnabé e Saulo e mostrou desejo de ouvir a palavra de Deus.' },
      { v: 8, en: 'But Elymas the sorcerer (for so is his name by interpretation) withstood them, seeking to turn the proconsul away from the faith.', pt: 'Mas resistia-lhes Elimas, o encantador (porque assim se interpreta o seu nome), procurando desviar a fé do procônsul.' },
      { v: 9, en: 'But Saul, who is also called Paul, filled with the Holy Spirit, fastened his eyes on him,', pt: 'Todavia Saulo, também chamado Paulo, cheio do Espírito Santo, fitando os olhos nele,' },
      { v: 10, en: 'and said, “Full of all deceit and all cunning, you son of the devil, you enemy of all righteousness, will you not cease to pervert the right ways of the Lord?', pt: 'disse: ç filho do Diabo, cheio de todo o engano e de toda a malícia, inimigo de toda a justiça, não cessarás de perverter os caminhos retos do Senhor?' },
      { v: 11, en: 'Now, behold, the hand of the Lord is on you, and you will be blind, not seeing the sun for a season!” Immediately a mist and darkness fell on him. He went around seeking someone to lead him by the hand.', pt: 'Agora eis a mão do Senhor sobre ti, e ficarás cego, sem ver o sol por algum tempo. Imediatamente caiu sobre ele uma névoa e trevas e, andando à roda, procurava quem o guiasse pela mão.' },
      { v: 12, en: 'Then the proconsul, when he saw what was done, believed, being astonished at the teaching of the Lord.', pt: 'Então o procônsul, vendo o que havia acontecido, creu, maravilhando-se da doutrina do Senhor.' },
      { v: 13, en: 'Now Paul and his company set sail from Paphos, and came to Perga in Pamphylia. John departed from them and returned to Jerusalem.', pt: 'Tendo Paulo e seus companheiros navegado de Pafos, chegaram a Perge, na Panfília. João, porém, apartando-se deles, voltou para Jerusalém.' },
      { v: 14, en: 'But they, passing on from Perga, came to Antioch of Pisidia. They went into the synagogue on the Sabbath day, and sat down.', pt: 'Mas eles, passando de Perge, chegaram a Antioquia da Psídia; e entrando na sinagoga, no dia de sábado, sentaram-se.' },
      { v: 15, en: 'After the reading of the law and the prophets, the rulers of the synagogue sent to them, saying, “Brothers, if you have any word of exhortation for the people, speak.”', pt: 'Depois da leitura da lei e dos profetas, os chefes da sinagoga mandaram dizer-lhes: Irmãos, se tendes alguma palavra de exortação ao povo, falai.' },
      { v: 16, en: 'Paul stood up, and beckoning with his hand said, “Men of Israel, and you who fear God, listen.', pt: 'Então Paulo se levantou e, pedindo silêncio com a mão, disse: Varões israelitas, e os que temeis a Deus, ouvi:' },
      { v: 17, en: 'The God of this people chose our fathers, and exalted the people when they stayed as aliens in the land of Egypt, and with an uplifted arm, he led them out of it.', pt: 'O Deus deste povo de Israel escolheu a nossos pais, e exaltou o povo, sendo eles estrangeiros na terra do Egito, de onde os tirou com braço poderoso,' },
      { v: 18, en: 'For a period of about forty years he put up with them in the wilderness.', pt: 'e suportou-lhes os maus costumes no deserto por espaço de quase quarenta anos;' },
      { v: 19, en: 'When he had destroyed seven nations in the land of Canaan, he gave them their land for an inheritance, for about four hundred fifty years.', pt: 'e, havendo destruído as sete nações na terra de Canaã, deu- lhes o território delas por herança durante cerca de quatrocentos e cinquenta anos.' },
      { v: 20, en: 'After these things he gave them judges until Samuel the prophet.', pt: 'Depois disto, deu-lhes juízes até o profeta Samuel.' },
      { v: 21, en: 'Afterward they asked for a king, and God gave to them Saul the son of Kish, a man of the tribe of Benjamin, for forty years.', pt: 'Então pediram um rei, e Deus lhes deu por quarenta anos a Saul, filho de Cis, varão da tribo de Benjamim.' },
      { v: 22, en: 'When he had removed him, he raised up David to be their king, to whom he also testified, ‘I have found David the son of Jesse, a man after my heart, who will do all my will.’', pt: 'E tendo deposto a este, levantou-lhes como rei a Davi, ao qual também, dando testemunho, disse: Achei a Davi, filho de Jessé, homem segundo o meu coração, que fará toda a minha vontade.' },
      { v: 23, en: 'From this man’s offspring, God has brought salvation to Israel according to his promise,', pt: 'Da descendência deste, conforme a promessa, trouxe Deus a Israel um Salvador, Jesus;' },
      { v: 24, en: 'before his coming, when John had first preached the baptism of repentance to Israel.', pt: 'havendo João, antes da aparecimento dele, pregado a todo o povo de Israel o batismo de arrependimento.' },
      { v: 25, en: 'As John was fulfilling his course, he said, ‘What do you suppose that I am? I am not he. But behold, one comes after me, the sandals of whose feet I am not worthy to untie.’', pt: 'Mas João, quando completava a carreira, dizia: Quem pensais vós que su sou? Eu não sou o Cristo, mas eis que após mim vem aquele a quem não sou digno de desatar as alparcas dos pés.' },
      { v: 26, en: 'Brothers, children of the stock of Abraham, and those among you who fear God, the word of this salvation is sent out to you.', pt: 'Irmãos, filhos da estirpe de Abraão, e os que dentre vós temem a Deus, a nós é enviada a palavra desta salvação.' },
      { v: 27, en: 'For those who dwell in Jerusalem, and their rulers, because they didn’t know him, nor the voices of the prophets which are read every Sabbath, fulfilled them by condemning him.', pt: 'Pois, os que habitam em Jerusalém e as suas autoridades, porquanto não conheceram a este Jesus, condenando-o, cumpriram as mesmas palavras dos profetas que se ouvem ler todos os sábados.' },
      { v: 28, en: 'Though they found no cause for death, they still asked Pilate to have him killed.', pt: 'E, se bem que não achassem nele nenhuma causa de morte, pediram a Pilatos que ele fosse morto.' },
      { v: 29, en: 'When they had fulfilled all things that were written about him, they took him down from the tree, and laid him in a tomb.', pt: 'Quando haviam cumprido todas as coisas que dele estavam escritas, tirando-o do madeiro, o puseram na sepultura;' },
      { v: 30, en: 'But God raised him from the dead,', pt: 'mas Deus o ressuscitou dentre os mortos;' },
      { v: 31, en: 'and he was seen for many days by those who came up with him from Galilee to Jerusalem, who are his witnesses to the people.', pt: 'e ele foi visto durante muitos dias por aqueles que com ele subiram da Galiléia a Jerusalém, os quais agora são suas testemunhas para com o povo.' },
      { v: 32, en: 'We bring you good news of the promise made to the fathers,', pt: 'E nós vos anunciamos as boas novas da promessa, feita aos pais,' },
      { v: 33, en: 'that God has fulfilled the same to us, their children, in that he raised up Jesus. As it is also written in the second psalm, ‘You are my Son. Today I have become your father.’', pt: 'a qual Deus nos tem cumprido, a nós, filhos deles, levantando a Jesus, como também está escrito no salmo segundo: Tu és meu Filho, hoje te gerei.' },
      { v: 34, en: '“Concerning that he raised him up from the dead, now no more to return to corruption, he has spoken thus: ‘I will give you the holy and sure blessings of David.’', pt: 'E no tocante a que o ressuscitou dentre os mortos para nunca mais tornar à corrupção, falou Deus assim: Dar-vos-ei as santas e fiéis bênçãos de Davi;' },
      { v: 35, en: 'Therefore he says also in another psalm, ‘You will not allow your Holy One to see decay.’', pt: 'pelo que ainda em outro salmo diz: Não permitirás que o teu Santo veja a corrupção.' },
      { v: 36, en: 'For David, after he had in his own generation served the counsel of God, fell asleep, and was laid with his fathers, and saw decay.', pt: 'Porque Davi, na verdade, havendo servido a sua própria geração pela vontade de Deus, dormiu e foi depositado junto a seus pais e experimentou corrupção.' },
      { v: 37, en: 'But he whom God raised up saw no decay.', pt: 'Mas aquele a quem Deus ressuscitou nenhuma corrupção experimentou.' },
      { v: 38, en: 'Be it known to you therefore, brothers, that through this man is proclaimed to you remission of sins,', pt: 'Seja-vos pois notório, varões, que por este se vos anuncia a remissão dos pecados.' },
      { v: 39, en: 'and by him everyone who believes is justified from all things, from which you could not be justified by the law of Moses.', pt: 'E de todas as coisas de que não pudestes ser justificados pela lei de Moisés, por ele é justificado todo o que crê.' },
      { v: 40, en: 'Beware therefore, lest that come on you which is spoken in the prophets:', pt: 'Cuidai pois que não venha sobre vós o que está dito nos profetas:' },
      { v: 41, en: '‘Behold, you scoffers, and wonder, and perish; for I work a work in your days, a work which you will in no way believe, if one declares it to you.’”', pt: 'Vede, ó desprezadores, admirai-vos e desaparecei; porque realizo uma obra em vossos dias, obra em que de modo algum crereis, se alguém vo-la contar.' },
      { v: 42, en: 'So when the Jews went out of the synagogue, the Gentiles begged that these words might be preached to them the next Sabbath.', pt: 'Quando iam saindo, rogavam que estas palavras lhes fossem repetidas no sábado seguinte.' },
      { v: 43, en: 'Now when the synagogue broke up, many of the Jews and of the devout proselytes followed Paul and Barnabas; who, speaking to them, urged them to continue in the grace of God.', pt: 'E, despedida a sinagoga, muitos judeus e prosélitos devotos seguiram a Paulo e Barnabé, os quais, falando-lhes, os exortavam a perseverarem na graça de Deus.' },
      { v: 44, en: 'The next Sabbath, almost the whole city was gathered together to hear the word of God.', pt: 'No sábado seguinte reuniu-se quase toda a cidade para ouvir a palavra de Deus.' },
      { v: 45, en: 'But when the Jews saw the multitudes, they were filled with jealousy, and contradicted the things which were spoken by Paul, and blasphemed.', pt: 'Mas os judeus, vendo as multidões, encheram-se de inveja e, blasfemando, contradiziam o que Paulo falava.' },
      { v: 46, en: 'Paul and Barnabas spoke out boldly, and said, “It was necessary that God’s word should be spoken to you first. Since indeed you thrust it from you, and judge yourselves unworthy of eternal life, behold, we turn to the Gentiles.', pt: 'Então Paulo e Barnabé, falando ousadamente, disseram: Era mister que a vós se pregasse em primeiro lugar a palavra de Deus; mas, visto que a rejeitais, e não vos julgais dignos da vida eterna, eis que nos viramos para os gentios;' },
      { v: 47, en: 'For so has the Lord commanded us, saying, ‘I have set you as a light for the Gentiles, that you should bring salvation to the uttermost parts of the earth.’”', pt: 'porque assim nos ordenou o Senhor: Eu te pus para luz dos gentios, a fim de que sejas para salvação até os confins da terra.' },
      { v: 48, en: 'As the Gentiles heard this, they were glad, and glorified the word of God. As many as were appointed to eternal life believed.', pt: 'Os gentios, ouvindo isto, alegravam-se e glorificavam a palavra do Senhor; e creram todos quantos haviam sido destinados para a vida eterna.' },
      { v: 49, en: 'The Lord’s word was spread abroad throughout all the region.', pt: 'E divulgava-se a palavra do Senhor por toda aquela região.' },
      { v: 50, en: 'But the Jews stirred up the devout and prominent women and the chief men of the city, and stirred up a persecution against Paul and Barnabas, and threw them out of their borders.', pt: 'Mas os judeus incitaram as mulheres devotas de alta posição e os principais da cidade, suscitaram uma perseguição contra Paulo e Barnabé, e os lançaram fora dos seus termos.' },
      { v: 51, en: 'But they shook off the dust of their feet against them, and came to Iconium.', pt: 'Mas estes, sacudindo contra eles o pó dos seus pés, partiram para Icônio.' },
      { v: 52, en: 'The disciples were filled with joy and with the Holy Spirit.', pt: 'Os discípulos, porém, estavam cheios de alegria e do Espírito Santo.' },
    ],
    14: [
      { v: 1, en: 'In Iconium, they entered together into the synagogue of the Jews, and so spoke that a great multitude both of Jews and of Greeks believed.', pt: 'Em Icônio entraram juntos na sinagoga dos judeus e falaram de tal modo que creu uma grande multidão tanto de judeus como de gregos.' },
      { v: 2, en: 'But the disbelieving Jews stirred up and embittered the souls of the Gentiles against the brothers.', pt: 'Mas os judeus incrédulos excitaram e irritaram os ânimos dos gentios contra os irmãos.' },
      { v: 3, en: 'Therefore they stayed there a long time, speaking boldly in the Lord, who testified to the word of his grace, granting signs and wonders to be done by their hands.', pt: 'Eles, entretanto, se demoraram ali por muito tempo, falando ousadamente acerca do Senhor, o qual dava testemunho à palavra da sua graça, concedendo que por suas mãos se fizessem sinais e prodígios.' },
      { v: 4, en: 'But the multitude of the city was divided. Part sided with the Jews, and part with the apostles.', pt: 'E se dividiu o povo da cidade; uns eram pelos judeus, e outros pelos apóstolos.' },
      { v: 5, en: 'When some of both the Gentiles and the Jews, with their rulers, made a violent attempt to mistreat and stone them,', pt: 'E, havendo um motim tanto dos gentios como dos judeus, juntamente com as suas autoridades, para os ultrajarem e apedrejarem,' },
      { v: 6, en: 'they became aware of it, and fled to the cities of Lycaonia, Lystra, Derbe, and the surrounding region.', pt: 'eles, sabendo-o, fugiram para Listra e Derbe, cidades da Licaônia, e a região circunvizinha;' },
      { v: 7, en: 'There they preached the Good News.', pt: 'e ali pregavam o evangelho.' },
      { v: 8, en: 'At Lystra a certain man sat, impotent in his feet, a cripple from his mother’s womb, who never had walked.', pt: 'Em Listra estava sentado um homem aleijado dos pés, coxo de nascença e que nunca tinha andado.' },
      { v: 9, en: 'He was listening to Paul speaking, who, fastening eyes on him, and seeing that he had faith to be made whole,', pt: 'Este ouvia falar Paulo, que, fitando nele os olhos e vendo que tinha fé para ser curado,' },
      { v: 10, en: 'said with a loud voice, “Stand upright on your feet!” He leaped up and walked.', pt: 'disse em alta voz: Levanta-te direito sobre os teus pés. E ele saltou, e andava.' },
      { v: 11, en: 'When the multitude saw what Paul had done, they lifted up their voice, saying in the language of Lycaonia, “The gods have come down to us in the likeness of men!”', pt: 'As multidões, vendo o que Paulo fizera, levantaram a voz, dizendo em língua licaônica: Fizeram-se os deuses semelhantes aos homens e desceram até nós.' },
      { v: 12, en: 'They called Barnabas “Jupiter”, and Paul “Mercury”, because he was the chief speaker.', pt: 'A Barnabé chamavam Júpiter e a Paulo, Mercúrio, porque era ele o que dirigia a palavra.' },
      { v: 13, en: 'The priest of Jupiter, whose temple was in front of their city, brought oxen and garlands to the gates, and would have made a sacrifice along with the multitudes.', pt: 'O sacerdote de Júpiter, cujo templo estava em frente da cidade, trouxe para as portas touros e grinaldas e, juntamente com as multidões, queria oferecer-lhes sacrifícios.' },
      { v: 14, en: 'But when the apostles, Barnabas and Paul, heard of it, they tore their clothes, and sprang into the multitude, crying out,', pt: 'Quando, porém, os apóstolos Barnabé e Paulo ouviram isto, rasgaram as suas vestes e saltaram para o meio da multidão, clamando' },
      { v: 15, en: '“Men, why are you doing these things? We also are men of like passions with you, and bring you good news, that you should turn from these vain things to the living God, who made the sky, the earth, the sea, and all that is in them;', pt: 'e dizendo: Senhores, por que fazeis estas coisas? Nós também somos homens, de natureza semelhante à vossa, e vos anunciamos o evangelho para que destas práticas vãs vos convertais ao Deus vivo, que fez o céu, a terra, o mar, e tudo quanto há neles;' },
      { v: 16, en: 'who in the generations gone by allowed all the nations to walk in their own ways.', pt: 'o qual nos tempos passados permitiu que todas as nações andassem nos seus próprios caminhos.' },
      { v: 17, en: 'Yet he didn’t leave himself without witness, in that he did good and gave you rains from the sky and fruitful seasons, filling our hearts with food and gladness.”', pt: 'Contudo não deixou de dar testemunho de si mesmo, fazendo o bem, dando-vos chuvas do céu e estações frutíferas, enchendo-vos de mantimento, e de alegria os vossos corações.' },
      { v: 18, en: 'Even saying these things, they hardly stopped the multitudes from making a sacrifice to them.', pt: 'E dizendo isto, com dificuldade impediram as multidões de lhes oferecerem sacrifícios.' },
      { v: 19, en: 'But some Jews from Antioch and Iconium came there, and having persuaded the multitudes, they stoned Paul, and dragged him out of the city, supposing that he was dead.', pt: 'Sobrevieram, porém, judeus de Antioquia e de Icônio e, havendo persuadido as multidões, apedrejaram a Paulo, e arrastaram-no para fora da cidade, cuidando que estava morto.' },
      { v: 20, en: 'But as the disciples stood around him, he rose up, and entered into the city. On the next day he went out with Barnabas to Derbe.', pt: 'Mas quando os discípulos o rodearam, ele se levantou e entrou na cidade. No dia seguinte partiu com Barnabé para Derbe.' },
      { v: 21, en: 'When they had preached the Good News to that city, and had made many disciples, they returned to Lystra, Iconium, and Antioch,', pt: 'E, tendo anunciado o evangelho naquela cidade e feito muitos discípulos, voltaram para Listra, Icônio e Antioquia,' },
      { v: 22, en: 'confirming the souls of the disciples, exhorting them to continue in the faith, and that through many afflictions we must enter into God’s Kingdom.', pt: 'confirmando as almas dos discípulos, exortando-os a perseverarem na fé, dizendo que por muitas tribulações nos é necessário entrar no reino de Deus.' },
      { v: 23, en: 'When they had appointed elders for them in every assembly, and had prayed with fasting, they commended them to the Lord, on whom they had believed.', pt: 'E, havendo-lhes feito eleger anciãos em cada igreja e orado com jejuns, os encomendaram ao Senhor em quem haviam crido.' },
      { v: 24, en: 'They passed through Pisidia, and came to Pamphylia.', pt: 'Atravessando então a Pisídia, chegaram à Panfília.' },
      { v: 25, en: 'When they had spoken the word in Perga, they went down to Attalia.', pt: 'E, tendo anunciado a palavra em Perge, desceram a Atália.' },
      { v: 26, en: 'From there they sailed to Antioch, from where they had been committed to the grace of God for the work which they had fulfilled.', pt: 'E dali navegaram para Antioquia, donde tinham sido encomendados à graça de Deus para a obra que acabavam de cumprir.' },
      { v: 27, en: 'When they had arrived, and had gathered the assembly together, they reported all the things that God had done with them, and that he had opened a door of faith to the nations.', pt: 'Quando chegaram e reuniram a igreja, relataram tudo quanto Deus fizera por meio deles, e como abrira aos gentios a porta da fé.' },
      { v: 28, en: 'They stayed there with the disciples for a long time.', pt: 'E ficaram ali não pouco tempo, com os discípulos.' },
    ],
    15: [
      { v: 1, en: 'Some men came down from Judea and taught the brothers, “Unless you are circumcised after the custom of Moses, you can’t be saved.”', pt: 'Então alguns que tinham descido da Judéia ensinavam aos irmãos: Se não vos circuncidardes, segundo o rito de Moisés, não podeis ser salvos.' },
      { v: 2, en: 'Therefore when Paul and Barnabas had no small discord and discussion with them, they appointed Paul and Barnabas, and some others of them, to go up to Jerusalem to the apostles and elders about this question.', pt: 'Tendo Paulo e Barnabé contenda e não pequena discussão com eles, os irmãos resolveram que Paulo e Barnabé e mais alguns dentre eles subissem a Jerusalém, aos apóstolos e aos anciãos, por causa desta questão.' },
      { v: 3, en: 'They, being sent on their way by the assembly, passed through both Phoenicia and Samaria, declaring the conversion of the Gentiles. They caused great joy to all the brothers.', pt: 'Eles, pois, sendo acompanhados pela igreja por um trecho do caminho, passavam pela Fenícia e por Samária, contando a conversão dos gentios; e davam grande alegria a todos os irmãos.' },
      { v: 4, en: 'When they had come to Jerusalem, they were received by the assembly and the apostles and the elders, and they reported all things that God had done with them.', pt: 'E, quando chegaram a Jerusalém, foram recebidos pela igreja e pelos apóstolos e anciãos, e relataram tudo quanto Deus fizera por meio deles.' },
      { v: 5, en: 'But some of the sect of the Pharisees who believed rose up, saying, “It is necessary to circumcise them, and to command them to keep the law of Moses.”', pt: 'Mas alguns da seita dos fariseus, que tinham crido, levantaram-se dizendo que era necessário circuncidá-los e mandar-lhes observar a lei de Moisés.' },
      { v: 6, en: 'The apostles and the elders were gathered together to see about this matter.', pt: 'Congregaram-se pois os apóstolos e os anciãos para considerar este assunto.' },
      { v: 7, en: 'When there had been much discussion, Peter rose up and said to them, “Brothers, you know that a good while ago God made a choice among you, that by my mouth the nations should hear the word of the Good News, and believe.', pt: 'E, havendo grande discussão, levantou-se Pedro e disse-lhes: Irmãos, bem sabeis que já há muito tempo Deus me elegeu dentre vós, para que os gentios ouvissem da minha boca a palavra do evangelho e cressem.' },
      { v: 8, en: 'God, who knows the heart, testified about them, giving them the Holy Spirit, just like he did to us.', pt: 'E Deus, que conhece os corações, testemunhou a favor deles, dando-lhes o Espírito Santo, assim como a nós;' },
      { v: 9, en: 'He made no distinction between us and them, cleansing their hearts by faith.', pt: 'e não fez distinção alguma entre eles e nós, purificando os seus corações pela fé.' },
      { v: 10, en: 'Now therefore why do you tempt God, that you should put a yoke on the neck of the disciples which neither our fathers nor we were able to bear?', pt: 'Agora, pois, por que tentais a Deus, pondo sobre a cerviz dos discípulos um jugo que nem nossos pais nem nós pudemos suportar?' },
      { v: 11, en: 'But we believe that we are saved through the grace of the Lord Jesus, just as they are.”', pt: 'Mas cremos que somos salvos pela graça do Senhor Jesus, do mesmo modo que eles também.' },
      { v: 12, en: 'All the multitude kept silence, and they listened to Barnabas and Paul reporting what signs and wonders God had done among the nations through them.', pt: 'Então toda a multidão se calou e escutava a Barnabé e a Paulo, que contavam quantos sinais e prodígios Deus havia feito por meio deles entre os gentios.' },
      { v: 13, en: 'After they were silent, James answered, “Brothers, listen to me.', pt: 'Depois que se calaram, Tiago, tomando a palavra, disse: Irmãos, ouvi-me:' },
      { v: 14, en: 'Simeon has reported how God first visited the nations, to take out of them a people for his name.', pt: 'Simão relatou como primeiramente Deus visitou os gentios para tomar dentre eles um povo para o seu Nome.' },
      { v: 15, en: 'This agrees with the words of the prophets. As it is written,', pt: 'E com isto concordam as palavras dos profetas; como está escrito:' },
      { v: 16, en: '‘After these things I will return. I will again build the tabernacle of David, which has fallen. I will again build its ruins. I will set it up,', pt: 'Depois disto voltarei, e reedificarei o tabernáculo de Davi, que está caído; reedificarei as suas ruínas, e tornarei a levantá-lo;' },
      { v: 17, en: 'That the rest of men may seek after the Lord; all the Gentiles who are called by my name, says the Lord, who does all these things.', pt: 'para que o resto dos homens busque ao Senhor, sim, todos os gentios, sobre os quais é invocado o meu nome,' },
      { v: 18, en: 'All of God’s works are known to him from eternity.’', pt: 'diz o Senhor que faz estas coisas, que são conhecidas desde a antiguidade.' },
      { v: 19, en: '“Therefore my judgment is that we don’t trouble those from among the Gentiles who turn to God,', pt: 'Por isso, julgo que não se deve perturbar aqueles, dentre os gentios, que se convertem a Deus,' },
      { v: 20, en: 'but that we write to them that they abstain from the pollution of idols, from sexual immorality, from what is strangled, and from blood.', pt: 'mas escrever-lhes que se abstenham das contaminações dos ídolos, da prostituição, do que é sufocado e do sangue.' },
      { v: 21, en: 'For Moses from generations of old has in every city those who preach him, being read in the synagogues every Sabbath.”', pt: 'Porque Moisés, desde tempos antigos, tem em cada cidade homens que o preguem, e cada sábado é lido nas sinagogas.' },
      { v: 22, en: 'Then it seemed good to the apostles and the elders, with the whole assembly, to choose men out of their company, and send them to Antioch with Paul and Barnabas: Judas called Barsabbas, and Silas, chief men among the brothers.', pt: 'Então pareceu bem aos apóstolos e aos anciãos com toda a igreja escolher homens dentre eles e enviá-los a Antioquia com Paulo e Barnabé, a saber: Judas, chamado Barsabás, e Silas, homens influentes entre os irmãos.' },
      { v: 23, en: 'They wrote these things by their hand: “The apostles, the elders, and the brothers, to the brothers who are of the Gentiles in Antioch, Syria, and Cilicia: greetings.', pt: 'E por intermédio deles escreveram o seguinte: Os apóstolos e os anciãos, irmãos, aos irmãos dentre os gentios em Antioquia, na Síria e na Cicília, saúde.' },
      { v: 24, en: 'Because we have heard that some who went out from us have troubled you with words, unsettling your souls, saying, ‘You must be circumcised and keep the law,’ to whom we gave no commandment;', pt: 'Portanto ouvimos que alguns dentre nós, aos quais nada mandamos, vos têm perturbado com palavras, confundindo as vossas almas,' },
      { v: 25, en: 'it seemed good to us, having come to one accord, to choose out men and send them to you with our beloved Barnabas and Paul,', pt: 'pareceu-nos bem, tendo chegado a um acordo, escolher alguns homens e enviá-los com os nossos amados Barnabé e Paulo,' },
      { v: 26, en: 'men who have risked their lives for the name of our Lord Jesus Christ.', pt: 'homens que têm exposto as suas vidas pelo nome de nosso Senhor Jesus Cristo.' },
      { v: 27, en: 'We have sent therefore Judas and Silas, who themselves will also tell you the same things by word of mouth.', pt: 'Enviamos portanto Judas e Silas, os quais também por palavra vos anunciarão as mesmas coisas.' },
      { v: 28, en: 'For it seemed good to the Holy Spirit, and to us, to lay no greater burden on you than these necessary things:', pt: 'Porque pareceu bem ao Espírito Santo e a nós não vos impor maior encargo além destas coisas necessárias:' },
      { v: 29, en: 'that you abstain from things sacrificed to idols, from blood, from things strangled, and from sexual immorality, from which if you keep yourselves, it will be well with you. Farewell.”', pt: 'Que vos abstenhais das coisas sacrificadas aos ídolos, e do sangue, e da carne sufocada, e da prostituição; e destas coisas fareis bem de vos guardar. Bem vos vá.' },
      { v: 30, en: 'So, when they were sent off, they came to Antioch. Having gathered the multitude together, they delivered the letter.', pt: 'Então eles, tendo-se despedido, desceram a Antioquia e, havendo reunido a assembléia, entregaram a carta.' },
      { v: 31, en: 'When they had read it, they rejoiced over the encouragement.', pt: 'E, quando a leram, alegraram-se pela consolação.' },
      { v: 32, en: 'Judas and Silas, also being prophets themselves, encouraged the brothers with many words, and strengthened them.', pt: 'Depois Judas e Silas, que também eram profetas, exortaram os irmãos com muitas palavras e os fortaleceram.' },
      { v: 33, en: 'After they had spent some time there, they were sent back with greetings from the brothers to the apostles.', pt: 'E, tendo-se demorado ali por algum tempo, foram pelos irmãos despedidos em paz, de volta aos que os haviam mandado.' },
      { v: 34, en: '[Mas pareceu bem a Silas ficar ali.]', pt: '[Mas pareceu bem a Silas ficar ali.]' },
      { v: 35, en: 'But Paul and Barnabas stayed in Antioch, teaching and preaching the word of the Lord, with many others also.', pt: 'Mas Paulo e Barnabé demoraram-se em Antioquia, ensinando e pregando com muitos outros a palavra do Senhor.' },
      { v: 36, en: 'After some days Paul said to Barnabas, “Let’s return now and visit our brothers in every city in which we proclaimed the word of the Lord, to see how they are doing.”', pt: 'Decorridos alguns dias, disse Paulo a Barnabé: Tornemos a visitar os irmãos por todas as cidades em que temos anunciado a palavra do Senhor, para ver como vão.' },
      { v: 37, en: 'Barnabas planned to take John, who was called Mark, with them also.', pt: 'Ora, Barnabé queria que levassem também a João, chamado Marcos.' },
      { v: 38, en: 'But Paul didn’t think that it was a good idea to take with them someone who had withdrawn from them in Pamphylia, and didn’t go with them to do the work.', pt: 'Mas a Paulo não parecia razoável que tomassem consigo aquele que desde a Panfília se tinha apartado deles e não os tinha acompanhado no trabalho.' },
      { v: 39, en: 'Then the contention grew so sharp that they separated from each other. Barnabas took Mark with him, and sailed away to Cyprus,', pt: 'E houve entre eles tal desavença que se separaram um do outro, e Barnabé, levando consigo a Marcos, navegou para Chipre.' },
      { v: 40, en: 'but Paul chose Silas, and went out, being commended by the brothers to the grace of God.', pt: 'Mas Paulo, tendo escolhido a Silas, partiu encomendado pelos irmãos à graça do Senhor.' },
      { v: 41, en: 'He went through Syria and Cilicia, strengthening the assemblies.', pt: 'E passou pela Síria e Cilícia, fortalecendo as igrejas.' },
    ],
    16: [
      { v: 1, en: 'He came to Derbe and Lystra: and behold, a certain disciple was there, named Timothy, the son of a Jewess who believed; but his father was a Greek.', pt: 'Chegou também a Derbe e Listra. E eis que estava ali certo discípulo por nome Timóteo, filho de uma judia crente, mas de pai grego;' },
      { v: 2, en: 'The brothers who were at Lystra and Iconium gave a good testimony about him.', pt: 'do qual davam bom testemunho os irmãos em Listra e Icônio.' },
      { v: 3, en: 'Paul wanted to have him go out with him, and he took and circumcised him because of the Jews who were in those parts; for they all knew that his father was a Greek.', pt: 'Paulo quis que este fosse com ele e, tomando-o, o circuncidou por causa dos judeus que estavam naqueles lugares; porque todos sabiam que seu pai era grego.' },
      { v: 4, en: 'As they went on their way through the cities, they delivered the decrees to them to keep which had been ordained by the apostles and elders who were at Jerusalem.', pt: 'Quando iam passando pelas cidades, entregavam aos irmãos, para serem observadas, as decisões que haviam sido tomadas pelos apóstolos e anciãos em Jerusalém.' },
      { v: 5, en: 'So the assemblies were strengthened in the faith, and increased in number daily.', pt: 'Assim as igrejas eram confirmadas na fé, e dia a dia cresciam em número.' },
      { v: 6, en: 'When they had gone through the region of Phrygia and Galatia, they were forbidden by the Holy Spirit to speak the word in Asia.', pt: 'Atravessaram a região frígio-gálata, tendo sido impedidos pelo Espírito Santo de anunciar a palavra na Ásia;' },
      { v: 7, en: 'When they had come opposite Mysia, they tried to go into Bithynia, but the Spirit didn’t allow them.', pt: 'e tendo chegado diante da Mísia, tentavam ir para Bitínia, mas o Espírito de Jesus não lho permitiu.' },
      { v: 8, en: 'Passing by Mysia, they came down to Troas.', pt: 'Então, passando pela Mísia, desceram a Trôade.' },
      { v: 9, en: 'A vision appeared to Paul in the night. There was a man of Macedonia standing, begging him, and saying, “Come over into Macedonia and help us.”', pt: 'De noite apareceu a Paulo esta visão: estava ali em pé um homem da Macedônia, que lhe rogava: Passa à Macedônia e ajuda-nos.' },
      { v: 10, en: 'When he had seen the vision, immediately we sought to go out to Macedonia, concluding that the Lord had called us to preach the Good News to them.', pt: 'E quando ele teve esta visão, procuravamos logo partir para a Macedônia, concluindo que Deus nos havia chamado para lhes anunciarmos o evangelho.' },
      { v: 11, en: 'Setting sail therefore from Troas, we made a straight course to Samothrace, and the day following to Neapolis;', pt: 'Navegando, pois, de Trôade, fomos em direitura a Samotrácia, e no dia seguinte a Neápolis;' },
      { v: 12, en: 'and from there to Philippi, which is a city of Macedonia, the foremost of the district, a Roman colony. We were staying some days in this city.', pt: 'e dali para Filipos, que é a primeira cidade desse distrito da Macedônia, e colônia romana; e estivemos alguns dias nessa cidade.' },
      { v: 13, en: 'On the Sabbath day we went outside of the city by a riverside, where we supposed there was a place of prayer, and we sat down, and spoke to the women who had come together.', pt: 'No sábado saímos portas afora para a beira do rio, onde julgávamos haver um lugar de oração e, sentados, falávamos às mulheres ali reunidas.' },
      { v: 14, en: 'A certain woman named Lydia, a seller of purple, of the city of Thyatira, one who worshiped God, heard us; whose heart the Lord opened to listen to the things which were spoken by Paul.', pt: 'E certa mulher chamada Lídia, vendedora de púrpura, da cidade de Tiatira, e que temia a Deus, nos escutava e o Senhor lhe abriu o coração para atender às coisas que Paulo dizia.' },
      { v: 15, en: 'When she and her household were baptized, she begged us, saying, “If you have judged me to be faithful to the Lord, come into my house, and stay.” So she persuaded us.', pt: 'Depois que foi batizada, ela e a sua casa, rogou-nos, dizendo: Se haveis julgado que eu sou fiel ao Senhor, entrai em minha casa, e ficai ali. E nos constrangeu a isso.' },
      { v: 16, en: 'As we were going to prayer, a certain girl having a spirit of divination met us, who brought her masters much gain by fortune telling.', pt: 'Ora, aconteceu que quando íamos ao lugar de oração, nos veio ao encontro uma jovem que tinha um espírito adivinhador, e que, adivinhando, dava grande lucro a seus senhores.' },
      { v: 17, en: 'Following Paul and us, she cried out, “These men are servants of the Most High God, who proclaim to us a way of salvation!”', pt: 'Ela, seguindo a Paulo e a nós, clamava, dizendo: São servos do Deus Altíssimo estes homens que vos anunciam um caminho de salvação.' },
      { v: 18, en: 'She was doing this for many days. But Paul, becoming greatly annoyed, turned and said to the spirit, “I command you in the name of Jesus Christ to come out of her!” It came out that very hour.', pt: 'E fazia isto por muitos dias. Mas Paulo, perturbado, voltou- se e disse ao espírito: Eu te ordeno em nome de Jesus Cristo que saias dela. E na mesma hora saiu.' },
      { v: 19, en: 'But when her masters saw that the hope of their gain was gone, they seized Paul and Silas, and dragged them into the marketplace before the rulers.', pt: 'Ora, vendo seus senhores que a esperança do seu lucro havia desaparecido, prenderam a Paulo e Silas, e os arrastaram para uma praça à presença dos magistrados.' },
      { v: 20, en: 'When they had brought them to the magistrates, they said, “These men, being Jews, are agitating our city,', pt: 'E, apresentando-os aos magistrados, disseram: Estes homens, sendo judeus, estão perturbando muito a nossa cidade.' },
      { v: 21, en: 'and advocate customs which it is not lawful for us to accept or to observe, being Romans.”', pt: 'e pregam costumes que não nos é lícito receber nem praticar, sendo nós romanos.' },
      { v: 22, en: 'The multitude rose up together against them, and the magistrates tore their clothes from them, and commanded them to be beaten with rods.', pt: 'A multidão levantou-se à uma contra eles, e os magistrados, rasgando-lhes os vestidos, mandaram açoitá-los com varas.' },
      { v: 23, en: 'When they had laid many stripes on them, they threw them into prison, charging the jailer to keep them safely,', pt: 'E, havendo-lhes dado muitos açoites, os lançaram na prisão, mandando ao carcereiro que os guardasse com segurança.' },
      { v: 24, en: 'who, having received such a command, threw them into the inner prison, and secured their feet in the stocks.', pt: 'Ele, tendo recebido tal ordem, os lançou na prisão interior e lhes segurou os pés no tronco.' },
      { v: 25, en: 'But about midnight Paul and Silas were praying and singing hymns to God, and the prisoners were listening to them.', pt: 'Pela meia-noite Paulo e Silas oravam e cantavam hinos a Deus, enquanto os presos os escutavam.' },
      { v: 26, en: 'Suddenly there was a great earthquake, so that the foundations of the prison were shaken; and immediately all the doors were opened, and everyone’s bonds were loosened.', pt: 'De repente houve um tão grande terremoto que foram abalados os alicerces do cárcere, e logo se abriram todas as portas e foram soltos os grilhões de todos.' },
      { v: 27, en: 'The jailer, being roused out of sleep and seeing the prison doors open, drew his sword and was about to kill himself, supposing that the prisoners had escaped.', pt: 'Ora, o carcereiro, tendo acordado e vendo abertas as portas da prisão, tirou a espada e ia suicidar-se, supondo que os presos tivessem fugido.' },
      { v: 28, en: 'But Paul cried with a loud voice, saying, “Don’t harm yourself, for we are all here!”', pt: 'Mas Paulo bradou em alta voz, dizendo: Não te faças nenhum mal, porque todos aqui estamos.' },
      { v: 29, en: 'He called for lights, sprang in, fell down trembling before Paul and Silas,', pt: 'Tendo ele pedido luz, saltou dentro e, todo trêmulo, se prostrou ante Paulo e Silas' },
      { v: 30, en: 'brought them out, and said, “Sirs, what must I do to be saved?”', pt: 'e, tirando-os para fora, disse: Senhores, que me é necessário fazer para me salvar?' },
      { v: 31, en: 'They said, “Believe in the Lord Jesus Christ, and you will be saved, you and your household.”', pt: 'Responderam eles: Crê no Senhor Jesus e serás salvo, tu e tua casa.' },
      { v: 32, en: 'They spoke the word of the Lord to him, and to all who were in his house.', pt: 'Então lhe pregaram a palavra de Deus, e a todos os que estavam em sua casa.' },
      { v: 33, en: 'He took them the same hour of the night, and washed their stripes, and was immediately baptized, he and all his household.', pt: 'Tomando-os ele consigo naquela mesma hora da noite, lavou- lhes as feridas; e logo foi batizado, ele e todos os seus.' },
      { v: 34, en: 'He brought them up into his house, and set food before them, and rejoiced greatly, with all his household, having believed in God.', pt: 'Então os fez subir para sua casa, pôs-lhes a mesa e alegrou- se muito com toda a sua casa, por ter crido em Deus.' },
      { v: 35, en: 'But when it was day, the magistrates sent the sergeants, saying, “Let those men go.”', pt: 'Quando amanheceu, os magistrados mandaram quadrilheiros a dizer: Soltai aqueles homens.' },
      { v: 36, en: 'The jailer reported these words to Paul, saying, “The magistrates have sent to let you go; now therefore come out, and go in peace.”', pt: 'E o carcereiro transmitiu a Paulo estas palavras, dizendo: Os magistrados mandaram que fosseis soltos; agora, pois, saí e ide em paz.' },
      { v: 37, en: 'But Paul said to them, “They have beaten us publicly, without a trial, men who are Romans, and have cast us into prison! Do they now release us secretly? No, most certainly, but let them come themselves and bring us out!”', pt: 'Mas Paulo respondeu-lhes: Açoitaram-nos publicamente sem sermos condenados, sendo cidadãos romanos, e nos lançaram na prisão, e agora encobertamente nos lançam fora? De modo nenhum será assim; mas venham eles mesmos e nos tirem.' },
      { v: 38, en: 'The sergeants reported these words to the magistrates, and they were afraid when they heard that they were Romans,', pt: 'E os quadrilheiros foram dizer aos magistrados estas palavras, e estes temeram quando ouviram que eles eram romanos;' },
      { v: 39, en: 'and they came and begged them. When they had brought them out, they asked them to depart from the city.', pt: 'vieram, pediram-lhes desculpas e, tirando-os para fora, rogavam que se retirassem da cidade.' },
      { v: 40, en: 'They went out of the prison, and entered into Lydia’s house. When they had seen the brothers, they encouraged them, and departed.', pt: 'Então eles saíram da prisão, entraram em casa de Lídia, e, vendo os irmãos, os confortaram, e partiram.' },
    ],
    17: [
      { v: 1, en: 'Now when they had passed through Amphipolis and Apollonia, they came to Thessalonica, where there was a Jewish synagogue.', pt: 'Tendo passado por Anfípolis e Apolônia, chegaram a Tessalônica, onde havia uma sinagoga dos judeus.' },
      { v: 2, en: 'Paul, as was his custom, went in to them, and for three Sabbath days reasoned with them from the Scriptures,', pt: 'Ora, Paulo, segundo o seu costume, foi ter com eles; e por três sábados discutiu com eles as Escrituras,' },
      { v: 3, en: 'explaining and demonstrating that the Christ had to suffer and rise again from the dead, and saying, “This Jesus, whom I proclaim to you, is the Christ.”', pt: 'expondo e demonstrando que era necessário que o Cristo padecesse e ressuscitasse dentre os mortos; este Jesus que eu vos anuncio, dizia ele, é o Cristo.' },
      { v: 4, en: 'Some of them were persuaded, and joined Paul and Silas, of the devout Greeks a great multitude, and not a few of the chief women.', pt: 'E alguns deles ficaram persuadidos e aderiram a Paulo e Silas, bem como grande multidão de gregos devotos e não poucas mulheres de posição.' },
      { v: 5, en: 'But the unpersuaded Jews took along some wicked men from the marketplace, and gathering a crowd, set the city in an uproar. Assaulting the house of Jason, they sought to bring them out to the people.', pt: 'Mas os judeus, movidos de inveja, tomando consigo alguns homens maus dentre os vadios e ajuntando o povo, alvoroçavam a cidade e, assaltando a casa de Jáson, os procuravam para entregá-los ao povo.' },
      { v: 6, en: 'When they didn’t find them, they dragged Jason and certain brothers before the rulers of the city, crying, “These who have turned the world upside down have come here also,', pt: 'Porém, não os achando, arrastaram Jáson e alguns irmãos à presença dos magistrados da cidade, clamando: Estes que têm transtornado o mundo chegaram também aqui,' },
      { v: 7, en: 'whom Jason has received. These all act contrary to the decrees of Caesar, saying that there is another king, Jesus!”', pt: 'os quais Jáson acolheu; e todos eles procedem contra os decretos de César, dizendo haver outro rei, que é Jesus.' },
      { v: 8, en: 'The multitude and the rulers of the city were troubled when they heard these things.', pt: 'Assim alvoroçaram a multidão e os magistrados da cidade, que ouviram estas coisas.' },
      { v: 9, en: 'When they had taken security from Jason and the rest, they let them go.', pt: 'Tendo, porém, recebido fiança de Jáson e dos demais, soltaram-nos.' },
      { v: 10, en: 'The brothers immediately sent Paul and Silas away by night to Beroea. When they arrived, they went into the Jewish synagogue.', pt: 'E logo, de noite, os irmãos enviaram Paulo e Silas para Beréia; tendo eles ali chegado, foram à sinagoga dos judeus.' },
      { v: 11, en: 'Now these were more noble than those in Thessalonica, in that they received the word with all readiness of mind, examining the Scriptures daily to see whether these things were so.', pt: 'Ora, estes eram mais nobres do que os de Tessalônica, porque receberam a palavra com toda avidez, examinando diariamente as Escrituras para ver se estas coisas eram assim.' },
      { v: 12, en: 'Many of them therefore believed; also of the prominent Greek women, and not a few men.', pt: 'De sorte que muitos deles creram, bem como bom número de mulheres gregas de alta posição e não poucos homens.' },
      { v: 13, en: 'But when the Jews of Thessalonica had knowledge that the word of God was proclaimed by Paul at Beroea also, they came there likewise, agitating the multitudes.', pt: 'Mas, logo que os judeus de Tessalônica souberam que também em Beréia era anunciada por Paulo a palavra de Deus, foram lá agitar e sublevar as multidões.' },
      { v: 14, en: 'Then the brothers immediately sent out Paul to go as far as to the sea, and Silas and Timothy still stayed there.', pt: 'Imediatamente os irmãos fizeram sair a Paulo para que fosse até o mar; mas Silas e Timóteo ficaram ali.' },
      { v: 15, en: 'But those who escorted Paul brought him as far as Athens. Receiving a commandment to Silas and Timothy that they should come to him very quickly, they departed.', pt: 'E os que acompanhavam a Paulo levaram-no até Atenas e, tendo recebido ordem para Silas e Timóteo a fim de que estes fossem ter com ele o mais depressa possível, partiram.' },
      { v: 16, en: 'Now while Paul waited for them at Athens, his spirit was provoked within him as he saw the city full of idols.', pt: 'Enquanto Paulo os esperava em Atenas, revoltava-se nele o seu espírito, vendo a cidade cheia de ídolos.' },
      { v: 17, en: 'So he reasoned in the synagogue with the Jews and the devout persons, and in the marketplace every day with those who met him.', pt: 'Argumentava, portanto, na sinagoga com os judeus e os gregos devotos, e na praça todos os dias com os que se encontravam ali.' },
      { v: 18, en: 'Some of the Epicurean and Stoic philosophers also were conversing with him. Some said, “What does this babbler want to say?” Others said, “He seems to be advocating foreign deities,” because he preached Jesus and the resurrection.', pt: 'Ora, alguns filósofos epicureus e estóicos disputavam com ele. Uns diziam: Que quer dizer este paroleiro? E outros: Parece ser pregador de deuses estranhos; pois anunciava a boa nova de Jesus e a ressurreição.' },
      { v: 19, en: 'They took hold of him, and brought him to the Areopagus, saying, “May we know what this new teaching is, which is spoken by you?', pt: 'E, tomando-o, o levaram ao Areópago, dizendo: Poderemos nós saber que nova doutrina é essa de que falas?' },
      { v: 20, en: 'For you bring certain strange things to our ears. We want to know therefore what these things mean.”', pt: 'Pois tu nos trazes aos ouvidos coisas estranhas; portanto queremos saber o que vem a ser isto.' },
      { v: 21, en: 'Now all the Athenians and the strangers living there spent their time in nothing else, but either to tell or to hear some new thing.', pt: 'Ora, todos os atenienses, como também os estrangeiros que ali residiam, de nenhuma outra coisa se ocupavam senão de contar ou de ouvir a última novidade.' },
      { v: 22, en: 'Paul stood in the middle of the Areopagus, and said, “You men of Athens, I perceive that you are very religious in all things.', pt: 'Então Paulo, estando de pé no meio do Areópago, disse: Varões atenienses, em tudo vejo que sois excepcionalmente religiosos;' },
      { v: 23, en: 'For as I passed along, and observed the objects of your worship, I found also an altar with this inscription: ‘TO AN UNKNOWN GOD.’ What therefore you worship in ignorance, this I announce to you.', pt: 'Porque, passando eu e observando os objetos do vosso culto, encontrei também um altar em que estava escrito: AO DEUS DESCONHECIDO. Esse, pois, que vós honrais sem o conhecer, é o que vos anuncio.' },
      { v: 24, en: 'The God who made the world and all things in it, he, being Lord of heaven and earth, doesn’t dwell in temples made with hands,', pt: 'O Deus que fez o mundo e tudo o que nele há, sendo ele Senhor do céu e da terra, não habita em templos feitos por mãos de homens;' },
      { v: 25, en: 'neither is he served by men’s hands, as though he needed anything, seeing he himself gives to all life and breath, and all things.', pt: 'nem tampouco é servido por mãos humanas, como se necessitasse de alguma coisa; pois ele mesmo é quem dá a todos a vida, a respiração e todas as coisas;' },
      { v: 26, en: 'He made from one blood every nation of men to dwell on all the surface of the earth, having determined appointed seasons, and the boundaries of their dwellings,', pt: 'e de um só fez todas as raças dos homens, para habitarem sobre toda a face da terra, determinando-lhes os tempos já dantes ordenados e os limites da sua habitação;' },
      { v: 27, en: 'that they should seek the Lord, if perhaps they might reach out for him and find him, though he is not far from each one of us.', pt: 'para que buscassem a Deus, se porventura, tateando, o pudessem achar, o qual, todavia, não está longe de cada um de nós;' },
      { v: 28, en: '‘For in him we live, and move, and have our being.’ As some of your own poets have said, ‘For we are also his offspring.’', pt: 'porque nele vivemos, e nos movemos, e existimos; como também alguns dos vossos poetas disseram: Pois dele também somos geração.' },
      { v: 29, en: 'Being then the offspring of God, we ought not to think that the Divine Nature is like gold, or silver, or stone, engraved by art and design of man.', pt: 'Sendo nós, pois, geração de Deus, não devemos pensar que a divindade seja semelhante ao ouro, ou à prata, ou à pedra esculpida pela arte e imaginação do homem.' },
      { v: 30, en: 'The times of ignorance therefore God overlooked. But now he commands that all people everywhere should repent,', pt: 'Mas Deus, não levando em conta os tempos da ignorância, manda agora que todos os homens em todo lugar se arrependam;' },
      { v: 31, en: 'because he has appointed a day in which he will judge the world in righteousness by the man whom he has ordained; of which he has given assurance to all men, in that he has raised him from the dead.”', pt: 'porquanto determinou um dia em que com justiça há de julgar o mundo, por meio do varão que para isso ordenou; e disso tem dado certeza a todos, ressuscitando-o dentre os mortos.' },
      { v: 32, en: 'Now when they heard of the resurrection of the dead, some mocked; but others said, “We want to hear you again concerning this.”', pt: 'Mas quando ouviram falar em ressurreição de mortos, uns escarneciam, e outros diziam: Acerca disso te ouviremos ainda outra vez.' },
      { v: 33, en: 'Thus Paul went out from among them.', pt: 'Assim Paulo saiu do meio deles.' },
      { v: 34, en: 'But certain men joined with him, and believed, among whom also was Dionysius the Areopagite, and a woman named Damaris, and others with them.', pt: 'Todavia, alguns homens aderiram a ele, e creram, entre os quais Dionísio, o areopagita, e uma mulher por nome Dâmaris, e com eles outros.' },
    ],
    18: [
      { v: 1, en: 'After these things Paul departed from Athens, and came to Corinth.', pt: 'Depois disto Paulo partiu para Atenas e chegou a Corinto.' },
      { v: 2, en: 'He found a certain Jew named Aquila, a man of Pontus by race, who had recently come from Italy, with his wife Priscilla, because Claudius had commanded all the Jews to depart from Rome. He came to them,', pt: 'E encontrando um judeu por nome Áqüila, natural do Ponto, que pouco antes viera da Itália, e Priscila, sua mulher (porque Cláudio tinha decretado que todos os judeus saíssem de Roma), foi ter com eles,' },
      { v: 3, en: 'and because he practiced the same trade, he lived with them and worked, for by trade they were tent makers.', pt: 'e, por ser do mesmo ofício, com eles morava, e juntos trabalhavam; pois eram, por ofício, fabricantes de tendas.' },
      { v: 4, en: 'He reasoned in the synagogue every Sabbath, and persuaded Jews and Greeks.', pt: 'Ele discutia todos os sábados na sinagoga, e persuadia a judeus e gregos.' },
      { v: 5, en: 'But when Silas and Timothy came down from Macedonia, Paul was compelled by the Spirit, testifying to the Jews that Jesus was the Christ.', pt: 'Quando Silas e Timóteo desceram da Macedônia, Paulo dedicou- se inteiramente à palavra, testificando aos judeus que Jesus era o Cristo.' },
      { v: 6, en: 'When they opposed him and blasphemed, he shook out his clothing and said to them, “Your blood be on your own heads! I am clean. From now on, I will go to the Gentiles!”', pt: 'Como estes, porém, se opusessem e proferissem injúrias, sacudiu ele as vestes e disse-lhes: O vosso sangue seja sobre a vossa cabeça; eu estou limpo, e desde agora vou para os gentios.' },
      { v: 7, en: 'He departed there, and went into the house of a certain man named Justus, one who worshiped God, whose house was next door to the synagogue.', pt: 'E saindo dali, entrou em casa de um homem temente a Deus, chamado Tito Justo, cuja casa ficava junto da sinagoga.' },
      { v: 8, en: 'Crispus, the ruler of the synagogue, believed in the Lord with all his house. Many of the Corinthians, when they heard, believed and were baptized.', pt: 'Crispo, chefe da sinagoga, creu no Senhor com toda a sua casa; e muitos dos coríntios, ouvindo, criam e eram batizados.' },
      { v: 9, en: 'The Lord said to Paul in the night by a vision, “Don’t be afraid, but speak and don’t be silent;', pt: 'E de noite disse o Senhor em visão a Paulo: Não temas, mas fala e não te cales;' },
      { v: 10, en: 'for I am with you, and no one will attack you to harm you, for I have many people in this city.”', pt: 'porque eu estou contigo e ninguém te acometerá para te fazer mal, pois tenho muito povo nesta cidade.' },
      { v: 11, en: 'He lived there a year and six months, teaching the word of God among them.', pt: 'E ficou ali um ano e seis meses, ensinando entre eles a palavra de Deus.' },
      { v: 12, en: 'But when Gallio was proconsul of Achaia, the Jews with one accord rose up against Paul and brought him before the judgment seat,', pt: 'Sendo Gálio procônsul da Acaia, levantaram-se os judeus de comum acordo contra Paulo, e o levaram ao tribunal,' },
      { v: 13, en: 'saying, “This man persuades men to worship God contrary to the law.”', pt: 'dizendo: Este persuade os homens a render culto a Deus de um modo contrário à lei.' },
      { v: 14, en: 'But when Paul was about to open his mouth, Gallio said to the Jews, “If indeed it were a matter of wrong or of wicked crime, you Jews, it would be reasonable that I should bear with you;', pt: 'E, quando Paulo estava para abrir a boca, disse Gálio aos judeus: Se de fato houvesse, ó judeus, algum agravo ou crime perverso, com razão eu vos sofreria;' },
      { v: 15, en: 'but if they are questions about words and names and your own law, look to it yourselves. For I don’t want to be a judge of these matters.”', pt: 'mas, se são questões de palavras, de nomes, e da vossa lei, disso cuidai vós mesmos; porque eu não quero ser juiz destas coisas.' },
      { v: 16, en: 'So he drove them from the judgment seat.', pt: 'E expulsou-os do tribunal.' },
      { v: 17, en: 'Then all the Greeks laid hold on Sosthenes, the ruler of the synagogue, and beat him before the judgment seat. Gallio didn’t care about any of these things.', pt: 'Então todos agarraram Sóstenes, chefe da sinagoga, e o espancavam diante do tribunal; e Gálio não se importava com nenhuma dessas coisas.' },
      { v: 18, en: 'Paul, having stayed after this many more days, took his leave of the brothers, and sailed from there for Syria, together with Priscilla and Aquila. He shaved his head in Cenchreae, for he had a vow.', pt: 'Paulo, tendo ficado ali ainda muitos dias, despediu-se dos irmãos e navegou para a Síria, e com ele Priscila e Áqüila, havendo rapado a cabeça em Cencréia, porque tinha voto.' },
      { v: 19, en: 'He came to Ephesus, and he left them there; but he himself entered into the synagogue, and reasoned with the Jews.', pt: 'E eles chegaram a Éfeso, onde Paulo os deixou; e tendo entrado na sinagoga, discutia com os judeus.' },
      { v: 20, en: 'When they asked him to stay with them a longer time, he declined;', pt: 'Estes rogavam que ficasse por mais algum tempo, mas ele não anuiu,' },
      { v: 21, en: 'but taking his leave of them, he said, “I must by all means keep this coming feast in Jerusalem, but I will return again to you if God wills.” Then he set sail from Ephesus.', pt: 'antes se despediu deles, dizendo: Se Deus quiser, de novo voltarei a vós; e navegou de Éfeso.' },
      { v: 22, en: 'When he had landed at Caesarea, he went up and greeted the assembly, and went down to Antioch.', pt: 'Tendo chegado a Cesaréia, subiu a Jerusalém e saudou a igreja, e desceu a Antioquia.' },
      { v: 23, en: 'Having spent some time there, he departed, and went through the region of Galatia, and Phrygia, in order, establishing all the disciples.', pt: 'E, tendo demorado ali algum tempo, partiu, passando sucessivamente pela região da Galácia e da Frígia, fortalecendo a todos os discípulos.' },
      { v: 24, en: 'Now a certain Jew named Apollos, an Alexandrian by race, an eloquent man, came to Ephesus. He was mighty in the Scriptures.', pt: 'Ora, chegou a Éfeso certo judeu chamado Apolo, natural de Alexandria, homem eloqüente e poderoso nas Escrituras.' },
      { v: 25, en: 'This man had been instructed in the way of the Lord; and being fervent in spirit, he spoke and taught accurately the things concerning Jesus, although he knew only the baptism of John.', pt: 'Era ele instruído no caminho do Senhor e, sendo fervoroso de espírito, falava e ensinava com precisão as coisas concernentes a Jesus, conhecendo entretanto somente o batismo de João.' },
      { v: 26, en: 'He began to speak boldly in the synagogue. But when Priscilla and Aquila heard him, they took him aside, and explained to him the way of God more accurately.', pt: 'Ele começou a falar ousadamente na sinagoga: mas quando Priscila e Áqüila o ouviram, levaram-no consigo e lhe expuseram com mais precisão o caminho de Deus.' },
      { v: 27, en: 'When he had determined to pass over into Achaia, the brothers encouraged him, and wrote to the disciples to receive him. When he had come, he greatly helped those who had believed through grace;', pt: 'Querendo ele passar à Acáia, os irmãos o animaram e escreveram aos discípulos que o recebessem; e tendo ele chegado, auxiliou muito aos que pela graça haviam crido.' },
      { v: 28, en: 'for he powerfully refuted the Jews, publicly showing by the Scriptures that Jesus was the Christ.', pt: 'Pois com grande poder refutava publicamente os judeus, demonstrando pelas escrituras que Jesus era o Cristo.' },
    ],
    19: [
      { v: 1, en: 'While Apollos was at Corinth, Paul, having passed through the upper country, came to Ephesus, and found certain disciples.', pt: 'E sucedeu que, enquanto Apolo estava em Corinto, Paulo tendo atravessado as regiões mais altas, chegou a Éfeso e, achando ali alguns discípulos,' },
      { v: 2, en: 'He said to them, “Did you receive the Holy Spirit when you believed?” They said to him, “No, we haven’t even heard that there is a Holy Spirit.”', pt: 'perguntou-lhes: Recebestes vós o Espírito Santo quando crestes? Responderam-lhe eles: Não, nem sequer ouvimos que haja Espírito Santo.' },
      { v: 3, en: 'He said, “Into what then were you baptized?” They said, “Into John’s baptism.”', pt: 'Tornou-lhes ele: Em que fostes batizados então? E eles disseram: No batismo de João.' },
      { v: 4, en: 'Paul said, “John indeed baptized with the baptism of repentance, saying to the people that they should believe in the one who would come after him, that is, in Jesus.”', pt: 'Mas Paulo respondeu: João administrou o batismo do arrependimento, dizendo ao povo que cresse naquele que após ele havia de vir, isto é, em Jesus.' },
      { v: 5, en: 'When they heard this, they were baptized in the name of the Lord Jesus.', pt: 'Quando ouviram isso, foram batizados em nome do Senhor Jesus.' },
      { v: 6, en: 'When Paul had laid his hands on them, the Holy Spirit came on them, and they spoke with other languages and prophesied.', pt: 'Havendo-lhes Paulo imposto as mãos, veio sobre eles o Espírito Santo, e falavam em línguas e profetizavam.' },
      { v: 7, en: 'They were about twelve men in all.', pt: 'E eram ao todo uns doze homens.' },
      { v: 8, en: 'He entered into the synagogue, and spoke boldly for a period of three months, reasoning and persuading about the things concerning God’s Kingdom.', pt: 'Paulo, entrando na sinagoga, falou ousadamente por espaço de três meses, discutindo e persuadindo acerca do reino de Deus.' },
      { v: 9, en: 'But when some were hardened and disobedient, speaking evil of the Way before the multitude, he departed from them, and separated the disciples, reasoning daily in the school of Tyrannus.', pt: 'Mas, como alguns deles se endurecessem e não obedecessem, falando mal do Caminho diante da multidão, apartou-se deles e separou os discípulos, discutindo diariamente na escola de Tirano.' },
      { v: 10, en: 'This continued for two years, so that all those who lived in Asia heard the word of the Lord Jesus, both Jews and Greeks.', pt: 'Durou isto por dois anos; de maneira que todos os que habitavam na Ásia, tanto judeus como gregos, ouviram a palavra do Senhor.' },
      { v: 11, en: 'God worked special miracles by the hands of Paul,', pt: 'E Deus pelas mãos de Paulo fazia milagres extraordinários,' },
      { v: 12, en: 'so that even handkerchiefs or aprons were carried away from his body to the sick, and the diseases departed from them, and the evil spirits went out.', pt: 'de sorte que lenços e aventais eram levados do seu corpo aos enfermos, e as doenças os deixavam e saíam deles os espíritos malignos.' },
      { v: 13, en: 'But some of the itinerant Jews, exorcists, took on themselves to invoke over those who had the evil spirits the name of the Lord Jesus, saying, “We adjure you by Jesus whom Paul preaches.”', pt: 'Ora, também alguns dos exorcistas judeus, ambulantes, tentavam invocar o nome de Jesus sobre os que tinham espíritos malignos, dizendo: Esconjuro-vos por Jesus a quem Paulo prega.' },
      { v: 14, en: 'There were seven sons of one Sceva, a Jewish chief priest, who did this.', pt: 'E os que faziam isto eram sete filhos de Ceva, judeu, um dos principais sacerdotes.' },
      { v: 15, en: 'The evil spirit answered, “Jesus I know, and Paul I know, but who are you?”', pt: 'respondendo, porém, o espírito maligno, disse: A Jesus conheço, e sei quem é Paulo; mas vós, quem sois?' },
      { v: 16, en: 'The man in whom the evil spirit was leaped on them, overpowered them, and prevailed against them, so that they fled out of that house naked and wounded.', pt: 'Então o homem, no qual estava o espírito maligno, saltando sobre eles, apoderou-se de dois e prevaleceu contra eles, de modo que, nus e feridos, fugiram daquela casa.' },
      { v: 17, en: 'This became known to all, both Jews and Greeks, who lived at Ephesus. Fear fell on them all, and the name of the Lord Jesus was magnified.', pt: 'E isto tornou-se conhecido de todos os que moravam em Éfeso, tanto judeus como gregos; e veio temor sobre todos eles, e o nome do Senhor Jesus era engrandecido.' },
      { v: 18, en: 'Many also of those who had believed came, confessing, and declaring their deeds.', pt: 'E muitos dos que haviam crido vinham, confessando e revelando os seus feitos.' },
      { v: 19, en: 'Many of those who practiced magical arts brought their books together and burned them in the sight of all. They counted their price, and found it to be fifty thousand pieces of silver.', pt: 'Muitos também dos que tinham praticado artes mágicas ajuntaram os seus livros e os queimaram na presença de todos; e, calculando o valor deles, acharam que montava a cinqüenta mil moedas de prata.' },
      { v: 20, en: 'So the word of the Lord was growing and becoming mighty.', pt: 'Assim a palavra do Senhor crescia poderosamente e prevalecia.' },
      { v: 21, en: 'Now after these things had ended, Paul determined in the spirit, when he had passed through Macedonia and Achaia, to go to Jerusalem, saying, “After I have been there, I must also see Rome.”', pt: 'Cumpridas estas coisas, Paulo propôs, em seu espírito, ir a Jerusalém, passando pela Macedônia e pela Acaia, porque dizia: Depois de haver estado ali, é-me necessário ver também Roma.' },
      { v: 22, en: 'Having sent into Macedonia two of those who served him, Timothy and Erastus, he himself stayed in Asia for a while.', pt: 'E, enviando à Macedônia dois dos que o auxiliavam, Timóteo e Erasto, ficou ele por algum tempo na Ásia.' },
      { v: 23, en: 'About that time there arose no small stir concerning the Way.', pt: 'Por esse tempo houve um não pequeno alvoroço acerca do Caminho.' },
      { v: 24, en: 'For a certain man named Demetrius, a silversmith, who made silver shrines of Artemis, brought no little business to the craftsmen,', pt: 'Porque certo ourives, por nome Demétrio, que fazia da prata miniaturas do templo de Diana, proporcionava não pequeno negócio aos artífices,' },
      { v: 25, en: 'whom he gathered together, with the workmen of like occupation, and said, “Sirs, you know that by this business we have our wealth.', pt: 'os quais ele ajuntou, bem como os oficiais de obras semelhantes, e disse: Senhores, vós bem sabeis que desta indústria nos vem a prosperidade,' },
      { v: 26, en: 'You see and hear, that not at Ephesus alone, but almost throughout all Asia, this Paul has persuaded and turned away many people, saying that they are no gods, that are made with hands.', pt: 'e estais vendo e ouvindo que não é só em Éfeso, mas em quase toda a Ásia, este Paulo tem persuadido e desviado muita gente, dizendo não serem deuses os que são feitos por mãos humanas.' },
      { v: 27, en: 'Not only is there danger that this our trade come into disrepute, but also that the temple of the great goddess Artemis will be counted as nothing, and her majesty destroyed, whom all Asia and the world worships.”', pt: 'E não somente há perigo de que esta nossa profissão caia em descrédito, mas também que o templo da grande deusa Diana seja estimado em nada, vindo mesmo a ser destituída da sua majestade aquela a quem toda a Ásia e o mundo adoram.' },
      { v: 28, en: 'When they heard this they were filled with anger, and cried out, saying, “Great is Artemis of the Ephesians!”', pt: 'Ao ouvirem isso, encheram-se de ira, e clamavam, dizendo: Grande é a Diana dos efésios!' },
      { v: 29, en: 'The whole city was filled with confusion, and they rushed with one accord into the theater, having seized Gaius and Aristarchus, men of Macedonia, Paul’s companions in travel.', pt: 'A cidade encheu-se de confusão, e todos à uma correram ao teatro, arrebatando a Gaio e a Aristarco, macedônios, companheiros de Paulo na viagem.' },
      { v: 30, en: 'When Paul wanted to enter in to the people, the disciples didn’t allow him.', pt: 'Querendo Paulo apresentar-se ao povo, os discípulos não lho permitiram.' },
      { v: 31, en: 'Certain also of the Asiarchs, being his friends, sent to him and begged him not to venture into the theater.', pt: 'Também alguns dos asiarcas, sendo amigos dele, mandaram rogar-lhe que não se arriscasse a ir ao teatro.' },
      { v: 32, en: 'Some therefore cried one thing, and some another, for the assembly was in confusion. Most of them didn’t know why they had come together.', pt: 'Uns, pois, gritavam de um modo, outros de outro; porque a assembléia estava em confusão, e a maior parte deles nem sabia por que causa se tinham ajuntado.' },
      { v: 33, en: 'They brought Alexander out of the multitude, the Jews putting him forward. Alexander beckoned with his hand, and would have made a defense to the people.', pt: 'Então tiraram dentre a turba a Alexandre, a quem os judeus impeliram para a frente; e Alexandre, acenando com a mão, queria apresentar uma defesa ao povo.' },
      { v: 34, en: 'But when they perceived that he was a Jew, all with one voice for a time of about two hours cried out, “Great is Artemis of the Ephesians!”', pt: 'Mas quando perceberam que ele era judeu, todos a uma voz gritaram por quase duas horas: Grande é a Diana dos efésios!' },
      { v: 35, en: 'When the town clerk had quieted the multitude, he said, “You men of Ephesus, what man is there who doesn’t know that the city of the Ephesians is temple keeper of the great goddess Artemis, and of the image which fell down from Zeus?', pt: 'Havendo o escrivão conseguido apaziguar a turba, disse: Varões efésios, que homem há que não saiba que a cidade dos efésios é a guardadora do templo da grande deusa Diana, e da imagem que caiu de Júpiter?' },
      { v: 36, en: 'Seeing then that these things can’t be denied, you ought to be quiet, and to do nothing rash.', pt: 'Ora, visto que estas coisas não podem ser contestadas, convém que vos aquieteis e nada façais precipitadamente.' },
      { v: 37, en: 'For you have brought these men here, who are neither robbers of temples nor blasphemers of your goddess.', pt: 'Porque estes homens que aqui trouxestes, nem são sacrílegos nem blasfemadores da nossa deusa.' },
      { v: 38, en: 'If therefore Demetrius and the craftsmen who are with him have a matter against anyone, the courts are open, and there are proconsuls. Let them press charges against one another.', pt: 'Todavia, se Demétrio e os artífices que estão com ele têm alguma queixa contra alguém, os tribunais estão abertos e há procônsules: que se acusem uns aos outros.' },
      { v: 39, en: 'But if you seek anything about other matters, it will be settled in the regular assembly.', pt: 'E se demandais alguma outra coisa, averiguar-se-á em legítima assembléia.' },
      { v: 40, en: 'For indeed we are in danger of being accused concerning today’s riot, there being no cause. Concerning it, we wouldn’t be able to give an account of this commotion.”', pt: 'Pois até corremos perigo de sermos acusados de sedição pelos acontecimentos de hoje, não havendo motivo algum com que possamos justificar este ajuntamento.' },
      { v: 41, en: 'When he had thus spoken, he dismissed the assembly.', pt: 'E, tendo dito isto, despediu a assembléia.' },
    ],
    20: [
      { v: 1, en: 'After the uproar had ceased, Paul sent for the disciples, took leave of them, and departed to go into Macedonia.', pt: 'Depois que cessou o alvoroço, Paulo mandou chamar os discípulos e, tendo-os exortado, despediu-se e partiu para a Macedônia.' },
      { v: 2, en: 'When he had gone through those parts, and had encouraged them with many words, he came into Greece.', pt: 'E, havendo andado por aquelas regiões, exortando os discípulos com muitas palavras, veio à Grécia.' },
      { v: 3, en: 'When he had spent three months there, and a plot was made against him by Jews as he was about to set sail for Syria, he determined to return through Macedonia.', pt: 'Depois de passar ali três meses, visto terem os judeus armado uma cilada contra ele quando ia embarcar para a Síria, determinou voltar pela Macedônia.' },
      { v: 4, en: 'These accompanied him as far as Asia: Sopater of Beroea; Aristarchus and Secundus of the Thessalonians; Gaius of Derbe; Timothy; and Tychicus and Trophimus of Asia.', pt: 'Acompanhou-o Sópater de Beréia, filho de Pirro; bem como dos de Tessalônica, Aristarco e Segundo; Gaio de Derbe e Timóteo; e dos da Ásia, Tíquico e Trófimo.' },
      { v: 5, en: 'But these had gone ahead, and were waiting for us at Troas.', pt: 'Estes porém, foram adiante e nos esperavam em Trôade.' },
      { v: 6, en: 'We sailed away from Philippi after the days of Unleavened Bread, and came to them at Troas in five days, where we stayed seven days.', pt: 'E nós, depois dos dias dos pães ázimos, navegamos de Filipos, e em cinco dias fomos ter com eles em Trôade, onde nos detivemos sete dias.' },
      { v: 7, en: 'On the first day of the week, when the disciples were gathered together to break bread, Paul talked with them, intending to depart on the next day, and continued his speech until midnight.', pt: 'No primeiro dia da semana, tendo-nos reunido a fim de partir o pão, Paulo, que havia de sair no dia seguinte, falava com eles, e prolongou o seu discurso até a meia-noite.' },
      { v: 8, en: 'There were many lights in the upper room where we were gathered together.', pt: 'Ora, havia muitas luzes no cenáculo onde estávamos reunidos.' },
      { v: 9, en: 'A certain young man named Eutychus sat in the window, weighed down with deep sleep. As Paul spoke still longer, being weighed down by his sleep, he fell down from the third floor, and was taken up dead.', pt: 'E certo jovem, por nome åutico, que estava sentado na janela, tomado de um sono profundo enquanto Paulo prolongava ainda mais o seu sermão, vencido pelo sono caiu do terceiro andar abaixo, e foi levantado morto.' },
      { v: 10, en: 'Paul went down, and fell upon him, and embracing him said, “Don’t be troubled, for his life is in him.”', pt: 'Tendo Paulo descido, debruçou-se sobre ele e, abraçando-o, disse: Não vos perturbeis, pois a sua alma está nele.' },
      { v: 11, en: 'When he had gone up, and had broken bread, and eaten, and had talked with them a long while, even until break of day, he departed.', pt: 'Então subiu, e tendo partido o pão e comido, ainda lhes falou largamente até o romper do dia; e assim partiu.' },
      { v: 12, en: 'They brought the boy in alive, and were greatly comforted.', pt: 'E levaram vivo o jovem e ficaram muito consolados.' },
      { v: 13, en: 'But we, going ahead to the ship, set sail for Assos, intending to take Paul aboard there; for he had so arranged, intending himself to go by land.', pt: 'Nós, porém, tomando a dianteira e embarcando, navegamos para Assôs, onde devíamos receber a Paulo, porque ele, havendo de ir por terra, assim o ordenara.' },
      { v: 14, en: 'When he met us at Assos, we took him aboard, and came to Mitylene.', pt: 'E, logo que nos alcançou em Assôs, recebemo-lo a bordo e fomos a Mitilene;' },
      { v: 15, en: 'Sailing from there, we came the following day opposite Chios. The next day we touched at Samos and stayed at Trogyllium, and the day after we came to Miletus.', pt: 'e navegando dali, chegamos no dia imediato defronte de Quios, no outro aportamos a Samos e [e tendo-nos demorado em Trogílio, chegamos,] no dia seguinte a Mileto.' },
      { v: 16, en: 'For Paul had determined to sail past Ephesus, that he might not have to spend time in Asia; for he was hastening, if it were possible for him, to be in Jerusalem on the day of Pentecost.', pt: 'Porque Paulo havia determinado passar ao largo de Éfeso, para não se demorar na Ásia; pois se apressava para estar em Jerusalém no dia de Pentecostes, se lhe fosse possível.' },
      { v: 17, en: 'From Miletus he sent to Ephesus, and called to himself the elders of the assembly.', pt: 'De Mileto mandou a Éfeso chamar os anciãos da igreja.' },
      { v: 18, en: 'When they had come to him, he said to them, “You yourselves know, from the first day that I set foot in Asia, how I was with you all the time,', pt: 'E, tendo eles chegado, disse-lhes: Vós bem sabeis de que modo me tenho portado entre vós sempre, desde o primeiro dia em que entrei na Ásia,' },
      { v: 19, en: 'serving the Lord with all humility, with many tears, and with trials which happened to me by the plots of the Jews;', pt: 'servindo ao Senhor com toda a humildade, e com lágrimas e provações que pelas ciladas dos judeus me sobrevieram;' },
      { v: 20, en: 'how I didn’t shrink from declaring to you anything that was profitable, teaching you publicly and from house to house,', pt: 'como não me esquivei de vos anunciar coisa alguma que útil seja, ensinando-vos publicamente e de casa em casa,' },
      { v: 21, en: 'testifying both to Jews and to Greeks repentance toward God, and faith toward our Lord Jesus.', pt: 'testificando, tanto a judeus como a gregos, o arrependimento para com Deus e a fé em nosso Senhor Jesus.' },
      { v: 22, en: 'Now, behold, I go bound by the Spirit to Jerusalem, not knowing what will happen to me there;', pt: 'Agora, eis que eu, constrangido no meu espírito, vou a Jerusalém, não sabendo o que ali acontecerá,' },
      { v: 23, en: 'except that the Holy Spirit testifies in every city, saying that bonds and afflictions wait for me.', pt: 'senão o que o Espírito Santo me testifica, de cidade em cidade, dizendo que me esperam prisões e tribulações.' },
      { v: 24, en: 'But these things don’t count; nor do I hold my life dear to myself, so that I may finish my race with joy, and the ministry which I received from the Lord Jesus, to fully testify to the Good News of the grace of God.', pt: 'mas em nada tenho a minha vida como preciosa para mim, contando que complete a minha carreira e o ministério que recebi do Senhor Jesus, para dar testemunho do evangelho da graça de Deus.' },
      { v: 25, en: '“Now, behold, I know that you all, among whom I went about preaching God’s Kingdom, will see my face no more.', pt: 'E eis agora, sei que nenhum de vós, por entre os quais passei pregando o reino de Deus, jamais tornará a ver o meu rosto.' },
      { v: 26, en: 'Therefore I testify to you today that I am clean from the blood of all men,', pt: 'Portanto, no dia de hoje, vos protesto que estou limpo do sangue de todos.' },
      { v: 27, en: 'for I didn’t shrink from declaring to you the whole counsel of God.', pt: 'Porque não me esquivei de vos anunciar todo o conselho de Deus.' },
      { v: 28, en: 'Take heed, therefore, to yourselves, and to all the flock, in which the Holy Spirit has made you overseers, to shepherd the assembly of the Lord and God which he purchased with his own blood.', pt: 'Cuidai pois de vós mesmos e de todo o rebanho sobre o qual o Espírito Santo vos constituiu bispos, para apascentardes a igreja de Deus, que ele adquiriu com seu próprio sangue.' },
      { v: 29, en: 'For I know that after my departure, vicious wolves will enter in among you, not sparing the flock.', pt: 'Eu sei que depois da minha partida entrarão no meio de vós lobos cruéis que não pouparão rebanho,' },
      { v: 30, en: 'Men will arise from among your own selves, speaking perverse things, to draw away the disciples after them.', pt: 'e que dentre vós mesmos se levantarão homens, falando coisas perversas para atrair os discípulos após si.' },
      { v: 31, en: 'Therefore watch, remembering that for a period of three years I didn’t cease to admonish everyone night and day with tears.', pt: 'Portanto vigiai, lembrando-vos de que por três anos não cessei noite e dia de admoestar com lágrimas a cada um de vós.' },
      { v: 32, en: 'Now, brothers, I entrust you to God, and to the word of his grace, which is able to build up, and to give you the inheritance among all those who are sanctified.', pt: 'Agora pois, vos encomendo a Deus e à palavra da sua graça, àquele que é poderoso para vos edificar e dar herança entre todos os que são santificados.' },
      { v: 33, en: 'I coveted no one’s silver, or gold, or clothing.', pt: 'De ninguém cobicei prata, nem ouro, nem vestes.' },
      { v: 34, en: 'You yourselves know that these hands served my necessities, and those who were with me.', pt: 'Vós mesmos sabeis que estas mãos proveram as minhas necessidades e as dos que estavam comigo.' },
      { v: 35, en: 'In all things I gave you an example, that so laboring you ought to help the weak, and to remember the words of the Lord Jesus, that he himself said, ‘It is more blessed to give than to receive.’ ”', pt: 'Em tudo vos dei o exemplo de que assim trabalhando, é necessário socorrer os enfermos, recordando as palavras do Senhor Jesus, porquanto ele mesmo disse: Coisa mais bem-aventurada é dar do que receber.' },
      { v: 36, en: 'When he had spoken these things, he knelt down and prayed with them all.', pt: 'Havendo dito isto, pôs-se de joelhos, e orou com todos eles.' },
      { v: 37, en: 'They all wept a lot, and fell on Paul’s neck and kissed him,', pt: 'E levantou-se um grande pranto entre todos, e lançando-se ao pescoço de Paulo, beijavam-no.' },
      { v: 38, en: 'sorrowing most of all because of the word which he had spoken, that they should see his face no more. And they accompanied him to the ship.', pt: 'entristecendo-se principalmente pela palavra que dissera, que não veriam mais o seu rosto. E eles o acompanharam até o navio.' },
    ],
    21: [
      { v: 1, en: 'When we had departed from them and had set sail, we came with a straight course to Cos, and the next day to Rhodes, and from there to Patara.', pt: 'E assim aconteceu que, separando-nos deles, navegamos e, correndo em direitura, chegamos a Cós, e no dia seguinte a Rodes, e dali a Pátara.' },
      { v: 2, en: 'Having found a ship crossing over to Phoenicia, we went aboard, and set sail.', pt: 'Achando um navio que seguia para a Fenícia, embarcamos e partimos.' },
      { v: 3, en: 'When we had come in sight of Cyprus, leaving it on the left hand, we sailed to Syria, and landed at Tyre, for there the ship was to unload her cargo.', pt: 'E quando avistamos Chipre, deixando-a á esquerda, navegamos para a Síria e chegamos a Tiro, pois o navio havia de ser descarregado ali.' },
      { v: 4, en: 'Having found disciples, we stayed there seven days. These said to Paul through the Spirit, that he should not go up to Jerusalem.', pt: 'Havendo achado os discípulos, demoramo-nos ali sete dias; e eles pelo Espírito diziam a Paulo que não subisse a Jerusalém.' },
      { v: 5, en: 'When those days were over, we departed and went on our journey. They all, with wives and children, brought us on our way until we were out of the city. Kneeling down on the beach, we prayed.', pt: 'Depois de passarmos ali aqueles dias, saímos e seguimos a nossa viagem, acompanhando-nos todos, com suas mulheres e filhos, até fora da cidade; e, postos de joelhos na praia, oramos,' },
      { v: 6, en: 'After saying goodbye to each other, we went on board the ship, and they returned home again.', pt: 'e despedindo-nos uns dos outros, embarcamos, e eles voltaram para casa.' },
      { v: 7, en: 'When we had finished the voyage from Tyre, we arrived at Ptolemais. We greeted the brothers, and stayed with them one day.', pt: 'Concluída a nossa viagem de Tiro, chegamos a Ptolemaida; e, havendo saudado os irmãos, passamos um dia com eles.' },
      { v: 8, en: 'On the next day, we, who were Paul’s companions, departed, and came to Caesarea. We entered into the house of Philip the evangelist, who was one of the seven, and stayed with him.', pt: 'Partindo no dia seguinte, fomos a Cesaréia; e entrando em casa de Felipe, o evangelista, que era um dos sete, ficamos com ele.' },
      { v: 9, en: 'Now this man had four virgin daughters who prophesied.', pt: 'Tinha este quatro filhas virgens que profetizavam.' },
      { v: 10, en: 'As we stayed there some days, a certain prophet named Agabus came down from Judea.', pt: 'Demorando-nos ali por muitos dias, desceu da Judéia um profeta, de nome Ágabo;' },
      { v: 11, en: 'Coming to us, and taking Paul’s belt, he bound his own feet and hands, and said, “Thus says the Holy Spirit: ‘So will the Jews at Jerusalem bind the man who owns this belt, and will deliver him into the hands of the Gentiles.’”', pt: 'e vindo ter conosco, tomou a cinta de Paulo e, ligando os seus próprios pés e mãos, disse: Isto diz o Espírito Santo: Assim os judeus ligarão em Jerusalém o homem a quem pertence esta cinta, e o entregarão nas mãos dos gentios.' },
      { v: 12, en: 'When we heard these things, both we and they of that place begged him not to go up to Jerusalem.', pt: 'Quando ouvimos isto, rogamos-lhe, tanto nós como os daquele lugar, que não subisse a Jerusalém.' },
      { v: 13, en: 'Then Paul answered, “What are you doing, weeping and breaking my heart? For I am ready not only to be bound, but also to die at Jerusalem for the name of the Lord Jesus.”', pt: 'Então Paulo resppondeu: Que fazeis chorando e magoando-me o coração? Porque eu estou pronto não só a ser ligado, mas ainda a morrer em Jerusalém pelo nome do Senhor Jesus.' },
      { v: 14, en: 'When he would not be persuaded, we ceased, saying, “The Lord’s will be done.”', pt: 'E, como não se deixasse persuadir, dissemos: Faça-se a vontade do Senhor; e calamo-nos.' },
      { v: 15, en: 'After these days we took up our baggage and went up to Jerusalem.', pt: 'Depois destes dias, havendo feito os preparativos, fomos subindo a Jerusalém.' },
      { v: 16, en: 'Some of the disciples from Caesarea also went with us, bringing one Mnason of Cyprus, an early disciple, with whom we would stay.', pt: 'E foram também conosco alguns discípulos de Cesaréia, levando consigo um certo Mnáson, cíprio, discípulo antigo, com quem nos havíamos de hospedar.' },
      { v: 17, en: 'When we had come to Jerusalem, the brothers received us gladly.', pt: 'E chegando nós a Jerusalém, os irmãos nos receberam alegremente.' },
      { v: 18, en: 'The day following, Paul went in with us to James; and all the elders were present.', pt: 'No dia seguinte Paulo foi em nossa companhia ter com Tiago, e compareceram todos os anciãos.' },
      { v: 19, en: 'When he had greeted them, he reported one by one the things which God had worked among the Gentiles through his ministry.', pt: 'E, havendo-os saudado, contou-lhes uma por uma as coisas que por seu ministério Deus fizera entre os gentios.' },
      { v: 20, en: 'They, when they heard it, glorified God. They said to him, “You see, brother, how many thousands there are among the Jews of those who have believed, and they are all zealous for the law.', pt: 'Ouvindo eles isto, glorificaram a Deus, e disseram-lhe: Bem vês, irmãos, quantos milhares há entre os judeus que têm crido, e todos são zelosos da lei; gregos, ouviram a palavra do' },
      { v: 21, en: 'They have been informed about you, that you teach all the Jews who are among the Gentiles to forsake Moses, telling them not to circumcise their children neither to walk after the customs.', pt: 'e têm sido informados a teu respeito que ensinas todos os judeus que estão entre os gentios a se apartarem de Moisés, dizendo que não circuncidem seus filhos, nem andem segundo os costumes da lei.' },
      { v: 22, en: 'What then? The assembly must certainly meet, for they will hear that you have come.', pt: 'Que se há de fazer, pois? Certamente saberão que és chegado.' },
      { v: 23, en: 'Therefore do what we tell you. We have four men who have taken a vow.', pt: 'Faze, pois, o que te vamos dizer: Temos quatro homens que fizeram voto;' },
      { v: 24, en: 'Take them, and purify yourself with them, and pay their expenses for them, that they may shave their heads. Then all will know that there is no truth in the things that they have been informed about you, but that you yourself also walk keeping the law.', pt: 'toma estes contigo, e santifica-te com eles, e faze por eles as despesas para que rapem a cabeça; e saberão todos que é falso aquilo de que têm sido informados a teu respeito, mas que também tu mesmo andas corretamente, guardando a lei.' },
      { v: 25, en: 'But concerning the Gentiles who believe, we have written our decision that they should observe no such thing, except that they should keep themselves from food offered to idols, from blood, from strangled things, and from sexual immorality.”', pt: 'Todavia, quanto aos gentios que têm crido já escrevemos, dando o parecer que se abstenham do que é sacrificado a os ídolos, do sangue, do sufocado e da prostituição.' },
      { v: 26, en: 'Then Paul took the men, and the next day, purified himself and went with them into the temple, declaring the fulfillment of the days of purification, until the offering was offered for every one of them.', pt: 'Então Paulo, no dia seguinte, tomando consigo aqueles homens, purificou-se com eles e entrou no templo, notificando o cumprimento dos dias da purificação, quando seria feita a favor de cada um deles a respectiva oferta.' },
      { v: 27, en: 'When the seven days were almost completed, the Jews from Asia, when they saw him in the temple, stirred up all the multitude and laid hands on him,', pt: 'Mas quando os sete dias estavam quase a terminar, os judeus da Ásia, tendo-o visto no templo, alvoroçaram todo o povo e agarraram-no,' },
      { v: 28, en: 'crying out, “Men of Israel, help! This is the man who teaches all men everywhere against the people, and the law, and this place. Moreover, he also brought Greeks into the temple, and has defiled this holy place!”', pt: 'clamando: Varões israelitas, acudi; este é o homem que por toda parte ensina a todos contra o povo, contra a lei, e contra este lugar; e ainda, além disso, introduziu gregos no templo, e tem profanado este santo lugar.' },
      { v: 29, en: 'For they had seen Trophimus, the Ephesian, with him in the city, and they supposed that Paul had brought him into the temple.', pt: 'Porque tinham visto com ele na cidade a Trófimo de Éfeso, e pensavam que Paulo o introduzira no templo.' },
      { v: 30, en: 'All the city was moved, and the people ran together. They seized Paul and dragged him out of the temple. Immediately the doors were shut.', pt: 'Alvoroçou-se toda a cidade, e houve ajuntamento do povo; e agarrando a Paulo, arrastaram-no para fora do templo, e logo as portas se fecharam.' },
      { v: 31, en: 'As they were trying to kill him, news came up to the commanding officer of the regiment that all Jerusalem was in an uproar.', pt: 'E, procurando eles matá-lo, chegou ao comandante da coorte o aviso de que Jerusalém estava toda em confusão;' },
      { v: 32, en: 'Immediately he took soldiers and centurions, and ran down to them. They, when they saw the chief captain and the soldiers, stopped beating Paul.', pt: 'o qual, tomando logo consigo soldados e centuriões, correu para eles; e quando viram o comandante e os soldados, cessaram de espancar a Paulo.' },
      { v: 33, en: 'Then the commanding officer came near, arrested him, commanded him to be bound with two chains, and inquired who he was and what he had done.', pt: 'Então aproximando-se o comandante, prendeu-o e mandou que fosse acorrentado com duas cadeias, e perguntou quem era e o que tinha feito.' },
      { v: 34, en: 'Some shouted one thing, and some another, among the crowd. When he couldn’t find out the truth because of the noise, he commanded him to be brought into the barracks.', pt: 'E na multidão uns gritavam de um modo, outros de outro; mas, não podendo por causa do alvoroço saber a verdade, mandou conduzí-lo à fortaleza.' },
      { v: 35, en: 'When he came to the stairs, he was carried by the soldiers because of the violence of the crowd;', pt: 'E sucedeu que, chegando às escadas, foi ele carregado pelos soldados por causa da violência da turba.' },
      { v: 36, en: 'for the multitude of the people followed after, crying out, “Away with him!”', pt: 'Pois a multidão o seguia, gritando: Mata-o!' },
      { v: 37, en: 'As Paul was about to be brought into the barracks, he asked the commanding officer, “May I speak to you?” He said, “Do you know Greek?', pt: 'Quando estava para ser introduzido na fortaleza, disse Paulo ao comandante: É-me permitido dizer-te alguma coisa? Respondeu ele: Sabes o grego?' },
      { v: 38, en: 'Aren’t you then the Egyptian, who before these days stirred up to sedition and led out into the wilderness the four thousand men of the Assassins?”', pt: 'Não és porventura o egípcio que há poucos dias fez uma sedição e levou ao deserto os quatro mil sicários?' },
      { v: 39, en: 'But Paul said, “I am a Jew, from Tarsus in Cilicia, a citizen of no insignificant city. I beg you, allow me to speak to the people.”', pt: 'Mas Paulo lhe disse: Eu sou judeu, natural de Tarso, cidade não insignificante da Cilícia; rogo-te que me permitas falar ao povo.' },
      { v: 40, en: 'When he had given him permission, Paul, standing on the stairs, beckoned with his hand to the people. When there was a great silence, he spoke to them in the Hebrew language, saying,', pt: 'E, havendo-lho permitido o comandante, Paulo, em pé na escada, fez sinal ao povo com a mão; e, feito grande silêncio, falou em língua hebraica, dizendo:' },
    ],
    22: [
      { v: 1, en: '“Brothers and fathers, listen to the defense which I now make to you.”', pt: 'Irmãos e pais, ouvi a minha defesa, que agora faço perante vós.' },
      { v: 2, en: 'When they heard that he spoke to them in the Hebrew language, they were even more quiet. He said,', pt: 'Ora, quando ouviram que lhes falava em língua hebraica, guardaram ainda maior silêncio. E ele prosseguiu.' },
      { v: 3, en: '“I am indeed a Jew, born in Tarsus of Cilicia, but brought up in this city at the feet of Gamaliel, instructed according to the strict tradition of the law of our fathers, being zealous for God, even as you all are today.', pt: 'Eu sou judeu, nascido em Tarso da Cilícia, mas criado nesta cidade, instruído aos pés de Gamaliel, conforme a precisão da lei de nossos pais, sendo zeloso para com Deus, assim como o sois todos vós no dia de hoje.' },
      { v: 4, en: 'I persecuted this Way to the death, binding and delivering into prisons both men and women.', pt: 'E persegui este Caminho até a morte, algemando e metendo em prisões tanto a homens como a mulheres,' },
      { v: 5, en: 'As also the high priest and all the council of the elders testify, from whom also I received letters to the brothers, and traveled to Damascus to bring them also who were there to Jerusalem in bonds to be punished.', pt: 'do que também o sumo sacerdote me é testemunha, e assim todo o conselho dos anciãos; e, tendo recebido destes cartas para os irmãos, seguia para Damasco, com o fim de trazer algemados a Jerusalém aqueles que ali estivessem, para que fossem castigados.' },
      { v: 6, en: 'As I made my journey, and came close to Damascus, about noon, suddenly a great light shone around me from the sky.', pt: 'Aconteceu, porém, que, quando caminhava e ia chegando perto de Damasco, pelo meio-dia, de repente, do céu brilhou-me ao redor uma grande luz.' },
      { v: 7, en: 'I fell to the ground, and heard a voice saying to me, ‘Saul, Saul, why are you persecuting me?’', pt: 'Caí por terra e ouvi uma voz que me dizia: Saulo, Saulo, por que me persegues?' },
      { v: 8, en: 'I answered, ‘Who are you, Lord?’ He said to me, ‘I am Jesus of Nazareth, whom you persecute.’', pt: 'Eu respondi: Quem és tu, Senhor? Disse-me: Eu sou Jesus, o nazareno, a quem tu persegues.' },
      { v: 9, en: '“Those who were with me indeed saw the light and were afraid, but they didn’t understand the voice of him who spoke to me.', pt: 'E os que estavam comigo viram, em verdade, a luz, mas não entenderam a voz daquele que falava comigo.' },
      { v: 10, en: 'I said, ‘What shall I do, Lord?’ The Lord said to me, ‘Arise, and go into Damascus. There you will be told about all things which are appointed for you to do.’', pt: 'Então disse eu: Senhor que farei? E o Senhor me disse: Levanta-te, e vai a Damasco, onde se te dirá tudo o que te é ordenado fazer.' },
      { v: 11, en: 'When I couldn’t see for the glory of that light, being led by the hand of those who were with me, I came into Damascus.', pt: 'Como eu nada visse por causa do esplendor daquela luz, guiado pela mão dos que estavam comigo cheguei a Damasco.' },
      { v: 12, en: 'One Ananias, a devout man according to the law, well reported of by all the Jews who lived in Damascus,', pt: 'um certo Ananias, varão piedoso conforme a lei, que tinha bom testemunho de todos os judeus que ali moravam,' },
      { v: 13, en: 'came to me, and standing by me said to me, ‘Brother Saul, receive your sight!’ In that very hour I looked up at him.', pt: 'vindo ter comigo, de pé ao meu lado, disse-me: Saulo, irmão, recobra a vista. Naquela mesma hora, recobrando a vista, eu o vi.' },
      { v: 14, en: 'He said, ‘The God of our fathers has appointed you to know his will, and to see the Righteous One, and to hear a voice from his mouth.', pt: 'Disse ele: O Deus de nossos pais de antemão te designou para conhecer a sua vontade, ver o Justo, e ouvir a voz da sua boca.' },
      { v: 15, en: 'For you will be a witness for him to all men of what you have seen and heard.', pt: 'Porque hás de ser sua testemunha para com todos os homens do que tens visto e ouvido.' },
      { v: 16, en: 'Now why do you wait? Arise, be baptized, and wash away your sins, calling on the name of the Lord.’', pt: 'Agora por que te demoras? Levanta-te, batiza-te e lava os teus pecados, invocando o seu nome.' },
      { v: 17, en: '“When I had returned to Jerusalem, and while I prayed in the temple, I fell into a trance,', pt: 'Aconteceu que, tendo eu voltado para Jerusalém, enquanto orava no templo, achei-me em êxtase,' },
      { v: 18, en: 'and saw him saying to me, ‘Hurry and get out of Jerusalem quickly, because they will not receive testimony concerning me from you.’', pt: 'e vi aquele que me dizia: Apressa-te e sai logo de Jerusalém; porque não receberão o teu testemunho acerca de mim.' },
      { v: 19, en: 'I said, ‘Lord, they themselves know that I imprisoned and beat in every synagogue those who believed in you.', pt: 'Disse eu: Senhor, eles bem sabem que eu encarcerava e açoitava pelas sinagogas os que criam em ti,' },
      { v: 20, en: 'When the blood of Stephen, your witness, was shed, I also was standing by, and consenting to his death, and guarding the cloaks of those who killed him.’', pt: 'e quando se derramava o sangue de Estêvão, tua testemunha, eu também estava presente, consentindo na sua morte e guardando as capas dos que o matavam.' },
      { v: 21, en: '“He said to me, ‘Depart, for I will send you out far from here to the Gentiles.’ ”', pt: 'Disse-me ele: Vai, porque eu te enviarei para longe aos gentios.' },
      { v: 22, en: 'They listened to him until he said that; then they lifted up their voice, and said, “Rid the earth of this fellow, for he isn’t fit to live!”', pt: 'Ora, escutavam-no até esta palavra, mas então levantaram a voz, dizendo: Tira do mundo tal homem, porque não convém que viva.' },
      { v: 23, en: 'As they cried out, and threw off their cloaks, and threw dust into the air,', pt: 'Gritando eles e arrojando de si as capas e lançando pó para o ar,' },
      { v: 24, en: 'the commanding officer commanded him to be brought into the barracks, ordering him to be examined by scourging, that he might know for what crime they shouted against him like that.', pt: 'o comandante mandou que levassem Paulo para dentro da fortaleza, ordenando que fosse interrogado debaixo de açoites, para saber por que causa assim clamavam contra ele.' },
      { v: 25, en: 'When they had tied him up with thongs, Paul asked the centurion who stood by, “Is it lawful for you to scourge a man who is a Roman, and not found guilty?”', pt: 'Quando o haviam atado com as correias, disse Paulo ao centurião que ali estava: É-vos lícito açoitar um cidadão romano, sem ser ele condenado?' },
      { v: 26, en: 'When the centurion heard it, he went to the commanding officer and told him, “Watch what you are about to do, for this man is a Roman!”', pt: 'Ouvindo isto, foi o centurião ter com o comandante e o avisou, dizendo: Vê o que estás para fazer, pois este homem é romano.' },
      { v: 27, en: 'The commanding officer came and asked him, “Tell me, are you a Roman?” He said, “Yes.”', pt: 'Vindo o comandante, perguntou-lhe: Dize-me: és tu romano? Respondeu ele: Sou.' },
      { v: 28, en: 'The commanding officer answered, “I bought my citizenship for a great price.” Paul said, “But I was born a Roman.”', pt: 'Tornou o comandante: Eu por grande soma de dinheiro adquiri este direito de cidadão. Paulo disse: Mas eu o sou de nascimento.' },
      { v: 29, en: 'Immediately those who were about to examine him departed from him, and the commanding officer also was afraid when he realized that he was a Roman, because he had bound him.', pt: 'Imediatamente, pois se apartaram dele aqueles que o iam interrogar; e até o comandante, tendo sabido que Paulo era romano, atemorizou-se porque o havia ligado.' },
      { v: 30, en: 'But on the next day, desiring to know the truth about why he was accused by the Jews, he freed him from the bonds, and commanded the chief priests and all the council to come together, and brought Paul down and set him before them.', pt: 'No dia seguinte, querendo saber ao certo a causa por que ele era acusado pelos judeus, soltou-o das prisões, e mandou que se reunissem os principais sacerdotes e todo o sinédrio; e, trazendo Paulo, apresentou-o diante deles.' },
    ],
    23: [
      { v: 1, en: 'Paul, looking steadfastly at the council, said, “Brothers, I have lived before God in all good conscience until today.”', pt: 'Fitando Paulo os olhos no sinédrio, disse: Varões irmãos, até o dia de hoje tenho andado diante de Deus com toda a boa consciência.' },
      { v: 2, en: 'The high priest, Ananias, commanded those who stood by him to strike him on the mouth.', pt: 'Mas o sumo sacerdote, Ananias, mandou aos que estavam junto dele que o ferissem na boca.' },
      { v: 3, en: 'Then Paul said to him, “God will strike you, you whitewashed wall! Do you sit to judge me according to the law, and command me to be struck contrary to the law?”', pt: 'Então Paulo lhe disse: Deus te ferirá a ti, parede branqueada; tu estás aí sentado para julgar-me segundo a lei, e contra a lei mandas que eu seja ferido?' },
      { v: 4, en: 'Those who stood by said, “Do you malign God’s high priest?”', pt: 'Os que estavam ali disseram: Injurias o sumo sacerdote de Deus?' },
      { v: 5, en: 'Paul said, “I didn’t know, brothers, that he was high priest. For it is written, ‘You shall not speak evil of a ruler of your people.’”', pt: 'Disse Paulo: Não sabia, irmãos, que era o sumo sacerdote; porque está escrito: Não dirás mal do príncipe do teu povo.' },
      { v: 6, en: 'But when Paul perceived that the one part were Sadducees and the other Pharisees, he cried out in the council, “Men and brothers, I am a Pharisee, a son of Pharisees. Concerning the hope and resurrection of the dead I am being judged!”', pt: 'Sabendo Paulo que uma parte era de saduceus e outra de fariseus, clamou no sinédrio: Varões irmãos, eu sou fariseu, filho de fariseus; é por causa da esperança da ressurreição dos mortos que estou sendo julgado.' },
      { v: 7, en: 'When he had said this, an argument arose between the Pharisees and Sadducees, and the crowd was divided.', pt: 'Ora, dizendo ele isto, surgiu dissensão entre os fariseus e saduceus; e a multidão se dividiu.' },
      { v: 8, en: 'For the Sadducees say that there is no resurrection, nor angel, nor spirit; but the Pharisees confess all of these.', pt: 'Porque os saduceus dizem que não há ressurreição, nem anjo, nem espírito; mas os fariseus reconhecem uma e outra coisa.' },
      { v: 9, en: 'A great clamor arose, and some of the scribes of the Pharisees’ part stood up, and contended, saying, “We find no evil in this man. But if a spirit or angel has spoken to him, let’s not fight against God!”', pt: 'Daí procedeu grande clamor; e levantando-se alguns da parte dos fariseus, altercavam, dizendo: Não achamos nenhum mal neste homem; e, quem sabe se lhe falou algum espírito ou anjo?' },
      { v: 10, en: 'When a great argument arose, the commanding officer, fearing that Paul would be torn in pieces by them, commanded the soldiers to go down and take him by force from among them, and bring him into the barracks.', pt: 'E avolumando-se a dissenção, o comandante, temendo que Paulo fosse por eles despedaçado, mandou que os soldados descessem e o tirassem do meio deles e o levassem para a fortaleza.' },
      { v: 11, en: 'The following night, the Lord stood by him, and said, “Cheer up, Paul, for as you have testified about me at Jerusalem, so you must testify also at Rome.”', pt: 'Na noite seguinte, apresentou-se-lhe o Senhor e disse: Tem bom ânimo: porque, como deste testemunho de mim em Jerusalém, assim importa que o dês também em Roma.' },
      { v: 12, en: 'When it was day, some of the Jews banded together, and bound themselves under a curse, saying that they would neither eat nor drink until they had killed Paul.', pt: 'Quando já era dia, coligaram-se os judeus e juraram sob pena de maldição que não comeriam nem beberiam enquanto não matassem a Paulo.' },
      { v: 13, en: 'There were more than forty people who had made this conspiracy.', pt: 'Eram mais de quarenta os que fizeram esta conjuração;' },
      { v: 14, en: 'They came to the chief priests and the elders, and said, “We have bound ourselves under a great curse, to taste nothing until we have killed Paul.', pt: 'e estes foram ter com os principais sacerdotes e anciãos, e disseram: Conjuramo-nos sob pena de maldição a não provarmos coisa alguma até que matemos a Paulo.' },
      { v: 15, en: 'Now therefore, you with the council inform the commanding officer that he should bring him down to you tomorrow, as though you were going to judge his case more exactly. We are ready to kill him before he comes near.”', pt: 'Agora, pois, vós, com o sinédrio, rogai ao comandante que o mande descer perante vós como se houvésseis de examinar com mais precisão a sua causa; e nós estamos prontos para matá-lo antes que ele chegue.' },
      { v: 16, en: 'But Paul’s sister’s son heard they were lying in wait, and he came and entered into the barracks and told Paul.', pt: 'Mas o filho da irmã de Paulo tendo sabido da cilada, foi, entrou na fortaleza e avisou a Paulo.' },
      { v: 17, en: 'Paul summoned one of the centurions, and said, “Bring this young man to the commanding officer, for he has something to tell him.”', pt: 'Chamando Paulo um dos centuriões, disse: Leva este moço ao comandante, porque tem alguma coisa que lhe comunicar.' },
      { v: 18, en: 'So he took him, and brought him to the commanding officer, and said, “Paul, the prisoner, summoned me and asked me to bring this young man to you, who has something to tell you.”', pt: 'Tomando-o ele, pois, levou-o ao comandante e disse: O preso Paulo, chamando-me, pediu-me que trouxesse à tua presença este moço, que tem alguma coisa a dizer-te.' },
      { v: 19, en: 'The commanding officer took him by the hand, and going aside, asked him privately, “What is it that you have to tell me?”', pt: 'O comandante tomou-o pela mão e, retirando-se à parte, perguntou-lhe em particular: Que é que tens a contar-me?' },
      { v: 20, en: 'He said, “The Jews have agreed to ask you to bring Paul down to the council tomorrow, as though intending to inquire somewhat more accurately concerning him.', pt: 'Disse ele: Os judeus combinaram rogar-te que amanhã mandes Paulo descer ao sinédrio, como que tendo de inquirir com mais precisão algo a seu respeito;' },
      { v: 21, en: 'Therefore don’t yield to them, for more than forty men lie in wait for him, who have bound themselves under a curse neither to eat nor to drink until they have killed him. Now they are ready, looking for the promise from you.”', pt: 'tu, pois, não te deixes persuadir por eles; porque mais de quarenta homens dentre eles armaram ciladas, os quais juraram sob pena de maldição não comerem nem beberem até que o tenham morto; e agora estão aprestados, esperando a tua promessa.' },
      { v: 22, en: 'So the commanding officer let the young man go, charging him, “Tell no one that you have revealed these things to me.”', pt: 'Então o comandante despediu o moço, ordenando-lhe que a ninguém dissesse que lhe havia contado aquilo.' },
      { v: 23, en: 'He called to himself two of the centurions, and said, “Prepare two hundred soldiers to go as far as Caesarea, with seventy horsemen, and two hundred men armed with spears, at the third hour of the night.”', pt: 'Chamando dois centuriões, disse: Aprontai para a terceira hora da noite duzentos soldados de infantaria, setenta de cavalaria e duzentos lanceiros para irem até Cesaréia;' },
      { v: 24, en: 'He asked them to provide animals, that they might set Paul on one, and bring him safely to Felix the governor.', pt: 'e mandou que aparelhassem cavalgaduras para que Paulo montasse, a fim de o levarem salvo ao governador Félix.' },
      { v: 25, en: 'He wrote a letter like this:', pt: 'E escreveu-lhe uma carta nestes termos:' },
      { v: 26, en: '“Claudius Lysias to the most excellent governor Felix: Greetings.', pt: 'Cláudio Lísias, ao excelentíssimo governador Félix, saúde.' },
      { v: 27, en: '“This man was seized by the Jews, and was about to be killed by them, when I came with the soldiers and rescued him, having learned that he was a Roman.', pt: 'Este homem foi preso pelos judeus, e estava a ponto de ser morto por eles quando eu sobrevim com a tropa e o livrei ao saber que era romano.' },
      { v: 28, en: 'Desiring to know the cause why they accused him, I brought him down to their council.', pt: 'Querendo saber a causa por que o acusavam, levei-o ao sinédrio deles;' },
      { v: 29, en: 'I found him to be accused about questions of their law, but not to be charged with anything worthy of death or of imprisonment.', pt: 'e achei que era acusado de questões da lei deles, mas que nenhum crime havia nele digno de morte ou prisão.' },
      { v: 30, en: 'When I was told that the Jews lay in wait for the man, I sent him to you immediately, charging his accusers also to bring their accusations against him before you. Farewell.”', pt: 'E quando fui informado que haveria uma cilada contra o homem, logo to enviei, intimando também aos acusadores que perante ti se manifestem contra ele. [Passa bem.]' },
      { v: 31, en: 'So the soldiers, carrying out their orders, took Paul and brought him by night to Antipatris.', pt: 'Os soldados, pois, conforme lhes fora mandado, tomando a Paulo, o levaram de noite a Antipátride.' },
      { v: 32, en: 'But on the next day they left the horsemen to go with him, and returned to the barracks.', pt: 'Mas no dia seguinte, deixando aos de cavalaria irem com ele, voltaram à fortaleza;' },
      { v: 33, en: 'When they came to Caesarea and delivered the letter to the governor, they also presented Paul to him.', pt: 'os quais, logo que chegaram a Cesaréia e entregaram a carta ao governador, apresentaram-lhe também Paulo.' },
      { v: 34, en: 'When the governor had read it, he asked what province he was from. When he understood that he was from Cilicia, he said,', pt: 'Tendo lido a carta, o governador perguntou de que província ele era; e, sabendo que era da Cilícia,' },
      { v: 35, en: '“I will hear you fully when your accusers also arrive.” He commanded that he be kept in Herod’s palace.', pt: 'disse: Ouvir-te-ei quando chegarem também os teus acusadores; e mandou que fosse guardado no pretório de Herodes.' },
    ],
    24: [
      { v: 1, en: 'After five days, the high priest, Ananias, came down with certain elders and an orator, one Tertullus. They informed the governor against Paul.', pt: 'Cinco dias depois o sumo sacerdote Ananias desceu com alguns anciãos e um certo Tertulo, orador, os quais fizeram, perante o governador, queixa contra Paulo.' },
      { v: 2, en: 'When he was called, Tertullus began to accuse him, saying, “Seeing that by you we enjoy much peace, and that prosperity is coming to this nation by your foresight,', pt: 'Sendo este chamado, Tertulo começou a acusá-lo, dizendo: Visto que por ti gozamos de muita paz e por tua providência são continuamente feitas reformas nesta nação,' },
      { v: 3, en: 'we accept it in all ways and in all places, most excellent Felix, with all thankfulness.', pt: 'em tudo e em todo lugar reconhecemo-lo com toda a gratidão, ó excelentíssimo Félix.' },
      { v: 4, en: 'But, that I don’t delay you, I entreat you to bear with us and hear a few words.', pt: 'Mas, para que não te detenha muito rogo-te que, conforme a tua eqüidade, nos ouças por um momento.' },
      { v: 5, en: 'For we have found this man to be a plague, an instigator of insurrections among all the Jews throughout the world, and a ringleader of the sect of the Nazarenes.', pt: 'Temos achado que este homem é uma peste, e promotor de sedições entre todos os judeus, por todo o mundo, e chefe da seita dos nazarenos;' },
      { v: 6, en: 'He even tried to profane the temple, and we arrested him.', pt: 'o qual tentou profanar o templo; e nós o prendemos, [e conforme a nossa lei o quisemos julgar.' },
      { v: 7, en: 'Mas sobrevindo o comandante Lísias no-lo tirou dentre as mãos com grande violência, mandando aos acusadores que viessem a ti.]', pt: 'Mas sobrevindo o comandante Lísias no-lo tirou dentre as mãos com grande violência, mandando aos acusadores que viessem a ti.]' },
      { v: 8, en: 'By examining him yourself you may ascertain all these things of which we accuse him.”', pt: 'e tu mesmo, examinando-o, poderás certificar-te de tudo aquilo de que nós o acusamos.' },
      { v: 9, en: 'The Jews also joined in the attack, affirming that these things were so.', pt: 'Os judeus também concordam na acusação, afirmando que estas coisas eram assim.' },
      { v: 10, en: 'When the governor had beckoned to him to speak, Paul answered, “Because I know that you have been a judge of this nation for many years, I cheerfully make my defense,', pt: 'Paulo, tendo-lhe o governador feito sinal que falasse, respondeu: Porquanto sei que há muitos anos és juiz sobre esta nação, com bom ânimo faço a minha defesa,' },
      { v: 11, en: 'seeing that you can verify that it is not more than twelve days since I went up to worship at Jerusalem.', pt: 'pois bem podes verificar que não há mais de doze dias subi a Jerusalém para adorar,' },
      { v: 12, en: 'In the temple they didn’t find me disputing with anyone or stirring up a crowd, either in the synagogues, or in the city.', pt: 'e que não me acharam no templo discutindo com alguém nem amotinando o povo, quer nas sinagogas quer na cidade.' },
      { v: 13, en: 'Nor can they prove to you the things of which they now accuse me.', pt: 'Nem te podem provar as coisas de que agora me acusam.' },
      { v: 14, en: 'But this I confess to you, that after the Way, which they call a sect, so I serve the God of our fathers, believing all things which are according to the law, and which are written in the prophets;', pt: 'Mas confesso-te isto: que, seguindo o caminho a que eles chamam seita, assim sirvo ao Deus de nossos pais, crendo tudo quanto está escrito na lei e nos profetas,' },
      { v: 15, en: 'having hope toward God, which these also themselves look for, that there will be a resurrection of the dead, both of the just and unjust.', pt: 'tendo esperança em Deus, como estes mesmos também esperam, de que há de haver ressurreição tanto dos justos como dos injustos.' },
      { v: 16, en: 'Herein I also practice always having a conscience void of offense toward God and men.', pt: 'Por isso procuro sempre ter uma consciência sem ofensas diante de Deus e dos homens.' },
      { v: 17, en: 'Now after some years, I came to bring gifts for the needy to my nation, and offerings;', pt: 'Vários anos depois vim trazer à minha nação esmolas e fazer oferendas;' },
      { v: 18, en: 'amid which certain Jews from Asia found me purified in the temple, not with a mob, nor with turmoil.', pt: 'e ocupado nestas coisas me acharam já santificado no templo não em ajuntamento, nem com tumulto, alguns judeus da Ásia,' },
      { v: 19, en: 'They ought to have been here before you, and to make accusation, if they had anything against me.', pt: 'os quais deviam comparecer diante de ti e acusar-me se tivessem alguma coisa contra mim;' },
      { v: 20, en: 'Or else let these men themselves say what injustice they found in me when I stood before the council,', pt: 'ou estes mesmos digam que iniquidade acharam, quando compareci perante o sinédrio,' },
      { v: 21, en: 'unless it is for this one thing that I cried standing among them, ‘Concerning the resurrection of the dead I am being judged before you today!’”', pt: 'a não ser acerca desta única palavra que, estando no meio deles, bradei: Por causa da ressurreição dos mortos é que hoje estou sendo julgado por vós.' },
      { v: 22, en: 'But Felix, having more exact knowledge concerning the Way, deferred them, saying, “When Lysias, the commanding officer, comes down, I will decide your case.”', pt: 'Félix, porém, que era bem informado a respeito do Caminho, adiou a questão, dizendo: Quando o comandante Lísias tiver descido, então tomarei inteiro conhecimento da vossa causa.' },
      { v: 23, en: 'He ordered the centurion that Paul should be kept in custody, and should have some privileges, and not to forbid any of his friends to serve him or to visit him.', pt: 'E ordenou ao centurião que Paulo ficasse detido, mas fosse tratado com brandura e que a nenhum dos seus proibisse servi-lo.' },
      { v: 24, en: 'But after some days, Felix came with Drusilla, his wife, who was a Jewess, and sent for Paul, and heard him concerning the faith in Christ Jesus.', pt: 'Alguns dias depois, vindo Félix com sua mulher Drusila, que era judia, mandou chamar a Paulo, e ouviu-o acerca da fé em Cristo Jesus.' },
      { v: 25, en: 'As he reasoned about righteousness, self-control, and the judgment to come, Felix was terrified, and answered, “Go your way for this time, and when it is convenient for me, I will summon you.”', pt: 'E discorrendo ele sobre a justiça, o domínio próprio e o juízo vindouro, Félix ficou atemorizado e respondeu: Por ora vai-te, e quando tiver ocasião favorável, eu te chamarei.' },
      { v: 26, en: 'Meanwhile, he also hoped that money would be given to him by Paul, that he might release him. Therefore also he sent for him more often, and talked with him.', pt: 'Esperava ao mesmo tempo que Paulo lhe desse dinheiro, pelo que o mandava chamar mais freqüentemente e conversava com ele.' },
      { v: 27, en: 'But when two years were fulfilled, Felix was succeeded by Porcius Festus, and desiring to gain favor with the Jews, Felix left Paul in bonds.', pt: 'Mas passados dois anos, teve Félix por sucessor a Pórcio Festo; e querendo Félix agradar aos judeus, deixou a Paulo preso.' },
    ],
    25: [
      { v: 1, en: 'Festus therefore, having come into the province, after three days went up to Jerusalem from Caesarea.', pt: 'Tendo, pois, entrado Festo na província, depois de três dias subiu de Cesaréia a Jerusalém.' },
      { v: 2, en: 'Then the high priest and the principal men of the Jews informed him against Paul, and they begged him,', pt: 'E os principais sacerdotes e os mais eminentes judeus fizeram-lhe queixa contra Paulo e, em detrimento deste,' },
      { v: 3, en: 'asking a favor against him, that he would summon him to Jerusalem; plotting to kill him on the way.', pt: 'lhe rogavam o favor de o mandar a Jerusalém, armando ciladas para o matarem no caminho.' },
      { v: 4, en: 'However Festus answered that Paul should be kept in custody at Caesarea, and that he himself was about to depart shortly.', pt: 'Mas Festo respondeu que Paulo estava detido em Cesaréia, e que ele mesmo brevemente partiria para lá.' },
      { v: 5, en: '“Let them therefore”, said he, “that are in power among you go down with me, and if there is anything wrong in the man, let them accuse him.”', pt: 'Portanto - disse ele - as autoridades dentre vós desçam comigo e, se há nesse homem algum crime, acusem-no.' },
      { v: 6, en: 'When he had stayed among them more than ten days, he went down to Caesarea, and on the next day he sat on the judgment seat, and commanded Paul to be brought.', pt: 'Tendo-se demorado entre eles não mais de oito ou dez dias, desceu a Cesaréia; e no dia seguinte, sentando-se no tribunal, mandou trazer Paulo.' },
      { v: 7, en: 'When he had come, the Jews who had come down from Jerusalem stood around him, bringing against him many and grievous charges which they could not prove,', pt: 'Tendo ele comparecido, rodearam-no os judeus que haviam descido de Jerusalém, trazendo contra ele muitas e graves acusações, que não podiam provar.' },
      { v: 8, en: 'while he said in his defense, “Neither against the law of the Jews, nor against the temple, nor against Caesar, have I sinned at all.”', pt: 'Paulo, porém, respondeu em sua defesa: Nem contra a lei dos judeus, nem contra o templo, nem contra César, tenho pecado em coisa alguma.' },
      { v: 9, en: 'But Festus, desiring to gain favor with the Jews, answered Paul and said, “Are you willing to go up to Jerusalem, and be judged by me there concerning these things?”', pt: 'Todavia Festo, querendo agradar aos judeus, respondendo a Paulo, disse: Queres subir a Jerusalém e ali ser julgado perante mim acerca destas coisas?' },
      { v: 10, en: 'But Paul said, “I am standing before Caesar’s judgment seat, where I ought to be tried. I have done no wrong to the Jews, as you also know very well.', pt: 'Mas Paulo disse: Estou perante o tribunal de César, onde devo ser julgado; nenhum mal fiz aos judeus, como muito bem sabes.' },
      { v: 11, en: 'For if I have done wrong, and have committed anything worthy of death, I don’t refuse to die; but if none of those things is true that they accuse me of, no one can give me up to them. I appeal to Caesar!”', pt: 'Se, pois, sou malfeitor e tenho cometido alguma coisa digna de morte, não recuso morrer; mas se nada há daquilo de que estes me acusam, ninguém me pode entregar a eles; apelo para César.' },
      { v: 12, en: 'Then Festus, when he had conferred with the council, answered, “You have appealed to Caesar. To Caesar you shall go.”', pt: 'Então Festo, tendo falado com o conselho, respondeu: Apelaste para César; para César irás.' },
      { v: 13, en: 'Now when some days had passed, King Agrippa and Bernice arrived at Caesarea, and greeted Festus.', pt: 'Passados alguns dias, o rei Agripa e Berenice vieram a Cesaréia em visita de saudação a Festo.' },
      { v: 14, en: 'As he stayed there many days, Festus laid Paul’s case before the king, saying, “There is a certain man left a prisoner by Felix;', pt: 'E, como se demorassem ali muitos dias, Festo expôs ao rei o caso de Paulo, dizendo: Há aqui certo homem que foi deixado preso por Félix,' },
      { v: 15, en: 'about whom, when I was at Jerusalem, the chief priests and the elders of the Jews informed me, asking for a sentence against him.', pt: 'a respeito do qual, quando estive em Jerusalém, os principais sacerdotes e os anciãos dos judeus me fizeram queixas, pedindo sentença contra ele;' },
      { v: 16, en: 'To whom I answered that it is not the custom of the Romans to give up any man to destruction, before the accused has met the accusers face to face, and has had opportunity to make his defense concerning the matter laid against him.', pt: 'aos quais respondi que não é costume dos romanos condenar homem algum sem que o acusado tenha presentes os seus acusadores e possa defender-se da acusação.' },
      { v: 17, en: 'When therefore they had come together here, I didn’t delay, but on the next day sat on the judgment seat, and commanded the man to be brought.', pt: 'Quando então eles se haviam reunido aqui, sem me demorar, no dia seguinte sentei-me no tribunal e mandei trazer o homem;' },
      { v: 18, en: 'Concerning whom, when the accusers stood up, they brought no charge of such things as I supposed;', pt: 'contra o qual os acusadores, levantando-se, não apresentaram acusação alguma das coisas perversas que eu suspeitava;' },
      { v: 19, en: 'but had certain questions against him about their own religion, and about one Jesus, who was dead, whom Paul affirmed to be alive.', pt: 'tinham, porém, contra ele algumas questões acerca da sua religião e de um tal Jesus defunto, que Paulo afirmava estar vivo.' },
      { v: 20, en: 'Being perplexed how to inquire concerning these things, I asked whether he was willing to go to Jerusalem and there be judged concerning these matters.', pt: 'E, estando eu perplexo quanto ao modo de investigar estas coisas, perguntei se não queria ir a Jerusalém e ali ser julgado no tocante às mesmas.' },
      { v: 21, en: 'But when Paul had appealed to be kept for the decision of the emperor, I commanded him to be kept until I could send him to Caesar.”', pt: 'Mas apelando Paulo para que fosse reservado ao julgamento do imperador, mandei que fosse detido até que o enviasse a César.' },
      { v: 22, en: 'Agrippa said to Festus, “I also would like to hear the man myself.” “Tomorrow,” he said, “you shall hear him.”', pt: 'Então Agripa disse a Festo: Eu bem quisera ouvir esse homem. Respondeu-lhe ele: Amanhã o ouvirás.' },
      { v: 23, en: 'So on the next day, when Agrippa and Bernice had come with great pomp, and they had entered into the place of hearing with the commanding officers and the principal men of the city, at the command of Festus, Paul was brought in.', pt: 'No dia seguinte vindo Agripa e Berenice, com muito aparato, entraram no auditório com os chefes militares e homens principais da cidade; então, por ordem de Festo, Paulo foi trazido.' },
      { v: 24, en: 'Festus said, “King Agrippa, and all men who are here present with us, you see this man, about whom all the multitude of the Jews petitioned me, both at Jerusalem and here, crying that he ought not to live any longer.', pt: 'Disse Festo: Rei Agripa e vós todos que estais presentes conosco, vedes este homem por causa de quem toda a multidão dos judeus, tanto em Jerusalém como aqui, recorreu a mim, clamando que não convinha que ele vivesse mais.' },
      { v: 25, en: 'But when I found that he had committed nothing worthy of death, and as he himself appealed to the emperor I determined to send him,', pt: 'Eu, porém, achei que ele não havia praticado coisa alguma digna de morte; mas havendo ele apelado para o imperador, resolvi remeter-lho.' },
      { v: 26, en: 'of whom I have no certain thing to write to my lord. Therefore I have brought him out before you, and especially before you, King Agrippa, that, after examination, I may have something to write.', pt: 'Do qual não tenho coisa certa que escreva a meu senhor, e por isso perante vós o trouxe, principalmente perante ti, ó rei Agripa, para que, depois de feito o interrogatório, tenha eu alguma coisa que escrever.' },
      { v: 27, en: 'For it seems to me unreasonable, in sending a prisoner, not to also specify the charges against him.”', pt: 'Porque não me parece razoável enviar um preso, e não notificar as acusações que há contra ele.' },
    ],
    26: [
      { v: 1, en: 'Agrippa said to Paul, “You may speak for yourself.” Then Paul stretched out his hand, and made his defense.', pt: 'Depois Agripa disse a Paulo: É-te permitido fazer a tua defesa. Então Paulo, estendendo a mão, começou a sua defesa:' },
      { v: 2, en: '“I think myself happy, King Agrippa, that I am to make my defense before you today concerning all the things that I am accused by the Jews,', pt: 'Sinto-me feliz, ó rei Agripa, em poder defender-me hoje perante ti de todas as coisas de que sou acusado pelos judeus;' },
      { v: 3, en: 'especially because you are expert in all customs and questions which are among the Jews. Therefore I beg you to hear me patiently.', pt: 'mormente porque és versado em todos os costumes e questões que há entre os judeus; pelo que te rogo que me ouças com paciência.' },
      { v: 4, en: '“Indeed, all the Jews know my way of life from my youth up, which was from the beginning among my own nation and at Jerusalem;', pt: 'A minha vida, pois, desde a mocidade, o que tem sido sempre entre o meu povo e em Jerusalém, sabem-na todos os judeus,' },
      { v: 5, en: 'having known me from the first, if they are willing to testify, that after the strictest sect of our religion I lived a Pharisee.', pt: 'pois me conhecem desde o princípio e, se quiserem, podem dar testemunho de que, conforme a mais severa seita da nossa religião, vivi fariseu.' },
      { v: 6, en: 'Now I stand here to be judged for the hope of the promise made by God to our fathers,', pt: 'E agora estou aqui para ser julgado por causa da esperança da promessa feita por Deus a nossos pais,' },
      { v: 7, en: 'which our twelve tribes, earnestly serving night and day, hope to attain. Concerning this hope I am accused by the Jews, King Agrippa!', pt: 'a qual as nossas doze tribos, servindo a Deus fervorosamente noite e dia, esperam alcançar; é por causa desta esperança, ó rei, que eu sou acusado pelos judeus.' },
      { v: 8, en: 'Why is it judged incredible with you, if God does raise the dead?', pt: 'Por que é que se julga entre vós incrível que Deus ressuscite os mortos?' },
      { v: 9, en: '“I myself most certainly thought that I ought to do many things contrary to the name of Jesus of Nazareth.', pt: 'Eu, na verdade, cuidara que devia praticar muitas coisas contra o nome de Jesus, o nazareno;' },
      { v: 10, en: 'This I also did in Jerusalem. I both shut up many of the saints in prisons, having received authority from the chief priests, and when they were put to death I gave my vote against them.', pt: 'o que, com efeito, fiz em Jerusalém. Pois havendo recebido autoridade dos principais dos sacerdotes, não somente encerrei muitos dos santos em prisões, como também dei o meu voto contra eles quando os matavam.' },
      { v: 11, en: 'Punishing them often in all the synagogues, I tried to make them blaspheme. Being exceedingly enraged against them, I persecuted them even to foreign cities.', pt: 'E, castigando-os muitas vezes por todas as sinagogas, obrigava-os a blasfemar; e enfurecido cada vez mais contra eles, perseguia-os até nas cidades estrangeiras.' },
      { v: 12, en: '“Whereupon as I traveled to Damascus with the authority and commission from the chief priests,', pt: 'Indo com este encargo a Damasco, munido de poder e comissão dos principais sacerdotes,' },
      { v: 13, en: 'at noon, O king, I saw on the way a light from the sky, brighter than the sun, shining around me and those who traveled with me.', pt: 'ao meio-dia, ó rei vi no caminho uma luz do céu, que excedia o esplendor do sol, resplandecendo em torno de mim e dos que iam comigo.' },
      { v: 14, en: 'When we had all fallen to the earth, I heard a voice saying to me in the Hebrew language, ‘Saul, Saul, why are you persecuting me? It is hard for you to kick against the goads.’', pt: 'E, caindo nós todos por terra, ouvi uma voz que me dizia em língua hebráica: Saulo, Saulo, por que me persegues? Dura coisa te é recalcitrar contra os aguilhões.' },
      { v: 15, en: '“I said, ‘Who are you, Lord?’ “He said, ‘I am Jesus, whom you are persecuting.', pt: 'Disse eu: Quem és, Senhor? Respondeu o Senhor: Eu sou Jesus, a quem tu persegues;' },
      { v: 16, en: 'But arise, and stand on your feet, for I have appeared to you for this purpose: to appoint you a servant and a witness both of the things which you have seen, and of the things which I will reveal to you;', pt: 'mas levanta-te e põe-te em pé; pois para isto te apareci, para te fazer ministro e testemunha tanto das coisas em que me tens visto como daquelas em que te hei de aparecer;' },
      { v: 17, en: 'delivering you from the people, and from the Gentiles, to whom I send you,', pt: 'livrando-te deste povo e dos gentios, aos quais te envio,' },
      { v: 18, en: 'to open their eyes, that they may turn from darkness to light and from the power of Satan to God, that they may receive remission of sins and an inheritance among those who are sanctified by faith in me.’', pt: 'para lhes abrir os olhos a fim de que se convertam das trevas à luz, e do poder de Satanás a Deus, para que recebam remissão de pecados e herança entre aqueles que são santificados pela fé em mim.' },
      { v: 19, en: '“Therefore, King Agrippa, I was not disobedient to the heavenly vision,', pt: 'Pelo que, ó rei Agripa, não fui desobediente à visão celestial,' },
      { v: 20, en: 'but declared first to them of Damascus, at Jerusalem, and throughout all the country of Judea, and also to the Gentiles, that they should repent and turn to God, doing works worthy of repentance.', pt: 'antes anunciei primeiramente aos que estão em Damasco, e depois em Jerusalém, e por toda a terra da Judéia e também aos gentios, que se arrependessem e se convertessem a Deus, praticando obras dignas de arrependimento.' },
      { v: 21, en: 'For this reason the Jews seized me in the temple, and tried to kill me.', pt: 'Por causa disto os judeus me prenderam no templo e procuravam matar-me.' },
      { v: 22, en: 'Having therefore obtained the help that is from God, I stand to this day testifying both to small and great, saying nothing but what the prophets and Moses said would happen,', pt: 'Tendo, pois, alcançado socorro da parte de Deus, ainda até o dia de hoje permaneço, dando testemunho tanto a pequenos como a grandes, não dizendo nada senão o que os profetas e Moisés disseram que devia acontecer;' },
      { v: 23, en: 'how the Christ must suffer, and how, by the resurrection of the dead, he would be first to proclaim light both to these people and to the Gentiles.”', pt: 'isto é, como o Cristo devia padecer, e como seria ele o primeiro que, pela ressurreiçao dos mortos, devia anunciar a luz a este povo e também aos gentios.' },
      { v: 24, en: 'As he thus made his defense, Festus said with a loud voice, “Paul, you are crazy! Your great learning is driving you insane!”', pt: 'Fazendo ele deste modo a sua defesa, disse Festo em alta voz: Estás louco, Paulo; as muitas letras te fazem delirar.' },
      { v: 25, en: 'But he said, “I am not crazy, most excellent Festus, but boldly declare words of truth and reasonableness.', pt: 'Mas Paulo disse: Não deliro, ó excelentíssimo Festo, antes digo palavras de verdade e de perfeito juízo.' },
      { v: 26, en: 'For the king knows of these things, to whom also I speak freely. For I am persuaded that none of these things is hidden from him, for this has not been done in a corner.', pt: 'Porque o rei, diante de quem falo com liberdade, sabe destas coisas, pois não creio que nada disto lhe é oculto; porque isto não se fez em qualquer canto.' },
      { v: 27, en: 'King Agrippa, do you believe the prophets? I know that you believe.”', pt: 'Crês tu nos profetas, ó rei Agripa? Sei que crês.' },
      { v: 28, en: 'Agrippa said to Paul, “With a little persuasion are you trying to make me a Christian?”', pt: 'Disse Agripa a Paulo: Por pouco me persuades a fazer-me cristão.' },
      { v: 29, en: 'Paul said, “I pray to God, that whether with little or with much, not only you, but also all that hear me today, might become such as I am, except for these bonds.”', pt: 'Respondeu Paulo: Prouvera a Deus que, ou por pouco ou por muito, não somente tu, mas também todos quantos hoje me ouvem, se tornassem tais qual eu sou, menos estas cadeias.' },
      { v: 30, en: 'The king rose up with the governor, and Bernice, and those who sat with them.', pt: 'E levantou-se o rei, e o governador, e Berenice, e os que com eles estavam sentados,' },
      { v: 31, en: 'When they had withdrawn, they spoke to one another, saying, “This man does nothing worthy of death or of bonds.”', pt: 'e retirando-se falavam uns com os outros, dizendo: Este homem não fez nada digno de morte ou prisão.' },
      { v: 32, en: 'Agrippa said to Festus, “This man might have been set free if he had not appealed to Caesar.”', pt: 'Então Agripa disse a Festo: Este homem bem podia ser solto, se não tivesse apelado para César.' },
    ],
    27: [
      { v: 1, en: 'When it was determined that we should sail for Italy, they delivered Paul and certain other prisoners to a centurion named Julius, of the Augustan band.', pt: 'E, como se determinou que navegássemos para a Itália, entregaram Paulo e alguns outros presos a um centurião por nome Júlio, da coorte augusta.' },
      { v: 2, en: 'Embarking in a ship of Adramyttium, which was about to sail to places on the coast of Asia, we put to sea; Aristarchus, a Macedonian of Thessalonica, being with us.', pt: 'E, embarcando em um navio de Adramítio, que estava prestes a navegar em demanda dos portos pela costa da Ásia, fizemo-nos ao mar, estando conosco Aristarco, macedônio de Tessalônica.' },
      { v: 3, en: 'The next day, we touched at Sidon. Julius treated Paul kindly, and gave him permission to go to his friends and refresh himself.', pt: 'No dia seguinte chegamos a Sidom, e Júlio, tratando Paulo com bondade, permitiu-lhe ir ver os amigos e receber deles os cuidados necessários.' },
      { v: 4, en: 'Putting to sea from there, we sailed under the lee of Cyprus, because the winds were contrary.', pt: 'Partindo dali, fomos navegando a sotavento de Chipre, porque os ventos eram contrários.' },
      { v: 5, en: 'When we had sailed across the sea which is off Cilicia and Pamphylia, we came to Myra, a city of Lycia.', pt: 'Tendo atravessado o mar ao longo da Cilícia e Panfília, chegamos a Mirra, na Lícia.' },
      { v: 6, en: 'There the centurion found a ship of Alexandria sailing for Italy, and he put us on board.', pt: 'Ali o centurião achou um navio de Alexandria que navegava para a Itália, e nos fez embarcar nele.' },
      { v: 7, en: 'When we had sailed slowly many days, and had come with difficulty opposite Cnidus, the wind not allowing us further, we sailed under the lee of Crete, opposite Salmone.', pt: 'Navegando vagarosamente por muitos dias, e havendo chegado com dificuldade defronte de Cnido, não nos permitindo o vento ir mais adiante, navegamos a sotavento de Creta, à altura de Salmone;' },
      { v: 8, en: 'With difficulty sailing along it we came to a certain place called Fair Havens, near the city of Lasea.', pt: 'e, costeando-a com dificuldade, chegamos a um lugar chamado Bons Portos, perto do qual estava a cidade de Laséia.' },
      { v: 9, en: 'When much time had passed and the voyage was now dangerous, because the Fast had now already gone by, Paul admonished them,', pt: 'Havendo decorrido muito tempo e tendo-se tornado perigosa a navegação, porque já havia passado o jejum, Paulo os advertia,' },
      { v: 10, en: 'and said to them, “Sirs, I perceive that the voyage will be with injury and much loss, not only of the cargo and the ship, but also of our lives.”', pt: 'dizendo-lhes: Senhores, vejo que a viagem vai ser com avaria e muita perda não só para a carga e o navio, mas também para as nossas vidas.' },
      { v: 11, en: 'But the centurion gave more heed to the master and to the owner of the ship than to those things which were spoken by Paul.', pt: 'Mas o centurião dava mais crédito ao piloto e ao dono do navio do que às coisas que Paulo dizia.' },
      { v: 12, en: 'Because the haven was not suitable to winter in, the majority advised going to sea from there, if by any means they could reach Phoenix, and winter there, which is a port of Crete, looking northeast and southeast.', pt: 'E não sendo o porto muito próprio para invernar, os mais deles foram de parecer que daí se fizessem ao mar para ver se de algum modo podiam chegar a Fênice, um porto de Creta que olha para o nordeste e para o sueste, para ali invernar.' },
      { v: 13, en: 'When the south wind blew softly, supposing that they had obtained their purpose, they weighed anchor and sailed along Crete, close to shore.', pt: 'Soprando brandamente o vento sul, e supondo eles terem alcançado o que desejavam, levantaram ferro e iam costeando Creta bem de perto.' },
      { v: 14, en: 'But before long, a stormy wind beat down from shore, which is called Euroclydon.', pt: 'Mas não muito depois desencadeou-se do lado da ilha um tufão de vento chamado euro-aquilão;' },
      { v: 15, en: 'When the ship was caught, and couldn’t face the wind, we gave way to it, and were driven along.', pt: 'e, sendo arrebatado o navio e não podendo navegar contra o vento, cedemos à sua força e nos deixávamos levar.' },
      { v: 16, en: 'Running under the lee of a small island called Clauda, we were able, with difficulty, to secure the boat.', pt: 'Correndo a sota-vento de uma pequena ilha chamada Clauda, somente a custo pudemos segurar o batel,' },
      { v: 17, en: 'After they had hoisted it up, they used cables to help reinforce the ship. Fearing that they would run aground on the Syrtis sand bars, they lowered the sea anchor, and so were driven along.', pt: 'o qual recolheram, usando então os meios disponíveis para cingir o navio; e, temendo que fossem lançados na Sirte, arriaram os aparelhos e se deixavam levar.' },
      { v: 18, en: 'As we labored exceedingly with the storm, the next day they began to throw things overboard.', pt: 'Como fôssemos violentamente açoitados pela tempestade, no dia seguinte começaram a alijar a carga ao mar.' },
      { v: 19, en: 'On the third day, they threw out the ship’s tackle with their own hands.', pt: 'E ao terceiro dia, com as próprias mãos lançaram os aparelhos do navio.' },
      { v: 20, en: 'When neither sun nor stars shone on us for many days, and no small storm pressed on us, all hope that we would be saved was now taken away.', pt: 'Não aparecendo por muitos dia nem sol nem estrelas, e sendo nós ainda batidos por grande tempestade, fugiu-nos afinal toda a esperança de sermos salvos.' },
      { v: 21, en: 'When they had been long without food, Paul stood up in the middle of them, and said, “Sirs, you should have listened to me, and not have set sail from Crete, and have gotten this injury and loss.', pt: 'Havendo eles estado muito tempo sem comer, Paulo, pondo-se em pé no meio deles, disse: Senhores, devíeis ter-me ouvido e não ter partido de Creta, para evitar esta avaria e perda.' },
      { v: 22, en: 'Now I exhort you to cheer up, for there will be no loss of life among you, but only of the ship.', pt: 'E agora vos exorto a que tenhais bom ânimo, pois não se perderá vida alguma entre vós, mas somente o navio.' },
      { v: 23, en: 'For there stood by me this night an angel, belonging to the God whose I am and whom I serve,', pt: 'Porque esta noite me apareceu um anjo do Deus de quem eu sou e a quem sirvo,' },
      { v: 24, en: 'saying, ‘Don’t be afraid, Paul. You must stand before Caesar. Behold, God has granted you all those who sail with you.’', pt: 'dizendo: Não temas, Paulo, importa que compareças perante César, e eis que Deus te deu todos os que navegam contigo.' },
      { v: 25, en: 'Therefore, sirs, cheer up! For I believe God, that it will be just as it has been spoken to me.', pt: 'Portanto, senhores, tende bom ânimo; pois creio em Deus que há de suceder assim como me foi dito.' },
      { v: 26, en: 'But we must run aground on a certain island.”', pt: 'Contudo é necessário irmos dar em alguma ilha.' },
      { v: 27, en: 'But when the fourteenth night had come, as we were driven back and forth in the Adriatic Sea, about midnight the sailors surmised that they were drawing near to some land.', pt: 'Quando chegou a décima quarta noite, sendo nós ainda impelidos pela tempestade no mar de Ádria, pela meia-noite, suspeitaram os marinheiros a proximidade de terra;' },
      { v: 28, en: 'They took soundings, and found twenty fathoms. After a little while, they took soundings again, and found fifteen fathoms.', pt: 'e lançando a sonda, acharam vinte braças; passando um pouco mais adiante, e tornando a lançar a sonda, acharam quinze braças.' },
      { v: 29, en: 'Fearing that we would run aground on rocky ground, they let go four anchors from the stern, and wished for daylight.', pt: 'Ora, temendo irmos dar em rochedos, lançaram da popa quatro âncoras, e esperaram ansiosos que amanhecesse.' },
      { v: 30, en: 'As the sailors were trying to flee out of the ship, and had lowered the boat into the sea, pretending that they would lay out anchors from the bow,', pt: 'Procurando, entrementes, os marinheiros fugir do navio, e tendo arriado o batel ao mar sob pretexto de irem lançar âncoras pela proa,' },
      { v: 31, en: 'Paul said to the centurion and to the soldiers, “Unless these stay in the ship, you can’t be saved.”', pt: 'disse Paulo ao centurião e aos soldados: Se estes não ficarem no navio, não podereis salvar-vos.' },
      { v: 32, en: 'Then the soldiers cut away the ropes of the boat, and let it fall off.', pt: 'Então os soldados cortaram os cabos do batel e o deixaram cair.' },
      { v: 33, en: 'While the day was coming on, Paul begged them all to take some food, saying, “Today is the fourteenth day that you wait and continue fasting, having taken nothing.', pt: 'Enquanto amanhecia, Paulo rogava a todos que comessem alguma coisa, dizendo: É já hoje o décimo quarto dia que esperais e permaneceis em jejum, não havendo provado coisa alguma.' },
      { v: 34, en: 'Therefore I beg you to take some food, for this is for your safety; for not a hair will perish from any of your heads.”', pt: 'Rogo-vos, portanto, que comais alguma coisa, porque disso depende a vossa segurança; porque nem um cabelo cairá da cabeça de qualquer de vós.' },
      { v: 35, en: 'When he had said this, and had taken bread, he gave thanks to God in the presence of all, and he broke it, and began to eat.', pt: 'E, havendo dito isto, tomou o pão, deu graças a Deus na presença de todos e, partindo-o começou a comer.' },
      { v: 36, en: 'Then they all cheered up, and they also took food.', pt: 'Então todos cobraram ânimo e se puseram também a comer.' },
      { v: 37, en: 'In all, we were two hundred seventy-six souls on the ship.', pt: 'Éramos ao todo no navio duzentas e setenta e seis almas.' },
      { v: 38, en: 'When they had eaten enough, they lightened the ship, throwing out the wheat into the sea.', pt: 'Depois de saciados com a comida, começaram a aliviar o navio, alijando o trigo no mar.' },
      { v: 39, en: 'When it was day, they didn’t recognize the land, but they noticed a certain bay with a beach, and they decided to try to drive the ship onto it.', pt: 'Quando amanheceu, não reconheciam a terra; divisavam, porém, uma enseada com uma praia, e consultavam se poderiam nela encalhar o navio.' },
      { v: 40, en: 'Casting off the anchors, they left them in the sea, at the same time untying the rudder ropes. Hoisting up the foresail to the wind, they made for the beach.', pt: 'Soltando as âncoras, deixaram-nas no mar, largando ao mesmo tempo as amarras do leme; e, içando ao vento a vela da proa, dirigiram-se para a praia.' },
      { v: 41, en: 'But coming to a place where two seas met, they ran the vessel aground. The bow struck and remained immovable, but the stern began to break up by the violence of the waves.', pt: 'Dando, porém, num lugar onde duas correntes se encontravam, encalharam o navio; e a proa, encravando-se, ficou imóvel, mas a popa se desfazia com a força das ondas.' },
      { v: 42, en: 'The soldiers’ counsel was to kill the prisoners, so that none of them would swim out and escape.', pt: 'Então o parecer dos soldados era que matassem os presos para que nenhum deles fugisse, escapando a nado.' },
      { v: 43, en: 'But the centurion, desiring to save Paul, stopped them from their purpose, and commanded that those who could swim should throw themselves overboard first to go toward the land;', pt: 'Mas o centurião, querendo salvar a Paulo, estorvou-lhes este intento; e mandou que os que pudessem nadar fossem os primeiros a lançar-se ao mar e alcançar a terra;' },
      { v: 44, en: 'and the rest should follow, some on planks, and some on other things from the ship. So they all escaped safely to the land.', pt: 'e que os demais se salvassem, uns em tábuas e outros em quaisquer destroços do navio. Assim chegaram todos à terra salvos.' },
    ],
    28: [
      { v: 1, en: 'When we had escaped, then they learned that the island was called Malta.', pt: 'Estando já salvos, soubemos então que a ilha se chamava Malta.' },
      { v: 2, en: 'The natives showed us uncommon kindness; for they kindled a fire, and received us all, because of the present rain, and because of the cold.', pt: 'Os indígenas usaram conosco de não pouca humanidade; pois acenderam uma fogueira e nos recolheram a todos por causa da chuva que caía, e por causa do frio.' },
      { v: 3, en: 'But when Paul had gathered a bundle of sticks and laid them on the fire, a viper came out because of the heat, and fastened on his hand.', pt: 'Ora havendo Paulo ajuntado e posto sobre o fogo um feixe de gravetos, uma víbora, fugindo do calor, apegou-se-lhe à mão.' },
      { v: 4, en: 'When the natives saw the creature hanging from his hand, they said to one another, “No doubt this man is a murderer, whom, though he has escaped from the sea, yet Justice has not allowed to live.”', pt: 'Quando os indígenas viram o réptil pendente da mão dele, diziam uns aos outros: Certamente este homem é homicida, pois, embora salvo do mar, a Justiça não o deixa viver.' },
      { v: 5, en: 'However he shook off the creature into the fire, and wasn’t harmed.', pt: 'Mas ele, sacudindo o réptil no fogo, não sofreu mal nenhum.' },
      { v: 6, en: 'But they expected that he would have swollen or fallen down dead suddenly, but when they watched for a long time and saw nothing bad happen to him, they changed their minds, and said that he was a god.', pt: 'Eles, porém, esperavam que Paulo viesse a inchar ou a cair morto de repente; mas tendo esperado muito tempo e vendo que nada de anormal lhe sucedia, mudaram de parecer e diziam que era um deus.' },
      { v: 7, en: 'Now in the neighborhood of that place were lands belonging to the chief man of the island, named Publius, who received us, and courteously entertained us for three days.', pt: 'Ora, nos arredores daquele lugar havia umas terras que pertenciam ao homem principal da ilha, por nome Públio, o qual nos recebeu e hospedou bondosamente por três dias.' },
      { v: 8, en: 'The father of Publius lay sick of fever and dysentery. Paul entered in to him, prayed, and laying his hands on him, healed him.', pt: 'Aconteceu estar de cama, enfermo de febre e disenteria, o pai de Públio; Paulo foi visitá-lo, e havendo orado, impôs-lhe as mãos, e o curou.' },
      { v: 9, en: 'Then when this was done, the rest also who had diseases in the island came, and were cured.', pt: 'Feito isto, vinham também os demais enfermos da ilha, e eram curados;' },
      { v: 10, en: 'They also honored us with many honors, and when we sailed, they put on board the things that we needed.', pt: 'e estes nos distinguiram com muitas honras; e, ao embarcarmos, puseram a bordo as coisas que nos eram necessárias.' },
      { v: 11, en: 'After three months, we set sail in a ship of Alexandria which had wintered in the island, whose sign was “The Twin Brothers.”', pt: 'Passados três meses, partimos em um navio de Alexandria que invernara na ilha, o qual tinha por insígnia Castor e Pólux.' },
      { v: 12, en: 'Touching at Syracuse, we stayed there three days.', pt: 'E chegando a Siracusa, ficamos ali três dias;' },
      { v: 13, en: 'From there we circled around and arrived at Rhegium. After one day, a south wind sprang up, and on the second day we came to Puteoli,', pt: 'donde, costeando, viemos a Régio; e, soprando no dia seguinte o vento sul, chegamos em dois dias a Putéoli,' },
      { v: 14, en: 'where we found brothers, and were entreated to stay with them for seven days. So we came to Rome.', pt: 'onde, achando alguns irmãos, fomos convidados a ficar com eles sete dias; e depois nos dirigimos a Roma.' },
      { v: 15, en: 'From there the brothers, when they heard of us, came to meet us as far as The Market of Appius and The Three Taverns. When Paul saw them, he thanked God, and took courage.', pt: 'Ora, os irmãos da lá, havendo recebido notícias nossas, vieram ao nosso encontro até a praça de Ápio e às Três Vendas, e Paulo, quando os viu, deu graças a Deus e cobrou ânimo.' },
      { v: 16, en: 'When we entered into Rome, the centurion delivered the prisoners to the captain of the guard, but Paul was allowed to stay by himself with the soldier who guarded him.', pt: 'Quando chegamos a Roma, [o centurião entregou os presos ao general do exército, mas,] a Paulo se lhe permitiu morar à parte, com o soldado que o guardava.' },
      { v: 17, en: 'After three days Paul called together those who were the leaders of the Jews. When they had come together, he said to them, “I, brothers, though I had done nothing against the people, or the customs of our fathers, still was delivered prisoner from Jerusalem into the hands of the Romans,', pt: 'Passados três dias, ele convocou os principais dentre os judeus; e reunidos eles, disse-lhes: Varões irmãos, não havendo eu feito nada contra o povo, ou contra os ritos paternos, vim contudo preso desde Jerusalém, entregue nas mãos dos romanos;' },
      { v: 18, en: 'who, when they had examined me, desired to set me free, because there was no cause of death in me.', pt: 'os quais, havendo-me interrogado, queriam soltar-me, por não haver em mim crime algum que merecesse a morte.' },
      { v: 19, en: 'But when the Jews spoke against it, I was constrained to appeal to Caesar, not that I had anything about which to accuse my nation.', pt: 'Mas opondo-se a isso os judeus, vi-me obrigado a apelar para César, não tendo, contudo, nada de que acusar a minha nação.' },
      { v: 20, en: 'For this cause therefore I asked to see you and to speak with you. For because of the hope of Israel I am bound with this chain.”', pt: 'Por esta causa, pois, vos convidei, para vos ver e falar; porque pela esperança de Israel estou preso com esta cadeia.' },
      { v: 21, en: 'They said to him, “We neither received letters from Judea concerning you, nor did any of the brothers come here and report or speak any evil of you.', pt: 'Mas eles lhe disseram: Nem recebemos da Judéia cartas a teu respeito, nem veio aqui irmão algum que contasse ou dissesse mal de ti.' },
      { v: 22, en: 'But we desire to hear from you what you think. For, as concerning this sect, it is known to us that everywhere it is spoken against.”', pt: 'No entanto bem quiséramos ouvir de ti o que pensas; porque, quanto a esta seita, notório nos é que em toda parte é impugnada.' },
      { v: 23, en: 'When they had appointed him a day, many people came to him at his lodging. He explained to them, testifying about God’s Kingdom, and persuading them concerning Jesus, both from the law of Moses and from the prophets, from morning until evening.', pt: 'Havendo-lhe eles marcado um dia, muitos foram ter com ele à sua morada, aos quais desde a manhã até a noite explicava com bom testemunho o reino de Deus e procurava persuadí-los acerca de Jesus, tanto pela lei de Moisés como pelos profetas.' },
      { v: 24, en: 'Some believed the things which were spoken, and some disbelieved.', pt: 'Uns criam nas suas palavras, mas outros as rejeitavam.' },
      { v: 25, en: 'When they didn’t agree among themselves, they departed after Paul had spoken one word, “The Holy Spirit spoke rightly through Isaiah, the prophet, to our fathers,', pt: 'E estando discordes entre si, retiraram-se, havendo Paulo dito esta palavra: Bem falou o Espírito Santo aos vossos pais pelo profeta Isaías,' },
      { v: 26, en: 'saying, ‘Go to this people, and say, in hearing, you will hear, but will in no way understand. In seeing, you will see, but will in no way perceive.', pt: 'dizendo: Vai a este povo e dize: Ouvindo, ouvireis, e de maneira nenhuma entendereis; e vendo, vereis, e de maneira nenhuma percebereis.' },
      { v: 27, en: 'For this people’s heart has grown callous. Their ears are dull of hearing. Their eyes they have closed. Lest they should see with their eyes, hear with their ears, understand with their heart, and would turn again, and I would heal them.’', pt: 'Porque o coração deste povo se endureceu, e com os ouvidos ouviram tardamente, e fecharam os olhos; para que não vejam com os olhos, nem ouçam com os ouvidos, nem entendam com o coração nem se convertam e eu os cure.' },
      { v: 28, en: '“Be it known therefore to you, that the salvation of God is sent to the nations, and they will listen.”', pt: 'Seja-vos pois notório que esta salvação de Deus é enviada aos gentios, e eles ouvirão.' },
      { v: 29, en: 'When he had said these words, the Jews departed, having a great dispute among themselves.', pt: '[E, havendo ele dito isto, partiram os judeus, tendo entre si grande contenda.]' },
      { v: 30, en: 'Paul stayed two whole years in his own rented house, and received all who were coming to him,', pt: 'E morou dois anos inteiros na casa que alugara, e recebia a todos os que o visitavam,' },
      { v: 31, en: 'preaching God’s Kingdom, and teaching the things concerning the Lord Jesus Christ with all boldness, without hindrance.', pt: 'pregando o reino de Deus e ensinando as coisas concernentes ao Senhor Jesus Cristo, com toda a liberdade, sem impedimento algum.' },
    ],
  },
};

export default book;
